-- Poems batch 133
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bcecd6a3-fbb8-4144-b67d-17cc0f8e4dd8','清曉湖上三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','菰月蘋風逗葛裳，出城趁得上番涼。',32,'全唐诗/poet.song.140000.json','["菰月蘋風逗葛裳，出城趁得上番涼。", "荷花笑沐燕支露，將謂無人見曉粧。"]'),
('8b674a50-54ed-4dcb-9b67-6a40efe43c74','清曉湖上三首  其三','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','六月西湖錦繡鄉，千層翠蓋萬紅粧。',32,'全唐诗/poet.song.140000.json','["六月西湖錦繡鄉，千層翠蓋萬紅粧。", "都將月露清涼氣，併作侵晨一噴香。"]'),
('97586487-e38c-4b88-a382-df2964e4057b','大兒長孺同羅時清尋凉鹽橋','楊萬里','宋','宋诗','song-poetry','','[]','燈火希疎夜向中，追涼只與熱相逢。',32,'全唐诗/poet.song.140000.json','["燈火希疎夜向中，追涼只與熱相逢。", "意行行到新橋上，兩岸無人四面風。"]'),
('f9e70a98-4a7e-4cf3-913a-c3ff89fd9938','曉出兜率寺送許耀卿二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','天竺興雲線許長，須臾遮盡衆蒼蒼。',32,'全唐诗/poet.song.140000.json','["天竺興雲線許長，須臾遮盡衆蒼蒼。", "何如灑作千峰雨，乞與都城六月涼。"]'),
('7618040e-3c9d-4a0d-9f9e-0d10f5187d78','曉出兜率寺送許耀卿二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兜率山深露氣清，柳陰暗處藕花明。',32,'全唐诗/poet.song.141000.json','["兜率山深露氣清，柳陰暗處藕花明。", "無端拾得閑煩惱，背却西湖又入城。"]'),
('513bcae6-64fb-4bc8-bdcb-7732932f5a12','蒲橋寓舍劇暑','楊萬里','宋','宋诗','song-poetry','','[]','三歲都城寓遠坊，今年一熱古無雙。',32,'全唐诗/poet.song.141000.json','["三歲都城寓遠坊，今年一熱古無雙。", "夜來何處山村雨，涼到蒲橋橋北窗。"]'),
('8a82bb11-696c-469e-a8f4-ce87c141800c','林景思寄贈五言以長句謝之','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','華亭沈虞卿，惠山尤延之。',264,'全唐诗/poet.song.141000.json','["華亭沈虞卿，惠山尤延之。", "每見無雜語，只說林景思。", "試問景思有何好，佳句驚人人絕倒。", "句句飛從月外來，可羞王公薦穹昊。", "若人乘雲駕天風，秋衣剪菊裁芙蓉。", "暮宿銀漢朝蓬宮，我欲從之東海東。", "西湖柳色二三月，相逢一笑冠纓絕。", "醉招和靖叫東坡，一吸西湖湖欲竭。", "我醉自眠君自顛，路人往往指作仙。", "此輩何曾識此樂，識與不識俱可憐。", "別時花開今已落，思君令人瘦如鶴。", "夢裏隨君携酒瓢，同登天台度石橋。", "瀑泉界天瀉雲窟，長松拔地攙煙霄。", "與君聯句章未了，帝城鐘動西峰曉。", "海風吹墮珊瑚枝，乃是先生寄我詩。", "火雲燒江江水沸，君詩清涼過於水。", "定知來自雪巢底，恍然坐我天台寺。"]'),
('221f3167-5292-41dc-8ed2-a33ae9452c93','李仁甫侍講閣學挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','紫橐猶黄帽，青燈到白頭。',48,'全唐诗/poet.song.141000.json','["紫橐猶黄帽，青燈到白頭。", "芝庭過晁董，金鐀續春秋。", "曉月承明寂，東風玉壘愁。", "殷勤倩潮水，將淚去西州。"]'),
('b5f38e7b-819b-4df9-b43a-65e2eb67deae','李仁甫侍講閣學挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','高議春江壯，長身野鶴孤。',48,'全唐诗/poet.song.141000.json','["高議春江壯，長身野鶴孤。", "生涯一杯酒，行李五車書。", "凡例今迂叟，聲名後老蘇。", "岷峨氣悽愴，不爲玉將珠。"]'),
('68760aab-fdbf-44b7-8bed-fb5e24a362c7','故王氏令人挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','貝葉參祇樹，蓍簪當副笄。',48,'全唐诗/poet.song.141000.json','["貝葉參祇樹，蓍簪當副笄。", "來嬪舍人樣，如古大夫妻。", "鸞誥金花濕，芝庭玉樹齊。", "藥成奔月去，寂寞海山西。"]'),
('8b226fb9-6d02-4502-9946-849d671ea9f5','故王氏令人挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','西掖梧方茂，南瀕藻已蕪。',48,'全唐诗/poet.song.141000.json','["西掖梧方茂，南瀕藻已蕪。", "謝庭風絮遠，潘室月窗孤。", "有訓才吾子，無人乳阿姑。", "弔賓成白鶴，卜地得青烏。"]'),
('2514a022-665e-4762-9677-25638c3d9af6','錢仲耕殿撰侍郎挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','易髓三爻表，恩波九里强。',48,'全唐诗/poet.song.141000.json','["易髓三爻表，恩波九里强。", "貫珠程氏傳，炊玉范家莊。", "荷橐中年紫，芸籤到老香。", "不應踰耳順，便返白雲鄉。"]'),
('69cecc28-eae2-4133-926c-3ebc76f75c9a','錢仲耕殿撰侍郎挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','使節三持玉，州轓兩畫熊。',48,'全唐诗/poet.song.141000.json','["使節三持玉，州轓兩畫熊。", "雪山郇寶白，冰漕太倉紅。", "理世非輕士，才難會憶公。", "石峰當西子，作殉送青楓。"]'),
('51729b8c-eb7b-40e2-8301-317df10e0405','周子及監簿挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','科目連雙中，聲名莫二渠。',48,'全唐诗/poet.song.141000.json','["科目連雙中，聲名莫二渠。", "手曾攀折檻，客有泣辭車。", "速化非吾事，偷閑只古書。", "黑頭黄壤去，有昊定何如。"]'),
('287011c5-ac9a-4a7d-b696-7bfad1da99da','周子及監簿挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','投老欣相得，論心恨較遲。',48,'全唐诗/poet.song.141000.json','["投老欣相得，論心恨較遲。", "披文流涕疏，分韻泛湖詩。", "天奪過逢樂，人興殄瘁悲。", "何須金馬客，解製玉樓辭。"]'),
('97ad6e8a-6664-4880-a2f5-97c37f0af0e7','洪丞相挽辭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','乾道扶初旭，中台煥五雲。',48,'全唐诗/poet.song.141000.json','["乾道扶初旭，中台煥五雲。", "纔登右丞相，已拜大觀文。", "胡不遲朞月，看渠集茂勳。", "一朝驚玉折，千載歎芝焚。"]'),
('631a1292-b8f4-4ec0-a717-f51a99621d2f','洪丞相挽辭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','家譜忠仍孝，詞林博更宏。',48,'全唐诗/poet.song.141000.json','["家譜忠仍孝，詞林博更宏。", "牧羝無是子，雛鳳有難兄。", "誰謂身非達，其如道不行。", "青蠅滿天地，白日轉清明。"]'),
('0275ced9-2357-48e9-91f3-539db325e6fd','太令人田氏挽辭二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天竺瓊爲岫，西湖錦作春。',48,'全唐诗/poet.song.141000.json','["天竺瓊爲岫，西湖錦作春。", "輕軒過微雨，小宰太夫人。", "游覽年年好，恩封日日新。", "如何君氏賵，忽費水衡銀。"]'),
('afa44987-f5dc-47fd-b102-f3f5b8735aee','太令人田氏挽辭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','家食初偕隠，君羹晚得嘗。',48,'全唐诗/poet.song.141000.json','["家食初偕隠，君羹晚得嘗。", "金花千軸告，玉樹五枝香。", "咫尺相山室，葱曨瓦廟岡。", "真令淮水絕，依舊慶源長。"]'),
('7004bc27-5b5c-478d-824d-6b2a14960582','寄題劉凝之墳山壯節亭用轆轤體','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','見了廬山想此賢，此賢見了失廬山。',64,'全唐诗/poet.song.141000.json','["見了廬山想此賢，此賢見了失廬山。", "胸中書卷雲凌亂，身外功名夢等閑。", "一點目光牛背上，五絃心在雁行間。", "欲吟壯節題崖石，筆挾風霜齒頰寒。"]'),
('7ce18db6-a2aa-49ba-be17-7f6614c223f8','寄題周元吉湖北漕司志功堂','楊萬里','宋','宋诗','song-poetry','','[]','周郎昨贊元戎幕，夜眺秦川登劍閣。',176,'全唐诗/poet.song.141000.json','["周郎昨贊元戎幕，夜眺秦川登劍閣。", "函關不用一丸泥，談笑生風掃河洛。", "君王尺一喚渠回，貯之鳳閣與鸞臺。", "不贊元戎贊丞相，筆補造化裨鹽梅。", "龍媒志在橫八極，天閑玉韉羈不得。", "又揮白羽岸綸巾，却去武昌尋赤壁。", "一覽亭前山月明，志功堂下大江橫。", "前稱公瑾後元吉，君家世有千人英。", "公瑾小喬在何許，元吉小蠻花解語。", "看君一箭落胡星，如臯一笑傾人城。", "金印如斗带萬釘，何人爲作燕然銘。"]'),
('d82b4a8a-a9ec-46c3-9683-dfd620ab3bb2','曉出浄慈送林子方二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','出得西湖月尚殘，荷花蕩裏柳行間。',32,'全唐诗/poet.song.141000.json','["出得西湖月尚殘，荷花蕩裏柳行間。", "紅香世界清涼國，行了南山却北山。"]'),
('59fcec8d-21d4-4aeb-9b0d-735812e52d61','曉出浄慈送林子方二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u590f\u5929", "\u53cb\u60c5", "\u9001\u522b", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u79bb\u522b"]','畢竟西湖六月中，風光不與四時同。',32,'全唐诗/poet.song.141000.json','["畢竟西湖六月中，風光不與四時同。", "接天蓮葉無窮碧，映日荷花別樣紅。"]'),
('0ff9efea-fa5a-46c7-9fe4-45747ce3ef58','題北山教場亭子','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','堂樣毬場五百弓，帝城何地似亭中。',32,'全唐诗/poet.song.141000.json','["堂樣毬場五百弓，帝城何地似亭中。", "北山南畔南山北，獨受西湖萬頃風。"]'),
('c36b05f2-59ce-4efa-a885-a7da4da2210a','送林子方直閣秘書將漕閩部三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','纔趁鋒車入帝關，又持使節過家山。',64,'全唐诗/poet.song.141000.json','["纔趁鋒車入帝關，又持使節過家山。", "作仙茶囿芝田裏，寓直蓬萊藏室間。", "握手清談紗帽點，羨君白日繡衣還。", "來年貢了雲龍璧，便綴金鸞玉笋班。"]'),
('27bc24ca-c4e8-4665-860b-269234a70f01','送林子方直閣秘書將漕閩部三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅花國裏荔枝村，頗記張燈作上元。',64,'全唐诗/poet.song.141000.json','["梅花國裏荔枝村，頗記張燈作上元。", "一別頻蒙訪生死，七年再見劣寒溫。", "屬當閔雨祈羣望，不得臨風共一尊。", "誰爲君王留國士，吾衰猶擬叫天閽。"]'),
('0dea261a-1940-4e95-ba99-891c3b44f038','送林子方直閣秘書將漕閩部三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','亦聞小泊贊公房，清曉扶藜叩上方。',64,'全唐诗/poet.song.141000.json','["亦聞小泊贊公房，清曉扶藜叩上方。", "君與一僧游別嶂，我行百匝遶長廊。", "風巾霧屨來雲外，雪檜霜松滿袖香。", "政是炎官張火傘，不應多取海山涼。"]'),
('eb5e18e5-538a-4864-8029-8c03ab774bd9','送李伯珍主管西歸','楊萬里','宋','宋诗','song-poetry','','[]','淡墨題名冠子衿，一星州縣歎浮沈。',64,'全唐诗/poet.song.141000.json','["淡墨題名冠子衿，一星州縣歎浮沈。", "向來寄我南樓賦，不減古人東武吟。", "几閣文書聊韞玉，蘭臺筆札即紬金。", "李家兄弟鵷鸞侶，一日雙飛入上林。"]'),
('57b30fe7-a3a3-43e0-87cd-a4b84806bc39','聖上閔雨徧禱未應下詔避殿減膳感歎賦之','楊萬里','宋','宋诗','song-poetry','','[]','夏旱焚如復入秋，聖皇避殿減瓊羞。',64,'全唐诗/poet.song.141000.json','["夏旱焚如復入秋，聖皇避殿減瓊羞。", "數峰北峙雲垂合，一陣西風雨又休。", "逐日望霓穿却眼，何時倒海作奔流。", "諸賢袖有爲霖手，不瀉天瓢洗主憂。"]'),
('29264318-be3e-4bfd-ad30-b9a7a9e04c33','七月二十三日題李亨之墨梅','楊萬里','宋','宋诗','song-poetry','','[]','夏熱秋逾甚，寒梅暑亦開。',24,'全唐诗/poet.song.141000.json','["夏熱秋逾甚，寒梅暑亦開。", "無塵管城子，幻出雪枝來。"]'),
('726c8ca8-c101-4a03-9000-87b196f1b332','牽牛花三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','素羅笠頂碧羅簷，晚卸藍裳著茜衫。',32,'全唐诗/poet.song.141000.json','["素羅笠頂碧羅簷，晚卸藍裳著茜衫。", "望見竹籬心獨喜，翩然飛上翠瓊篸。"]'),
('72676b49-1542-44d6-8a73-e566c1fb9dae','牽牛花三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','莫笑渠儂不服箱，天孫爲織碧雲裳。',32,'全唐诗/poet.song.141000.json','["莫笑渠儂不服箱，天孫爲織碧雲裳。", "浪言偷得星橋巧，只解冰盤染茈薑。"]'),
('8bc87c3b-7696-4657-a45e-82c9a77423d1','牽牛花三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','曉思歡欣晚思愁，繞籬縈架太嬌柔。',32,'全唐诗/poet.song.141000.json','["曉思歡欣晚思愁，繞籬縈架太嬌柔。", "木犀未發芙蓉落，買斷西風恣意秋。"]'),
('4cd29430-5559-42c1-adcd-05d2b700f978','江下送客','楊萬里','宋','宋诗','song-poetry','','[]','却因送客動歸心，過市逢喧悶不禁。',32,'全唐诗/poet.song.141000.json','["却因送客動歸心，過市逢喧悶不禁。", "偶見人家好池館，柳行盡處一亭深。"]'),
('f440f3e5-6268-4b4b-b50a-d41ac99d72e0','和姜邦傑春坊續麗人行','楊萬里','宋','宋诗','song-poetry','','[]','玉人自惜如花面，不許黄鸝鸚鵡見。',165,'全唐诗/poet.song.141000.json','["玉人自惜如花面，不許黄鸝鸚鵡見。", "若令畫史識傾城，寫徧人間屏與扇。", "春光嬾困扶不起，吹殘玉笙也慵理。", "是誰瞥見一梳雲，微月影中掃穠李。", "阿昉姓周不姓顧，筆端那得蓮生步。", "無妨正面與渠看，看了丹青無畫處。", "古來妍醜知幾何，嫫母背面謾人多。", "君不見漢宮六六多少人，畫圖枉却王昭君。", "是時當面看寫真，却遣琵琶彈塞塵。", "不如九京喚起文與可，麝煤醉與竹傳神。"]'),
('34a02597-d07b-423f-9fb2-6789ad67934e','和姜邦傑春坊再贈七字','楊萬里','宋','宋诗','song-poetry','','[]','可笑詩人死愛名，吻間長作候蟲聲。',64,'全唐诗/poet.song.141000.json','["可笑詩人死愛名，吻間長作候蟲聲。", "鍊成九轉丹砂著，贏得千莖白雪生。", "政使古今傳不朽，不知身世竟何成。", "老夫老去真休去，一聽梅山主夏盟。"]'),
('e668d631-15a8-4d80-a2cf-0c9d009a2e3d','木犀初發呈張功父','楊萬里','宋','宋诗','song-poetry','','[]','塵世何曾識桂林，花仙夜入廣寒深。',64,'全唐诗/poet.song.141000.json','["塵世何曾識桂林，花仙夜入廣寒深。", "移將天上衆香國，寄在梢頭一粟金。", "露下風高月當戶，夢回酒醒客聞砧。", "詩情惱得渾無那，不爲龍涎與水沈。"]'),
('a1501a58-ca6f-40a0-b71f-db1af313d276','又和六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','詩人家在木犀林，萬頃湖光一徑深。',64,'全唐诗/poet.song.141000.json','["詩人家在木犀林，萬頃湖光一徑深。", "夾路兩行森翠蓋，西風半夜散麩金。", "邀賓把酒香浮玉，擘水庖霜膾落砧。", "掇取仙山入京洛，不妨冷眼看昇沈。"]'),
('a7dc0244-b3a5-4d90-98bf-4e8e4cf6ef6c','又和六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','分得吳剛斫處林，鵝兒酒色不須深。',64,'全唐诗/poet.song.141000.json','["分得吳剛斫處林，鵝兒酒色不須深。", "系從犀首名干木，派別黄香字子金。", "衣濺薔薇兼水麝，韻如月杵應霜砧。", "餘芬薰入旃檀骨，從此人間有桂沈。"]'),
('55c63cfd-7ca0-4fde-8f1c-24f58d36ec78','又和六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','端能小脫簿書林，招喚詩流卜夜深。',64,'全唐诗/poet.song.141000.json','["端能小脫簿書林，招喚詩流卜夜深。", "老我愁隤半山玉，憑君淺酌一荷金。", "水邊賞桂秋圍坐，雨後摘蔬香滿砧。", "乘醉却來湖上戲，手翻波月看浮沉。"]'),
('26e06843-99c5-4a58-aaf7-15bb9f77fd02','又和六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','約齋詩客坐詩林，派入江西徹底深。',64,'全唐诗/poet.song.141000.json','["約齋詩客坐詩林，派入江西徹底深。", "縫霧裁雲梭織錦，明堂清廟玉摐金。", "已呼毛穎哦齏臼，更約姮娥聘槀砧。", "細詠新來木犀句，一燈明滅夜沉沉。"]'),
('173061db-b869-49ee-b6bc-954cd4a30960','又和六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','老子江西有故林，萬松圍裏桂花深。',64,'全唐诗/poet.song.141000.json','["老子江西有故林，萬松圍裏桂花深。", "憶曾風露飄寒粟，自領兒童拾落金。", "割蜜旋將揉作餠，擣香須記不經砧。", "一枝未覺秋光減，燈影相看萬籟沈。"]'),
('a319abe9-0145-4807-b099-738c00a7536d','又和六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','帝城底裏有山林，桂樹團團煙霧深。',64,'全唐诗/poet.song.141000.json','["帝城底裏有山林，桂樹團團煙霧深。", "玉臂折來數枝月，銀髯羞插滿頭金。", "談間千首有此客，空外一聲何處砧。", "酒亦銷愁亦生病，不須不醉不須沉。"]'),
('056bbf38-d7ea-4b77-ac36-12d901c26ed5','題徐衡仲西窗詩編','楊萬里','宋','宋诗','song-poetry','','[]','江東詩老有徐郎，語带江西句子香。',64,'全唐诗/poet.song.141000.json','["江東詩老有徐郎，語带江西句子香。", "秋月春花入牙頰，松風澗水出肝腸。", "居仁衣鉢新分似，吉甫波瀾併取將。", "嶺表舊游君記否，荔支林裏折桄榔。"]'),
('379ef7b1-729f-4a37-b117-3c1f853f7b79','題吳夢與古樂府','楊萬里','宋','宋诗','song-poetry','','[]','金麥褰帷銀蒜鈎，水光殿後月華樓。',64,'全唐诗/poet.song.141000.json','["金麥褰帷銀蒜鈎，水光殿後月華樓。", "鶑歌花笑柳起舞，何處人間更有愁。", "吳郎那得吳宮語，夢裏苧羅人道許。", "低紅揜翠曲未終，小兒索飯啼門東。"]'),
('fbf9e0f6-2e1f-43c6-9776-97132774c35c','賀皇太子九月四日生辰二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','金莖分露與黄花，銀漢非煙作瑞霞。',64,'全唐诗/poet.song.141000.json','["金莖分露與黄花，銀漢非煙作瑞霞。", "萬國元良當誕節，重輪日月正光華。", "祖堯父舜真千載，禹子湯孫更一家。", "清曉壽觴天上至，蟠桃如甕棗如瓜。"]'),
('05d75d16-1c6a-45f8-96c0-721404d00e8b','賀皇太子九月四日生辰二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','典學光陰璧不如，簡編燈火卷還舒。',64,'全唐诗/poet.song.141000.json','["典學光陰璧不如，簡編燈火卷還舒。", "極知儲后勤稽古，却是儒生嬾讀書。", "心到帝王圖籍外，手追雅頌國風初。", "人間未見瑶山集，十倍曹丕尚有餘。"]'),
('f85b239a-4af8-4456-a779-7e17ed6631e6','題薰陾中興慶壽頌','楊萬里','宋','宋诗','song-poetry','','[]','炎暉十葉生太皇，即宋光武趙少康。',202,'全唐诗/poet.song.141000.json','["炎暉十葉生太皇，即宋光武趙少康。", "皇穹柱折地無軸，再闢三極紀八荒。", "與天同仁自同壽，八十萬歲登九九。", "淳熙天子駕蒼龍，春王三朝領羣后。", "是時雪花曉尚飄，日華飛來雪即銷。", "玉巵灧海泛椒柏，寶冊錯錦凋瓊瑶。", "虞典漢儀照億世，可無鴻筆描天地。", "下帷窺園幾代孫，濃墨大書三萬字。", "點竄封禪典引辭，塗改皇武貞符詩。", "珠璣金玉槌作屑，鑄出夏鼎仍商彝。", "歧陽石鼓魚貫柳，浯溪石崖非好手。", "誰將臣陾中興慶壽篇，刻之玉版藏名山，何千萬年千萬年。"]'),
('7e106427-6c53-4223-86b3-579df760ce25','石榴','楊萬里','宋','宋诗','song-poetry','','[]','深著紅藍染暑裳，琢成紋玳敵秋霜。',64,'全唐诗/poet.song.141000.json','["深著紅藍染暑裳，琢成紋玳敵秋霜。", "半含笑裏清冰齒，忽綻吟邊古錦囊。", "霧縠作房珠作骨，水精爲醴玉爲漿。", "劉郎不爲文園渴，何苦星槎遠取將。"]'),
('257832d9-e227-4727-8212-59c2906aa627','九月十日同尤延之觀浄慈新殿','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昨雨敗重九，謂併敗此行。',132,'全唐诗/poet.song.141000.json','["昨雨敗重九，謂併敗此行。", "雲師出小譎，垂曉偷放晴。", "初愁落君後，我反先出城。", "竚立已小倦，喜聞馬來聲。", "南山有新觀，大殿初落成。", "入門山脊動，仰目天心橫。", "柱起龍活立，簷飛鵬怒昇。", "影入西湖中，失盡千峰稜。", "天竺拉靈隠，駿奔總來庭。", "老禪定何巧，幻此壯玉京。", "書生茅三間，饑眠方曲肱。"]'),
('f216b173-077c-4e09-a8de-595def505353','看劉寺芙蓉','楊萬里','宋','宋诗','song-poetry','','[]','初約山寺游，端爲怪奇石。',144,'全唐诗/poet.song.141000.json','["初約山寺游，端爲怪奇石。", "那知雲水鄉，化作錦繡國。", "入門逕深深，過眼秋寂寂。", "隔竹小亭明，稠紅漏疎碧。", "山僧引幽踐，絕巘恣佳陟。", "三步綺爲障，十步霞作壁。", "爛如屏四圍，搭以帔五色。", "滿山盡芙蓉，山僧所手植。", "秋英例臞淡，此花獨腴澤。", "却憶補外時，朝士作祖席。", "是間萬株梅，冷射千崖白。", "舊游不可尋，雪枝半榛棘。"]'),
('79ea71b0-d07a-4f16-8ee4-6802d25b63e4','劉寺展繡亭上與尤延之久待京仲遠不至再相待於靈芝寺','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南山十日菊，秋酌有前諾。',156,'全唐诗/poet.song.141000.json','["南山十日菊，秋酌有前諾。", "東省三同舍，山行何用約。", "也復相丁寧，彼此撥忙著。", "清晨到劉寺，寸步輒倚薄。", "望君久未來，細意揀巖壑。", "上到展繡亭，聊復休倦脚。", "回覽西湖天，向我懷中落。", "山幽人轉孤，境勝情反惡。", "昔賢願獨往，對影誰與樂。", "或者欣羣遊，避喧那可却。", "我隨梁溪叟，觴次饒驩謔。", "坐無山浦翁，談間頓蕭索。", "斜陽更待渠，小向靈芝泊。"]'),
('9d043c9f-d00b-459c-b9a4-b739b4f641a0','買菊','楊萬里','宋','宋诗','song-poetry','','[]','老夫山居花繞屋，南齋杏花北齋菊。',144,'全唐诗/poet.song.141000.json','["老夫山居花繞屋，南齋杏花北齋菊。", "青春二月杏花開，抱瓶醉卧錦繡堆。", "涼秋九月菊花發，自折寒枝插華髮。", "湘纍落英曾幾何，陶令東籬未是多。", "吾家滿山種秋色，黄金爲地香爲國。", "就中更有一丈黄，霜葩月蕊耿出牆。", "飲徒亡酒尋不得，尋得一身花露香。", "如今小寓咸陽市，有口何曾問花事。", "百錢擔上買一株，聊伴詩人發幽意。"]'),
('52a7f2cf-26a7-44ae-bc49-00ff1ef72c4c','朱新仲舍人灊山詩集其子軧叔止見惠且有詩和以謝之','楊萬里','宋','宋诗','song-poetry','','[]','灊山詩伯錦裁篇，玉樹郎君手爲編。',64,'全唐诗/poet.song.141000.json','["灊山詩伯錦裁篇，玉樹郎君手爲編。", "美似洛花爭曉靚，清如江月赴秋圓。", "力追杜老今誰擬，親得陵陽夜半傳。", "再拜一吟三太息，青燈細雨伴淒然。"]'),
('5bc7da5f-0299-497c-aa10-4524eeff64a8','再和謝朱叔止機宜投贈奬及南海集之句','楊萬里','宋','宋诗','song-poetry','','[]','重陽風雨不全篇，春草池塘豈滿編。',64,'全唐诗/poet.song.141000.json','["重陽風雨不全篇，春草池塘豈滿編。", "好句誰言較多少，古人信手斲方圓。", "自慚下下中中語，只合休休莫莫傳。", "珍重銀鈎揮玉唾，竟無瑶報只空然。"]'),
('16cd0e6f-7c84-4b03-b178-b9fdc191860d','經和寧門外賣花市見菊','楊萬里','宋','宋诗','song-poetry','','[]','病眼仇冤一束書，客舍葭莩菊一株。',163,'全唐诗/poet.song.141000.json','["病眼仇冤一束書，客舍葭莩菊一株。", "看來看去兩相厭，花意索寞恰似無。", "清曉肩輿過花市，陶家全圃移在此。", "千株萬株都不看，一枝兩枝誰復貴。", "平地拔起金浮屠，瑞光千尺照碧虛。", "乃是結成菊花塔，蜜蜂作僧僧作蝶。", "菊花障子更玲瓏，生採翡翠鋪屏風。", "金錢裝面密如積，金鈿滿地無人拾。", "先生一見雙眼開，故山三逕何獨懷。", "君不見內前四時有花賣，和寧門外花如海。"]'),
('26fabd52-bf4c-4f59-bcc5-d88026b7b460','九月十五夜月細看桂枝北茂南缺未經古人拈出紀以二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','桂樹冰輪兩不齊，桂圓不似月圓時。',32,'全唐诗/poet.song.141000.json','["桂樹冰輪兩不齊，桂圓不似月圓時。", "吳剛玉斧何曾巧，斫盡南枝放北枝。"]'),
('407209e9-ff04-47d0-bcf8-9c4a5a70af5b','九月十五夜月細看桂枝北茂南缺未經古人拈出紀以二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','青天如水月如空，月色天容一皎中。',32,'全唐诗/poet.song.141000.json','["青天如水月如空，月色天容一皎中。", "若遣桂華生塞了，姮娥無殿兔無宮。"]'),
('09c73567-47ef-40ef-b33a-deebe6387e98','和張功父病中遣懷','楊萬里','宋','宋诗','song-poetry','','[]','人自窮通詩自詩，管渠人事與天時。',64,'全唐诗/poet.song.141000.json','["人自窮通詩自詩，管渠人事與天時。", "鶴長未便賢鳬短，梅早那須笑杏遲。", "公子近來忺說病，老夫秋至不曾悲。", "人生隨分堪行樂，何必蘭亭與習池。"]'),
('bf68a01a-19fe-4fd4-baa9-e225692c1139','早入東省殘月初上','楊萬里','宋','宋诗','song-poetry','','[]','秉燭趨省署，兩街猶閉門。',120,'全唐诗/poet.song.141000.json','["秉燭趨省署，兩街猶閉門。", "素娥獨早作，碧沼澣黝盆。", "寶釦剝見漆，半稜光剩銀。", "忽作青白眼，圜視向我嗔。", "黑氣貫瞳子，側睨不敢真。", "皎然一玉李，前行導征輪。", "熒然數金粟，後扈從車塵。", "朝雞傳三令，都騎爭載奔。", "星芒銷欲無，月影澹失痕。", "金鴉飛上天，吐出紅龍鱗。"]'),
('45441add-896a-45b4-aa6b-e2335724d4fb','緩轡入東宮門望見漁浦山','楊萬里','宋','宋诗','song-poetry','','[]','漁浦孤峰入九城，承華門裏最分明。',32,'全唐诗/poet.song.141000.json','["漁浦孤峰入九城，承華門裏最分明。", "馬頭看得山低去，夾道芙蓉紅露聲。"]'),
('d28242a8-acac-4bb8-ad84-e80db924511d','和徐衡仲惠詩','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風騷壇上徑雄趨，不作俳辭笑矣乎。',64,'全唐诗/poet.song.141000.json','["風騷壇上徑雄趨，不作俳辭笑矣乎。", "紙落雲煙看醉旭，氣含蔬笋薄僧殊。", "夜來霜月千家滿，雨後風埃半點無。", "安得與君幽討去，一觴一詠惱西湖。"]'),
('069665aa-bdad-40dd-a090-4ec3d22a01f9','和張功父夢歸南湖','楊萬里','宋','宋诗','song-poetry','','[]','一生兩事苦相關，從仕居貧併作難。',64,'全唐诗/poet.song.141000.json','["一生兩事苦相關，從仕居貧併作難。", "顧我雪穿行脚襪，羨君身作在家官。", "曉分京兆月半璧，夕問南湖水幾竿。", "桃李能言春滿坐，向人猶自訴霜寒。"]'),
('4283b8c3-c8b4-48d1-a9bd-f5d9b873144d','張功父請祠甚力得之簡以長句','楊萬里','宋','宋诗','song-poetry','','[]','老夫不及朱師古，納却太常少卿得潼府。',132,'全唐诗/poet.song.141000.json','["老夫不及朱師古，納却太常少卿得潼府。", "老夫不及張約齋，乞得華州仙觀名雲臺。", "金印如斗床滿笏，富貴何曾膏白骨。", "一世窮忙爲阿誰，終日逢人皺兩眉。", "賣身長鬚仍赤脚，忍面墦間乞東郭。", "添丁德曜喜欲顛，孤竹一簞真箇錯。", "張君有宅復有田，朱君歸去無一錢。", "老夫老矣不歸去，五柳先生應笑汝。"]'),
('c29cfca7-f08e-44de-8de3-6658b62e535a','三老董公','楊萬里','宋','宋诗','song-poetry','','[]','一色三軍雪染衣，拔山氣力陡然衰。',32,'全唐诗/poet.song.141000.json','["一色三軍雪染衣，拔山氣力陡然衰。", "三王事業無多子，却是良平不得知。"]'),
('3c98e15c-9647-46e9-9047-edf21cd8ff2d','利州路提刑秘書張季長送洮研發視乃一段柏木也作詩謝之','楊萬里','宋','宋诗','song-poetry','','[]','繡衣使者凜霜威，方丈仙人舊羽儀。',64,'全唐诗/poet.song.141000.json','["繡衣使者凜霜威，方丈仙人舊羽儀。", "別去十年真一夢，書來萬里寄相思。", "如何綠石涵風面，化作青銅溜雨枝。", "却送新詩報嘉惠，偷兒當不要新詩。"]'),
('69b68939-0d55-4ba5-88df-f7fbab9ca4bb','送德輪行者','楊萬里','宋','宋诗','song-poetry','','[]','瀝血抄經奈若何，十年依舊一頭陀。',32,'全唐诗/poet.song.141000.json','["瀝血抄經奈若何，十年依舊一頭陀。", "袈裟未著愁多事，著了袈裟事更多。"]'),
('21965a71-f023-4857-bbd5-fc33cd45caa9','擬上舍寒江動碧虛詩','楊萬里','宋','宋诗','song-poetry','','[]','江遠澄無底，秋深分外寒。',72,'全唐诗/poet.song.141000.json','["江遠澄無底，秋深分外寒。", "太虛元碧浄，倒影動清湍。", "浪雪翻空碎，天藍落鏡看。", "光摇蘆葉冷，聲戰蓼花乾。", "畫手琱心苦，詩脾覓句難。", "人間那有許，我欲把漁竿。"]'),
('b19f6280-4630-478c-9622-e09fa532d75c','送朱師古龍圖少卿帥潼川二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','璧水蓬山徧羽儀，頌臺公府更光輝。',64,'全唐诗/poet.song.141000.json','["璧水蓬山徧羽儀，頌臺公府更光輝。", "紫荷到眼垂持橐，黄菊關心便拂衣。", "鬻子運籌年尚少，買臣衣繡日思歸。", "小煩諭蜀須還報，却袖香煙侍太微。"]'),
('f647ddfc-046f-4720-9c3d-80022564e02f','送朱師古龍圖少卿帥潼川二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','甲戌花時策集英，相看鬚鬢各青青。',64,'全唐诗/poet.song.141000.json','["甲戌花時策集英，相看鬚鬢各青青。", "曲江初別春三月，北闕重來再一星。", "百石去官君似邴，千年歸鶴我輸丁。", "因書若寄楊員外，莫道山寒少茯苓。"]'),
('2e0be905-1814-4115-b0cb-055ef4fbe73e','高宗聖神武文憲孝皇帝挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','芒動長星帚，親揮却日戈。',48,'全唐诗/poet.song.141000.json','["芒動長星帚，親揮却日戈。", "再令天有柱，一定海無波。", "黄屋非堯樂，薰琴付舜歌。", "祗書魏蕩字，誄語不須多。"]'),
('77e558fb-e12b-4bf7-969e-468365b7f0ad','高宗聖神武文憲孝皇帝挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','更造今光武，中興昔武丁。',48,'全唐诗/poet.song.141000.json','["更造今光武，中興昔武丁。", "雲昭河洛畫，天作典謨經。", "立極餘三紀，頤神再一星。", "堯山鄰禹穴，松雪蔚爭青。"]'),
('4049b971-3f52-49bd-a324-00b2af4d06c4','記夢三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雲袖危相複，霜鐘韻政遲。',24,'全唐诗/poet.song.141000.json','["雲袖危相複，霜鐘韻政遲。", "忽然數聲急，却是住撞時。"]'),
('da42cc7c-83dc-4573-9840-2b73ba215b3c','記夢三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水動花梢動，花摇水影摇。',24,'全唐诗/poet.song.141000.json','["水動花梢動，花摇水影摇。", "不知各無意，爲復兩相招。"]'),
('58986fb7-4c89-4b11-9d7d-260effd88cc0','記夢三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','霧外知何寺，鐘聲只隔山。',24,'全唐诗/poet.song.141000.json','["霧外知何寺，鐘聲只隔山。", "望來無里許，還在九霄間。"]'),
('c962c6ee-3fa7-4e96-a167-06985c6253da','題眉山程侅所藏山谷寫杜詩帖','楊萬里','宋','宋诗','song-poetry','','[]','杜家碧山銀魚詩，黄家虎卧龍跳字。',144,'全唐诗/poet.song.141000.json','["杜家碧山銀魚詩，黄家虎卧龍跳字。", "六丁難取真宰愁，程家十襲今三世。", "程家蘇家元舅甥，子瞻正輔外弟兄。", "正輔有孫文百鍊，筆倒三江胸萬卷。", "公車獻策五十篇，玉札國體航化源。", "遠謀小扣囊底智，瓌詞未出海內傳。", "三年抱璞咸陽市，子虛無因達天帝。", "如今却買巴峽船，峨眉山月秋正圓。", "丈夫身健恐不免，即召枚臯未渠晚。"]'),
('1f0ca2a7-d3f7-4019-bc40-99dba495cce5','題臨川李子經文藁','楊萬里','宋','宋诗','song-poetry','','[]','聖經賢傳緊關津，騷客詩家妙斧斤。',64,'全唐诗/poet.song.141000.json','["聖經賢傳緊關津，騷客詩家妙斧斤。", "總被先生漏消息，不令後輩隔知聞。", "都城一日紙增價，天下幾人貧似君。", "不要綈袍却歸去，平生笑殺送窮文。"]'),
('b9f893ac-e0ed-41f6-9d2e-5dc487288f17','送喻叔奇工部知處州','楊萬里','宋','宋诗','song-poetry','','[]','厭直含香與握蘭，一麾江海泝冰灘。',64,'全唐诗/poet.song.141000.json','["厭直含香與握蘭，一麾江海泝冰灘。", "括蒼山水名天下，工部風煙入筆端。", "新國小遲懷印綬，故園暫許理漁竿。", "即看治行聞天聽，紫詔徵還集孔鸞。"]'),
('2dfbc841-2d61-4982-831f-78c10dc8e250','送劉童子','楊萬里','宋','宋诗','song-poetry','','[]','天上麒麟地上行，掌中珠玉月中生。',64,'全唐诗/poet.song.141000.json','["天上麒麟地上行，掌中珠玉月中生。", "瀾翻六籍吞諸子，聲動三公及九卿。", "別有詩書真事業，不應童子是勳名。", "長成來奏三千牘，桃李春風冠集英。"]'),
('024fe0ab-dc3e-4d5b-99c9-8b61fb7dcaec','題劉道原墓次剛直亭','楊萬里','宋','宋诗','song-poetry','','[]','山南山北蔚松楸，四海千年仰二劉。',64,'全唐诗/poet.song.141000.json','["山南山北蔚松楸，四海千年仰二劉。", "迂叟餽縑寧凍死，伯夷種粟幾時秋。", "平生鐵作三尺喙，土苴人間萬戶侯。", "廬阜作江江作阜，始應父子不傳休。"]'),
('684048fd-9fe6-48db-893e-518a0ff9fb9e','除夜張功父惠詩索荆溪集次韻送往','楊萬里','宋','宋诗','song-poetry','','[]','早往荆溪集，應無桂隠詩。',48,'全唐诗/poet.song.141000.json','["早往荆溪集，應無桂隠詩。", "梅邊五字律，管底一斑窺。", "新歲來朝是，流年去浪移。", "誰能守除夕，妨我夢歸時。"]'),
('955660d9-5d04-4243-8e1a-b9513c3e0941','題畢少董繙經圖','楊萬里','宋','宋诗','song-poetry','','[]','宋生把卷讀且指，李生把卷問奇字。',124,'全唐诗/poet.song.141000.json','["宋生把卷讀且指，李生把卷問奇字。", "榻上坐著一老子，右手秉筆袒左臂。", "春秋論語訓傳成未成，胸中有話頗欲告兩生。", "欲呼小白拉重耳，同討犬戎尊帝京。", "蠶妾不解事，兩生未可語。", "冬郎政兒癡，誰能復憐許。", "繙經未了報歸期，携書歸來獻玉墀。", "胡沙滿面無人識，回首兩生斗南北。"]'),
('c1a1ee23-d975-43bc-90eb-96c3e700158b','戊申元日立春題道山堂前梅花','楊萬里','宋','宋诗','song-poetry','','[]','今年元日不孤來，带領新春一併回。',64,'全唐诗/poet.song.141000.json','["今年元日不孤來，带領新春一併回。", "夜雨初添石渠水，東風先入道山梅。", "不妨數朶且微破，未要十分都盡開。", "江路野香元自好，阿誰移取種蓬萊。"]'),
('e8be9840-6f19-4592-8594-73b23e2d1ef1','龍山送客二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','念念還鄉未得還，偶因送客到龍山。',32,'全唐诗/poet.song.141000.json','["念念還鄉未得還，偶因送客到龍山。", "分明認得西歸路，只是回車却入關。"]'),
('1475018a-9210-4104-bf69-19702d6ab502','龍山送客二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','無奈鄉愁只强忘，龍山喚起再思鄉。',32,'全唐诗/poet.song.141000.json','["無奈鄉愁只强忘，龍山喚起再思鄉。", "故鄉依舊千山外，却被龍山斷殺腸。"]'),
('b4cc9f45-f94a-4a68-8391-dfb88a8ed4c0','問春二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','今歲春歸不小心，合將消息報園林。',32,'全唐诗/poet.song.141000.json','["今歲春歸不小心，合將消息報園林。", "蘇公堤上千株柳，二月猶慳半縷金。"]'),
('a8d83f18-b177-4771-87a1-2285fdae09c4','問春二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','元日春回不道遲，匆匆未遣萬花知。',32,'全唐诗/poet.song.141000.json','["元日春回不道遲，匆匆未遣萬花知。", "道山堂下紅梅樹，速借晴光染一枝。"]'),
('6dd2a277-e46d-4613-b978-0383c0c8fda5','曉入秘書省過三橋','楊萬里','宋','宋诗','song-poetry','','[]','船底吳儂尚晏眠，一船炊飯數船煙。',32,'全唐诗/poet.song.141000.json','["船底吳儂尚晏眠，一船炊飯數船煙。", "行人各自東西岸，抵死回頭看兩邊。"]'),
('2b9ba43a-d4a2-42aa-b8a6-d08afe297256','謝譚德稱國正惠詩','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今年日瘦天不喜，玉皇顔慘方諸淚。',156,'全唐诗/poet.song.141000.json','["今年日瘦天不喜，玉皇顔慘方諸淚。", "草木無光紅紫遲，春半何曾有春意。", "誰將好手挽春回，割取錦江春色來。", "七星橋邊楊柳動，百花潭上桃李開。", "乃是國子先生贈詩卷，筆下東風隨手轉。", "君不見李家謫仙吟掉頭，解道峨眉山月半輪秋。", "又不見蘇家老仙冰啄句，更說只恐夜深花睡去。", "先生辦著錦繡腸，朅來西湖山水鄉。", "乞君湖山入詩囊，法嗣兩仙一瓣香。"]'),
('113d63b5-27dc-429a-a5d8-7a85f4c12f80','連日二相過史局不到省中後園杏花開盡','楊萬里','宋','宋诗','song-poetry','','[]','史館頻催史筆遲，道山還解有忙時。',32,'全唐诗/poet.song.141000.json','["史館頻催史筆遲，道山還解有忙時。", "後園兩日不曾到，開盡杏花人不知。"]'),
('f90f7cad-350d-418d-8024-ee5a3f36d3c5','省中新柳','楊萬里','宋','宋诗','song-poetry','','[]','元日新春已早歸，却緣春雪勒春遲。',32,'全唐诗/poet.song.141000.json','["元日新春已早歸，却緣春雪勒春遲。", "一年柳色今何似，政是猶黄未綠時。"]'),
('e9662905-c3a2-41af-a34c-59f80891cca3','讀梁武帝事','楊萬里','宋','宋诗','song-poetry','','[]','眼見臺城作劫灰，一聲荷荷可憐哉。',32,'全唐诗/poet.song.141000.json','["眼見臺城作劫灰，一聲荷荷可憐哉。", "梵王豈是無甘露，不爲君王致蜜來。"]'),
('00a320f6-af16-4c99-8497-a2b5b2ad46da','跋悟空道人墨蹟','楊萬里','宋','宋诗','song-poetry','','[]','葱嶺書如積，銀鈎墨尚新。',48,'全唐诗/poet.song.141000.json','["葱嶺書如積，銀鈎墨尚新。", "前身虞學士，今代衛夫人。", "曲水脩蘭禊，明珠採洛神。", "更令添此帖，急就不須珍。"]'),
('3d0117ec-4c23-43ff-a849-f100ad72fbab','偶送西歸朝天二集與尤延之蒙惠七言和韻以謝之','楊萬里','宋','宋诗','song-poetry','','[]','梁溪歸自鏡湖天，筆捲湖光入大篇。',64,'全唐诗/poet.song.141000.json','["梁溪歸自鏡湖天，筆捲湖光入大篇。", "傾出錦囊和雨濕，炯如柘彈走盤圓。", "許分句法何曾付，自笑蕪辭敢浪傳。", "兩集不須求序引，祇將妙語冠陳編。"]'),
('9f81d368-c862-4be6-bd3b-c9ef334afa4c','跋王順伯所藏歐公集古錄序真蹟','楊萬里','宋','宋诗','song-poetry','','[]','遂初欣遇兩詩伯，臨川先生一禪客。',202,'全唐诗/poet.song.141000.json','["遂初欣遇兩詩伯，臨川先生一禪客。", "三人情好元不疎，祇是相逢逢不得。", "渠有貞觀碑，儂有永和詞。", "真贋爭到底，未說妍與蚩。", "珊瑚擊得如粉碎，趙璧博城翻手悔。", "不似三家鬭斷碑，夜半戰酣莫先退。", "皇朝愛碑首歐陽，集古萬卷六一堂。", "玄珪漆玉堆墨寶，黟霜黑水塗緇裳。", "臨川無端汲古手，席卷歐家都奄有。", "岣山科斗不要論，嶧山野火不經焚。", "尤家沈家喙如鐵，未放臨川第一勳。", "不知臨川何許得尤物，集古序篇出真筆。", "遂初心妬口不言，君看跋語猶悵然。"]'),
('8e15a4ce-2bcc-4d52-b125-38a3d6f27a15','和趙稷臣惠詩軸','楊萬里','宋','宋诗','song-poetry','','[]','今代宗英政駿賢，同居江介更同年。',64,'全唐诗/poet.song.141000.json','["今代宗英政駿賢，同居江介更同年。", "別來十載長相憶，新聽千詩喜欲顛。", "爽似月華秋豔豔，韻如荷葉夏田田。", "吹燈把翫舒還卷，老眼惺鬆夜不眠。"]'),
('0c418af0-a370-4240-ab5b-a33404eac594','和段季承左藏惠四絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','箇箇詩家各築壇，一家橫割一江山。',32,'全唐诗/poet.song.141000.json','["箇箇詩家各築壇，一家橫割一江山。", "祇知輕薄唐將晚，更解攀翻晉以還。"]'),
('b0d3a451-cef3-4cad-b370-7617c87e3102','和段季承左藏惠四絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','遮莫蟠胸書似山，更饒落筆語如泉。',32,'全唐诗/poet.song.141000.json','["遮莫蟠胸書似山，更饒落筆語如泉。", "陰何絕倒無人怨，却怨渠儂祕不傳。"]'),
('e1dce3bc-1323-4e4d-9169-c22bb0545833','和段季承左藏惠四絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','道是詩壇萬丈高，端能辦却一生勞。',32,'全唐诗/poet.song.141000.json','["道是詩壇萬丈高，端能辦却一生勞。", "阿誰不識珠將玉，若箇關渠風更騷。"]'),
('fc7fb2f0-31b6-40f6-9fc7-7dbc3dd27885','和段季承左藏惠四絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','四詩贈我儘新奇，萬象從君聽指麾。',32,'全唐诗/poet.song.141000.json','["四詩贈我儘新奇，萬象從君聽指麾。", "流水落花春寂寞，小風淡日燕差池。"]'),
('88f9c431-41ee-46f6-a74c-e54ec66950ba','和張功父梅詩十絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','今歲柴車總未巾，孤山龍井不曾行。',32,'全唐诗/poet.song.141000.json','["今歲柴車總未巾，孤山龍井不曾行。", "老無半點看花意，遮莫明朝雨及晴。"]'),
('711911a7-83d1-466f-8171-b8bc019a2de1','和張功父梅詩十絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','道山堂後數株梅，爲底偏於雨裏開。',32,'全唐诗/poet.song.141000.json','["道山堂後數株梅，爲底偏於雨裏開。", "到得晴來無一朶，亂飛白雪點蒼苔。"]'),
('f5f298d0-e634-4cf3-bc51-848d25664ac3','和張功父梅詩十絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','不是春光不早回，却緣春雪勒疎梅。',32,'全唐诗/poet.song.141000.json','["不是春光不早回，却緣春雪勒疎梅。", "詩人縱有催花手，有雪堪推花只推。"]'),
('941e4eae-2a6d-490e-8820-99d2aab5bdaf','和張功父梅詩十絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','淡淡梅花不要裝，真珠樓閣水精鄉。',32,'全唐诗/poet.song.141000.json','["淡淡梅花不要裝，真珠樓閣水精鄉。", "騷人詞客猶愁冷，紫蝶黄蜂更敢忙。"]'),
('f31399a5-16c6-4c04-9faa-50102de4fd71','和張功父梅詩十絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','東皇歲歲駕蒼龍，只許仙妃萬玉從。',32,'全唐诗/poet.song.141000.json','["東皇歲歲駕蒼龍，只許仙妃萬玉從。", "天上冰霜清入骨，人間桃李若爲容。"]'),
('0370225c-0f56-4d58-8910-59a091ffeae9','和張功父梅詩十絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','約齋句子已清圜，更賦梅花分外妍。',32,'全唐诗/poet.song.141000.json','["約齋句子已清圜，更賦梅花分外妍。", "不飲銷金傳玉手，却來囓雪聳詩肩。"]'),
('bd675c88-448f-406b-9b1e-49a41e40f7e0','和張功父梅詩十絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','道是梅兄不解琴，南枝風雪自成音。',32,'全唐诗/poet.song.141000.json','["道是梅兄不解琴，南枝風雪自成音。", "玉繩低後金盆落，獨與此君談此心。"]'),
('f7ef0aca-77e4-4026-9496-45d2edca7819','和張功父梅詩十絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','橫斜影裏惜花殘，忘却人間一鼠肝。',32,'全唐诗/poet.song.141000.json','["橫斜影裏惜花殘，忘却人間一鼠肝。", "莫怨梅殘看不足，請君明歲早來看。"]'),
('c0b1f1d0-e049-4348-87d6-9b098db64fa9','和張功父梅詩十絕句  其九','楊萬里','宋','宋诗','song-poetry','','[]','要與梅花巧鬭新，恨無詩句敵黄陳。',32,'全唐诗/poet.song.141000.json','["要與梅花巧鬭新，恨無詩句敵黄陳。", "約齋詩好人仍好，不怕梅花賽却人。"]'),
('d3a7644f-3bea-42ec-8a64-21e097eeba9d','和張功父梅詩十絕句  其一○','楊萬里','宋','宋诗','song-poetry','','[]','老子年來不願餘，祇慚霜鬢入金鋪。',32,'全唐诗/poet.song.141000.json','["老子年來不願餘，祇慚霜鬢入金鋪。", "故山自有梅千樹，夢繞橫枝撚斷鬚。"]'),
('56d37145-469e-46b1-bbe3-6dab337e0b4e','去瑞香病葉','楊萬里','宋','宋诗','song-poetry','','[]','紫蕤落盡長青枝，政是添新換舊時。',32,'全唐诗/poet.song.141000.json','["紫蕤落盡長青枝，政是添新換舊時。", "辛苦爲渠耘病葉，殷勤挽住是游絲。"]'),
('fad14dab-e41f-4ca9-ac65-ecb7d4c681bf','和袁起巖郎中投贈七字二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','故人一別兩相思，不但平生痛飲師。',64,'全唐诗/poet.song.141000.json','["故人一別兩相思，不但平生痛飲師。", "胸次五三真事業，筆端四六更歌詩。", "閉門覓句今無己，刻意傷春古牧之。", "卧雪高人家譜在，春風政著紫蘭枝。"]'),
('694ecf4f-8991-4f16-8ea6-90ccdb1c688d','和袁起巖郎中投贈七字二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','道場山下弄山泉，餐菊紉蘭萬物先。',64,'全唐诗/poet.song.141000.json','["道場山下弄山泉，餐菊紉蘭萬物先。", "送眼飛鴻高四海，補天健筆震三川。", "池塘碧草回春夢，衣鉢黄梅肯夜傳。", "雨不饒人有新句，怨渠未許見全篇。"]'),
('8963f553-0ed5-4824-8d8d-ddc9f8598b77','跋袁起巖所藏後湖帖并遺像一軸詩中語皆檃括帖中語也','楊萬里','宋','宋诗','song-poetry','','[]','先生向來落異縣，故人十載不相聞。',210,'全唐诗/poet.song.141000.json','["先生向來落異縣，故人十載不相聞。", "歸來不但荒三逕，點檢松菊無一存。", "裹輪加璧豈不好，朝廷禮數優遺老。", "紅旗黄紙久罷休，青山白雲苦死留，咫尺西岡歸未得。", "只待桃花水生半篙碧，便拏短艇歸結茅，共尋赤松與黄石。", "風煙之表非人間，別有天地寬且閑。", "周山賣却不要錢，袁家送酒一破顔。", "猶嫌孤斟太落莫，更覓高人共杯杓。", "銀鈎四紙墨尚鮮，妙處難與俗人言。", "忽逢先生自天降，手扶太一青藜杖。", "仙容可望不可親，飄然飛去青霞上。", "白蘋滿棹何時歸，秋著蘆花知不知。"]'),
('55206e70-2c2d-4ebd-93bf-02e154a12d54','謝邵德稱示淳熙聖孝詩','楊萬里','宋','宋诗','song-poetry','','[]','古人浪語筆如椽，何人解把筆題天。',128,'全唐诗/poet.song.141000.json','["古人浪語筆如椽，何人解把筆題天。", "崑崙爲筆點海水，青天借作一張紙。", "作商猗那周皇矣，廷尉簿正邵夫子。", "淳熙聖孝貫三光，題大如天誰敢當。", "夫子一洒金玉章，銀河吹笙間琳琅。", "吉甫奚斯鴻雁行，彼何人哉唐漫郎。", "夜來玉蟲雜金粟，老夫春寒眠不足。", "起來拾得聖孝詩，燈花阿那聖得知。"]'),
('bb862e70-651f-4cb1-8d21-d7aedcc07c9d','題曾無己所藏高麗疋紙蔡君謨歐公筆蹟','楊萬里','宋','宋诗','song-poetry','','[]','三韓玉葉展明蠲，諸老銀鈎卷碧鮮。',32,'全唐诗/poet.song.141000.json','["三韓玉葉展明蠲，諸老銀鈎卷碧鮮。", "幸自不逢文與可，一竿秋竹掃風煙。"]'),
('0021d048-78e2-475a-9aa7-1ea029893e33','夢種菜','楊萬里','宋','宋诗','song-poetry','','[]','背秋新理小園荒，過雨畦丁破塊忙。',64,'全唐诗/poet.song.141000.json','["背秋新理小園荒，過雨畦丁破塊忙。", "菜子已抽蝴蝶翅，菊花猶著鬰金裳。", "從教蘆菔專車大，早覺蔓菁撲鼻香。", "宿酒未銷羹糝熟，析酲不用柘爲漿。"]'),
('6095eaf1-5e0c-49fb-a40b-0614247993f5','謝曹宗臣惠雙溪集','楊萬里','宋','宋诗','song-poetry','','[]','君不見東陽沈隠侯，君不見宣城謝玄暉。',130,'全唐诗/poet.song.141000.json','["君不見東陽沈隠侯，君不見宣城謝玄暉。", "兩處雙溪清徹底，二子詩句清於溪。", "千載却有曹夫子，天借古人作詩地。", "家在東陽寶婺邊，官在宣城蓮幕裏。", "溪光滴作兩眼明，溪秀吐作五字清。", "開卷看來掩卷坐，詞波跳作雙溪聲。", "無人寫作雙溪操，收拾新篇句中妙。", "莫將沈謝鴻雁行，便與猗那薦清廟。"]'),
('8c21c5f3-5c2b-456d-82b8-d01dc8c22e42','過霸東石橋桐花盡落','楊萬里','宋','宋诗','song-poetry','','[]','老去能逢幾箇春，今年春事不關人。',32,'全唐诗/poet.song.141000.json','["老去能逢幾箇春，今年春事不關人。", "紅千紫百何曾夢，壓尾桐花也作塵。"]'),
('17f0fd7e-97e8-4b4e-988e-8a4912f4a04a','春雨呈袁起巖','楊萬里','宋','宋诗','song-poetry','','[]','昨日晴暄儘十分，無端寒濕復今晨。',64,'全唐诗/poet.song.141000.json','["昨日晴暄儘十分，無端寒濕復今晨。", "蒼顔華髮差排老，急雨顛風屏當春。", "只有觀書堪遣日，從來病眼不如人。", "詩名滿世真何用，更賺先生願卜鄰。"]'),
('da609532-5f0c-4d93-b92b-a69106de5725','再和','楊萬里','宋','宋诗','song-poetry','','[]','三月陰晴頃刻分，晚來非午午非晨。',64,'全唐诗/poet.song.141000.json','["三月陰晴頃刻分，晚來非午午非晨。", "閉門細草新蒲雨，過眼飛花落絮春。", "顧我江湖釣竿客，識君臺閣步雲人。", "柯山不患無人作，便合留中作近鄰。"]'),
('78f36d6c-cda9-4ee8-ba84-caa44823ae19','擬玉水記方流詩','楊萬里','宋','宋诗','song-poetry','','[]','觀水那無術，曾於往記求。',72,'全唐诗/poet.song.141000.json','["觀水那無術，曾於往記求。", "是間還韞玉，其外必方流。", "縝栗淵潜久，英華氣上浮。", "清波皆中矩，寶祲直橫秋。", "金海芒相貫，璿源折以幽。", "端如君子德，不病暗中投。"]'),
('0714ef42-bec6-41df-9563-91339dcc09f6','擬歸院柳邊迷詩','楊萬里','宋','宋诗','song-poetry','','[]','玉殿朝初退，金門馬不嘶。',72,'全唐诗/poet.song.141000.json','["玉殿朝初退，金門馬不嘶。", "院深歸有處，柳暗迹都迷。", "紫陌春無際，青絲舞正齊。", "風煙忘近遠，樓閣問高低。", "殘雪鶑聲外，斜陽鳳掖西。", "少陵花底路，物物獻詩題。"]'),
('45748464-6fdd-445a-b07f-aade788881bc','擬汲古得脩綆詩','楊萬里','宋','宋诗','song-poetry','','[]','學子研終古，難將短淺求。',72,'全唐诗/poet.song.141000.json','["學子研終古，難將短淺求。", "汲深欣得得，操綆要脩脩。", "遠酌源千載，長繅思萬周。", "初如泉眼隔，忽若井花浮。", "意到言前達，詞於筆下流。", "昌黎感秋句，聖處極冥搜。"]'),
('95013b57-32e1-4b05-ae2e-0305819026cd','謝張功父送牡丹','楊萬里','宋','宋诗','song-poetry','','[]','病眼看書痛不勝，洛花千朶喚雙明。',64,'全唐诗/poet.song.141000.json','["病眼看書痛不勝，洛花千朶喚雙明。", "淺紅釅紫各新樣，雪白鵝黄非舊名。", "擡舉精神微雨過，留連消息嫩寒生。", "蠟封水養松窗底，未似琱欄倚半酲。"]'),
('5dab0467-25b4-4b77-bc56-dc6b9f5b5c6a','張功父送牡丹續送酴醾且示酴醾長篇和以謝之','楊萬里','宋','宋诗','song-poetry','','[]','溪桃紅霞作紅雨，海棠飄盡春無處。',180,'全唐诗/poet.song.141000.json','["溪桃紅霞作紅雨，海棠飄盡春無處。", "約齋錦幄一夜空，行李移歸雪宮住。", "只道青蛟弱無力，飛上朱簷還有翼。", "貪看翡翠積成堆，忽吐瓊瑶真作劇。", "素影與月相將迎，綠雲和露相扶擎。", "南枝暗香久寂莫，此花與梅同一清。", "老夫最愛嚼香雪，不但解酲仍滌熱。", "牡丹未要煎牛酥，酴醾相領入冰壺。", "約齋知我春愁重，併遣二友來相娛。", "惜無老盆一快舉，淡日微風花自舞。", "約齋詩瘦浪作癡，君不見酒不到劉伶墳上土。"]'),
('9a4e50e2-e1d3-4c37-9d5a-55f969470f3c','和張功父送黄薔薇并酒之韻','楊萬里','宋','宋诗','song-poetry','','[]','海外薔薇水，中州未得方。',48,'全唐诗/poet.song.141000.json','["海外薔薇水，中州未得方。", "旋偷金掌露，淺染玉羅裳。", "已換桃花骨，何須賈氏香。", "更煩麴生輩，同訪墨池楊。"]'),
('2afee210-0757-4de4-8f8e-abb0d7f085ce','和張功父聞子規','楊萬里','宋','宋诗','song-poetry','','[]','久雨今朝忽作晴，老人懷抱不勝清。',64,'全唐诗/poet.song.141000.json','["久雨今朝忽作晴，老人懷抱不勝清。", "仲宣久作登樓賦，望帝更吟當殿聲。", "春去春來渾是夢，花開花落若爲情。", "歸心不用渠催喚，自有江鷗與狎盟。"]'),
('b5a30b56-eaee-4603-9684-8df93d5ca03c','跋范文公與尹師魯帖','楊萬里','宋','宋诗','song-poetry','','[]','佳客千山得得來，主人雙眼爲渠開。',32,'全唐诗/poet.song.141000.json','["佳客千山得得來，主人雙眼爲渠開。", "逢人莫說當時事，且泊南亭把一杯。"]'),
('63d28dcb-ee9b-4090-ab05-210602fb1b76','跋韓魏公與尹師魯帖','楊萬里','宋','宋诗','song-poetry','','[]','侍中尺箠撻羌酋，更得河南共運籌。',32,'全唐诗/poet.song.141000.json','["侍中尺箠撻羌酋，更得河南共運籌。", "到得降書來北闕，河南騎馬去均州。"]'),
('edae6211-3620-4f01-be0d-dd5899526d9d','跋陳簡齋奏草','楊萬里','宋','宋诗','song-poetry','','[]','詩宗已上少陵壇，筆法仍抽逸少關。',32,'全唐诗/poet.song.141000.json','["詩宗已上少陵壇，筆法仍抽逸少關。", "真蹟總歸天上去，獨留奏草在人間。"]'),
('6d49e8d2-4fb9-477b-bc1e-9992c3e65de4','又跋簡齋與夫人帖','楊萬里','宋','宋诗','song-poetry','','[]','家在錢塘身在蘇，扊扅消息近來疎。',32,'全唐诗/poet.song.141000.json','["家在錢塘身在蘇，扊扅消息近來疎。", "極知薪水無錢買，且遣長鬚送乘壺。"]'),
('2a56028c-7720-472d-9988-32be553930f0','丘母太碩人臧氏挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','行樂潘慈母，榮封衛碩人。',48,'全唐诗/poet.song.141000.json','["行樂潘慈母，榮封衛碩人。", "金花五色誥，雨葉六番春。", "白露凋萱慘，青山拱木新。", "九齡真上壽，一子更名臣。"]'),
('c5c81fcf-853a-4c29-b04a-b487c0244deb','丘母太碩人臧氏挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','共伯松楸後，宗文玉雪初。',48,'全唐诗/poet.song.141000.json','["共伯松楸後，宗文玉雪初。", "吹燈躬夜績，聽子讀殘書。", "帥閫方蘭膳，王畿又版輿。", "藥成人不見，月裏踏蟾蜍。"]'),
('df50645d-07dc-4ca0-942a-155d90ed07c2','劉平甫挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','忠孝元家法，經綸豈嬾心。',48,'全唐诗/poet.song.141000.json','["忠孝元家法，經綸豈嬾心。", "日邊遲信息，霞外且山林。", "風月詩天巧，乾坤酒陸沉。", "一生欠半面，五字寄哀音。"]'),
('62e922b3-212c-4312-ab85-e2e3ce0f89a6','劉平甫挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','忠顯肩雙廟，屏山籙二程。',48,'全唐诗/poet.song.141000.json','["忠顯肩雙廟，屏山籙二程。", "嶺寒松節苦，壇暖杏花明。", "君也孤傳業，天乎獨短生。", "子孫無一物，故紙付渠耕。"]'),
('3fa4ad75-d885-48c0-b2c3-d1c393656d15','戊申四月九日得請補外初出國門宿釋迦寺','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','出却金宮入梵宮，翠微綠霧染衣濃。',64,'全唐诗/poet.song.141000.json','["出却金宮入梵宮，翠微綠霧染衣濃。", "三年不識西湖月，一夜初聞南澗鐘。", "藏室蓬山真昨戲，園翁溪友得今從。", "若非朝士相追送，何處冥鴻更有蹤。"]'),
('ec98e63f-236c-4c26-8f12-74db424b0489','題南屏山興教寺清曠樓贈擇訥律師','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清曠樓中夕眺間，落暉殘雨兩生寒。',32,'全唐诗/poet.song.141000.json','["清曠樓中夕眺間，落暉殘雨兩生寒。", "樓中占盡南山了，更占西湖與北山。"]'),
('02ab6843-ac3f-4461-b6a1-c37316c3f948','明發南屏','楊萬里','宋','宋诗','song-poetry','','[]','新晴在在野花香，過雨迢迢沙路長。',64,'全唐诗/poet.song.141000.json','["新晴在在野花香，過雨迢迢沙路長。", "兩度立朝今結局，一生行客老還鄉。", "猶嫌數騎傳書札，剩喜千山入肺腸。", "到得前頭上船處，莫將白髮照滄浪。"]'),
('7d8f6eb6-d946-4985-9605-a6c6af41af07','過南蕩三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','秧纔束髮幼相依，麥已掀髯喜可知。',32,'全唐诗/poet.song.141000.json','["秧纔束髮幼相依，麥已掀髯喜可知。", "笑殺槿籬能耐事，東扶西倒野酴醾。"]'),
('6a30b16a-a412-4232-ab5d-c6dc4a730171','過南蕩三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','近岫遥峰翠作圍，平田小港碧行遲。',32,'全唐诗/poet.song.141000.json','["近岫遥峰翠作圍，平田小港碧行遲。", "垂楊一徑深深去，阿那人家住得奇。"]'),
('50191294-af34-49a5-bf1b-2812391ddf5c','過南蕩三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','政好行時莫嬾行，猶寒未熱雨初晴。',32,'全唐诗/poet.song.141000.json','["政好行時莫嬾行，猶寒未熱雨初晴。", "江西休問何時到，已離南屏第一程。"]'),
('412a6b40-fffa-4572-a94f-419805eaa57b','過楊村','楊萬里','宋','宋诗','song-poetry','','[]','石橋兩畔好人煙，匹似諸村別一川。',64,'全唐诗/poet.song.141000.json','["石橋兩畔好人煙，匹似諸村別一川。", "楊柳陰中新酒店，蒲萄架底小漁船。", "紅紅白白花臨水，碧碧黄黄麥際天。", "政爾清和還在道，爲誰辛苦不歸田。"]'),
('4872c52b-2529-4f34-950a-57a30cb2cdbb','側溪解纜','楊萬里','宋','宋诗','song-poetry','','[]','夢裏喧聲定不凡，順風解纜破晴嵐。',64,'全唐诗/poet.song.141000.json','["夢裏喧聲定不凡，順風解纜破晴嵐。", "起來職事惟洗面，此外功名是掛帆。", "莫笑一蔬兼半菽，飽餐萬壑與千巖。", "蓬萊雲氣君休望，且向嚴灘濯布衫。"]'),
('814a02a8-90a3-49af-94bf-dd123039ef24','洗面絕句','楊萬里','宋','宋诗','song-poetry','','[]','浙山兩岸送歸艎，新擣春藍淺染蒼。',32,'全唐诗/poet.song.141000.json','["浙山兩岸送歸艎，新擣春藍淺染蒼。", "自汲江波供盥漱，清晨滿面落花香。"]'),
('4ee443f3-786d-43a4-bc07-3807580f4998','舟過桐廬三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','瀟灑桐廬縣，寒江繚一灣。',48,'全唐诗/poet.song.141000.json','["瀟灑桐廬縣，寒江繚一灣。", "朱樓隔綠柳，白塔映青山。", "稚子排窗出，舟人買菜還。", "峰頭好亭子，不得一躋攀。"]'),
('94566a59-4953-4940-8dd6-5d6ac05fb7c8','舟過桐廬三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','近縣人人喜，來船岸岸移。',48,'全唐诗/poet.song.141000.json','["近縣人人喜，來船岸岸移。", "偶因小泊處，恰是早餐時。", "喚僕答相亂，看山寒不知。", "橫洲猶半在，今歲水生遲。"]'),
('8935a5e9-f106-4859-8fe7-d56f47c8ec93','舟過桐廬三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','後面山無數，南頭柳更多。',48,'全唐诗/poet.song.141000.json','["後面山無數，南頭柳更多。", "人家逼江岸，屋柱入滄波。", "老去頻經此，重來更幾何。", "牛山動悲感，曾侍板輿過。"]'),
('dd1ce1ef-c629-4205-b5ad-1261464a85ec','溜港灘','楊萬里','宋','宋诗','song-poetry','','[]','此去嚴州只半程，一江分作兩江橫。',32,'全唐诗/poet.song.141000.json','["此去嚴州只半程，一江分作兩江橫。", "忽驚洲背青山下，却有帆檣地上行。"]'),
('dad4d15f-4106-436e-b36f-82b1eea52404','午睡聞子規','楊萬里','宋','宋诗','song-poetry','','[]','睡眼䰒鬆未爽時，一聲杜宇頓開眉。',32,'全唐诗/poet.song.141000.json','["睡眼䰒鬆未爽時，一聲杜宇頓開眉。", "不須報道思歸樂，今我真歸不用思。"]'),
('3e0f38f6-cb86-47d8-9f63-6f0c9ef3a1a6','已過胥口將近釣臺','楊萬里','宋','宋诗','song-poetry','','[]','睡起衣襟亂，頭巾百摺痕。',48,'全唐诗/poet.song.141000.json','["睡起衣襟亂，頭巾百摺痕。", "帆端風色緊，船底水聲喧。", "胥口冤餘浪，嚴灘釣處村。", "因行還訪古，故老莫能言。"]'),
('9f6365be-f6a6-4175-8e07-b0f01edc2032','釣臺','楊萬里','宋','宋诗','song-poetry','','[]','釣石三千丈，將何作釣絲。',48,'全唐诗/poet.song.141000.json','["釣石三千丈，將何作釣絲。", "肯離山水窟，去作帝王師。", "小范真同味，玄英也並祠。", "老夫歸已晚，莫遣客星知。"]'),
('e6b6a667-7109-4fcd-b39b-efa817eedb61','蘭溪女兒浦曉寒','楊萬里','宋','宋诗','song-poetry','','[]','前年寒早熱亦早，去年寒遲熱亦遲。',64,'全唐诗/poet.song.141000.json','["前年寒早熱亦早，去年寒遲熱亦遲。", "何曾寒暑有遲速，通融三年那兌支。", "人生何必早得意，芍藥榮時牡丹瘁。", "榮枯遲速一笑休，順風今日好行舟。"]'),
('c2ad0d82-d078-4718-8ac4-0c5a2ef558c8','橫山塔','楊萬里','宋','宋诗','song-poetry','','[]','相識橫山塔，于今十五年。',48,'全唐诗/poet.song.141000.json','["相識橫山塔，于今十五年。", "孤標立絕頂，秃影照清川。", "寂寞無香火，將迎幾舫船。", "吾衰豈重過，珍重塔中仙。"]'),
('68647fd6-04b9-4ac8-b80a-e36b956353e5','舟過蘭溪','楊萬里','宋','宋诗','song-poetry','','[]','駕雨顛風過即虛，殺風急雨有還無。',64,'全唐诗/poet.song.141000.json','["駕雨顛風過即虛，殺風急雨有還無。", "雲山奔走無停住，岸樹欹斜不要扶。", "船底石聲知淺水，沙頭笠影倦牽夫。", "金臺祇在橫山背，便到金臺也日晡。"]'),
('0b9f2a12-8bad-48d6-8c5f-a6a7fc91d437','嘲穉子','楊萬里','宋','宋诗','song-poetry','','[]','雨裏船中不自由，無愁穉子亦成愁。',32,'全唐诗/poet.song.141000.json','["雨裏船中不自由，無愁穉子亦成愁。", "看渠坐睡何曾醒，及至教眠却掉頭。"]'),
('c2ae77ed-9dcf-4be6-a792-8f46cd247dcf','雨中遣悶','楊萬里','宋','宋诗','song-poetry','','[]','船篷深閉膝難安，四面千峰不得看。',32,'全唐诗/poet.song.141000.json','["船篷深閉膝難安，四面千峰不得看。", "莫厭霏微悶人雨，插秧怕熱愛輕寒。"]'),
('7c9e4aba-f70e-4502-a2a7-43b03cfa5151','橫山江岸','楊萬里','宋','宋诗','song-poetry','','[]','近船古岸不勝高，浪劃濤剜似削刀。',32,'全唐诗/poet.song.141000.json','["近船古岸不勝高，浪劃濤剜似削刀。", "層石層砂層膩土，僧厨蒸出栗黄糕。"]'),
('ce6467ec-5554-45da-bb44-aaa9c7ef6d0e','舟中午睡','楊萬里','宋','宋诗','song-poetry','','[]','一葉摇無定，昏然妙思通。',48,'全唐诗/poet.song.141000.json','["一葉摇無定，昏然妙思通。", "化爲漆園蝶，飛入大槐宮。", "有酒相勾引，無茶作寇戎。", "平生眠不足，還債艣聲中。"]'),
('d6aef350-13f2-475d-86ca-98cc0421afcf','炙蒸餠','楊萬里','宋','宋诗','song-poetry','','[]','圓瑩僧何矮，清鬆絮爾輕。',48,'全唐诗/poet.song.141000.json','["圓瑩僧何矮，清鬆絮爾輕。", "削成瓊葉片，嚼作雪花聲。", "炙手三家市，焦頭五鼎烹。", "老夫饑欲死，汝輩且同行。"]'),
('ecf94ed8-891f-428b-9474-7a6c9effcc62','睡起觀山','楊萬里','宋','宋诗','song-poetry','','[]','過雨前汀未可登，搴篷小散睡瞢騰。',32,'全唐诗/poet.song.141000.json','["過雨前汀未可登，搴篷小散睡瞢騰。", "船頭政好看山色，一點江風冷似冰。"]'),
('27ea7487-8334-4a1f-a098-c11dfc16e4b1','柴步灘','楊萬里','宋','宋诗','song-poetry','','[]','江闊水不聚，分爲三五灘。',108,'全唐诗/poet.song.141000.json','["江闊水不聚，分爲三五灘。", "遂令客子舟，上灘一一難。", "小沙已成洲，大洲已成山。", "山有樹百尺，樹圍屋數間。", "水底復生洲，沙濕猶未乾。", "從此洲愈多，安得水更寬。", "憶從嚴陵歸，水落不能湍。", "拖以數童僕，折却十竹竿。", "今茲過吾舟，念昔猶膽寒。"]'),
('6f25022d-7903-4678-b8e3-0f6dd230f4cb','東磧灘','楊萬里','宋','宋诗','song-poetry','','[]','江船初上灘，灘水政勃怒。',96,'全唐诗/poet.song.141000.json','["江船初上灘，灘水政勃怒。", "船工與水鬭，水力攔船住。", "琉璃忽破碎，冰雪迸吞吐。", "竟令水柔伏，低頭船底去。", "朝來發盈川，已過灘十許。", "但聞浪喧闐，未覩水態度。", "却緣看後船，偶爾見奇處。", "從此至三衢，猶有灘四五。"]'),
('11c9353f-f069-428a-8154-4ec54544bf6c','將至地黄灘','楊萬里','宋','宋诗','song-poetry','','[]','未到地黄灘，十里先聞聲。',72,'全唐诗/poet.song.141000.json','["未到地黄灘，十里先聞聲。", "檣竿已震掉，未敢與渠爭。", "舟人各整篙，有如大敵臨。", "搴篷試一望，濺雪紛淙琤。", "乃是水磑港，爲灘作先鳴。", "真灘定若何，老夫虛作驚。"]'),
('66adef20-5cf6-4926-a503-6d67606a433e','蘇木灘','楊萬里','宋','宋诗','song-poetry','','[]','灘雪清濺眸，灘雷怒醒耳。',84,'全唐诗/poet.song.141000.json','["灘雪清濺眸，灘雷怒醒耳。", "落洪翠壁立，跳波碧山起。", "船進若戰勝，船退亦遊戲。", "若非篙師苦，進退皆可喜。", "忽逢下灘舟，掀舞快雲駃。", "何曾費一棹，纔瞬已數里。", "會有上灘時，得意君勿恃。"]'),
('17366320-1e4c-4ef5-9f05-cf880d63c45e','遼車灘','楊萬里','宋','宋诗','song-poetry','','[]','東岸上不得，西岸上更難。',84,'全唐诗/poet.song.141000.json','["東岸上不得，西岸上更難。", "五船往復來，經緯灘兩間。", "一船初徑進，當流爲衆先。", "濤頭打澎湃，退縮不敢干。", "一船作後殿，忽焉突而前。", "瞬息越湍險，回顧有矜顔。", "老夫與寓目，亦爲一粲然。"]'),
('d16a2ec0-ddcf-4df1-83f8-25fce0f410ed','舟中新暑止酒','楊萬里','宋','宋诗','song-poetry','','[]','新暑酒不宜，作熱妨夜睡。',60,'全唐诗/poet.song.141000.json','["新暑酒不宜，作熱妨夜睡。", "不如看人飲，亦自有醉意。", "彼飲吾爲嚥，所美過於味。", "同舟笑吾癡，吾不羨渠醉。", "安知醉與醒，誰似誰不似。"]'),
('7e0e4682-75d6-4165-b729-49b0961068fe','過查瀨','楊萬里','宋','宋诗','song-poetry','','[]','眼底常山一武中，上灘更得半帆風。',64,'全唐诗/poet.song.141000.json','["眼底常山一武中，上灘更得半帆風。", "青天以水爲銅鏡，白鷺前身是釣翁。", "舊日岸頭渾改盡，數尖山觜忽攙空。", "老夫只費五六日，行盡浙山西復東。"]'),
('26dd628e-6c59-4598-81a6-52c7a9b159db','舟過大水旁羅灘渴甚小飲','楊萬里','宋','宋诗','song-poetry','','[]','熟水無多喫，烹茶未要來。',48,'全唐诗/poet.song.141000.json','["熟水無多喫，烹茶未要來。", "從教十分渴，連掃兩三杯。", "岸樹背船走，江波閃日開。", "靈山定能飲，分酹碧蓮醅。"]'),
('c0a29f41-6385-40bc-8048-8f008e1edffa','過鉛山江口','楊萬里','宋','宋诗','song-poetry','','[]','下却諸灘水漸平，舟行已遠上饒城。',32,'全唐诗/poet.song.141000.json','["下却諸灘水漸平，舟行已遠上饒城。", "酒家便有江鄉景，綠柳梢頭掛玉瓶。"]'),
('85bf6442-2cf3-4061-8dca-cbc5c466cf37','過弋陽觀競渡','楊萬里','宋','宋诗','song-poetry','','[]','急鼓繁鉦動地呼，碧瑠璃上兩龍趨。',64,'全唐诗/poet.song.141000.json','["急鼓繁鉦動地呼，碧瑠璃上兩龍趨。", "一聲翻倒馮夷國，千載淒涼楚大夫。", "銀椀錦標誇勝捷，畫橈繡臂照江湖。", "三年端年真虛過，奇觀初逢慰道塗。"]'),
('ba44ec17-69bc-4488-924a-50c92d0b0a12','靈山','楊萬里','宋','宋诗','song-poetry','','[]','饒水回回轉，靈山面面逢。',48,'全唐诗/poet.song.141000.json','["饒水回回轉，靈山面面逢。", "展成青步障，斂作碧芙蓉。", "變態百千樣，尖新三兩峰。", "遠看方更好，還隔翠雲重。"]'),
('51dec713-72b1-4d65-a5a6-9c578e7d47d7','龜峰','楊萬里','宋','宋诗','song-poetry','','[]','明發大琛山，龜峰引頸來對面。',62,'全唐诗/poet.song.141000.json','["明發大琛山，龜峰引頸來對面。", "亭午過弋陽，龜峰縮頭不相見。", "綠毛蒙茸浄如染，紫殻輪囷有斑點。", "不知七十二鑽神不神，桃花市裏看最真。"]'),
('069a0853-ff4b-483e-91ea-70abc70b8c23','五月一日過貴溪舟中苦熱','楊萬里','宋','宋诗','song-poetry','','[]','半月陰涼天氣佳，今朝新暑不饒些。',64,'全唐诗/poet.song.141000.json','["半月陰涼天氣佳，今朝新暑不饒些。", "一生怕熱長逢熱，千里還家未到家。", "入却船來那得出，恰方日午幾時斜。", "勸君莫愛高官職，行路難時却怨嗟。"]'),
('dcec9c65-b1e6-4afe-9857-398809ab1569','初二日苦熱','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','人言長江無六月，我言六月無長江。',128,'全唐诗/poet.song.141000.json','["人言長江無六月，我言六月無長江。", "只今五月已如許，六月更來何可當。", "船倉周圍各五尺，且道此中底寬窄。", "上下東西與南北，一面是水五面日。", "日光煮水復成湯，此外何處能清涼。", "掀篷更無風半點，揮扇只有汗如漿。", "吾曹避暑自無處，飛蠅投吾求避暑。", "吾不解飛且此住，飛蠅解飛不飛去。"]'),
('99c61757-2561-411e-90b2-65879d2a7c89','端午前一日阻風鄱陽湖觀競渡','楊萬里','宋','宋诗','song-poetry','','[]','惡風夜半阻歸船，端欲留人作勝緣。',64,'全唐诗/poet.song.141000.json','["惡風夜半阻歸船，端欲留人作勝緣。", "千里携家觀競渡，五湖新漲政黏天。", "棹翻波浪山如雪，醉殺兒郎喜欲顛。", "得去更佳留亦好，吾曹何處不欣然。"]'),
('4f934ce8-06a1-433f-960e-e6abcb8b11ab','初六日過鄱陽湖入相見灣','楊萬里','宋','宋诗','song-poetry','','[]','阻風兩日卸高桅，笑傲江妃縱酒杯。',64,'全唐诗/poet.song.141000.json','["阻風兩日卸高桅，笑傲江妃縱酒杯。", "及至絕湖纔一瞬，翻令病眼不雙開。", "蘆洲荻港何時了，南浦西山不肯來。", "相見灣中悶人死，一灣九步十縈迴。"]'),
('514aeb0a-1bc2-4b1a-b8c2-f4f9fad4f37b','過趙家莊','楊萬里','宋','宋诗','song-poetry','','[]','老子方孤悶，西山忽在旁。',48,'全唐诗/poet.song.141000.json','["老子方孤悶，西山忽在旁。", "回頭鄔子砦，明眼趙家莊。", "試飲章江味，中涵吉水香。", "望鄉儂已喜，而況到吾鄉。"]'),
('bb642cc1-6dc5-41b6-a069-dceac98edb6d','十五日明發石口遇順風','楊萬里','宋','宋诗','song-poetry','','[]','泝流淺水刺樓船，百棹千篙祇不前。',64,'全唐诗/poet.song.141000.json','["泝流淺水刺樓船，百棹千篙祇不前。", "一夜波聲喧到曉，北風氣力欲翻天。", "掛帆未了青泥過，轉眼相將玉笥邊。", "無數小舟俱在後，追儂不及指爲仙。"]'),
('238c23aa-7cbd-46a9-b01c-d2e3df0a28d7','山居午睡起弄花三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','五年出仕喜還家，雙桂成陰不闕些。',32,'全唐诗/poet.song.141000.json','["五年出仕喜還家，雙桂成陰不闕些。", "午睡起來無理會，銀盆清水弄荷花。"]'),
('45f76fcb-07e0-440f-85e3-86419245eb50','山居午睡起弄花三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','數片荷花漾水盆，忽然相聚忽然分。',32,'全唐诗/poet.song.141000.json','["數片荷花漾水盆，忽然相聚忽然分。", "從教壓捺沉盆底，依舊浮來無水痕。"]'),
('0dba5cea-5f6f-487b-a70c-9835cefdc24c','山居午睡起弄花三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','浸得荷花水一盆，將來洗面漱牙根。',32,'全唐诗/poet.song.141000.json','["浸得荷花水一盆，將來洗面漱牙根。", "涼生鬚鬢香生頰，沉麝龍涎却是村。"]'),
('940d8538-ded3-4b1f-b991-095641edd4a2','賀必遠叔四月八日洗兒','楊萬里','宋','宋诗','song-poetry','','[]','年年四月初八日，水沉湯浴黄金佛。',88,'全唐诗/poet.song.141000.json','["年年四月初八日，水沉湯浴黄金佛。", "今年大阮當此時，真珠水洗白玉兒。", "吾家英傑相間起，胄出關西老夫子。", "公家宣和中大夫，大江之西推名儒。", "六十年來誰繼渠，願兒長成讀祖書，再起門戶光鄉閭。"]'),
('99e52d63-c432-4fec-aea5-3b123ec55c3c','七月二十三日南極老人星歌上叔父十三致政一杯千歲之壽','楊萬里','宋','宋诗','song-poetry','','[]','淡溪居士登九齡，朱顔青鬢如後生。',130,'全唐诗/poet.song.141000.json','["淡溪居士登九齡，朱顔青鬢如後生。", "橫拖仙人綠玉杖，倒誦上帝黄庭經。", "璇霄仙籍書姓名，丹霞染誥金花綾。", "近來更覺雙眼明，夜抄蠅頭窗下燈。", "登山臨水兩脚輕，御風騎氣不用行。", "何人有筆筆無塵，鵝溪一幅爲寫真。", "烏紗白苧坐鼓琴，上有千歲長松青。", "令威旁舞玄夫聽，箇是活底南極老人星。"]'),
('394e656a-cdcb-4591-9cd7-5fc93c01b1ee','秋暑','楊萬里','宋','宋诗','song-poetry','','[]','夏暑減未曾，秋暑增愈劇。',96,'全唐诗/poet.song.141000.json','["夏暑減未曾，秋暑增愈劇。", "老翁避無處，茅齋聊憩息。", "銀盆滿注水，銀水同一色。", "中涵雙桂影，倒卧一天碧。", "清光湛不動，欲弄還復惜。", "偶然一播灑，樹影碎相激。", "洗面涼已滋，漱齒痛仍逼。", "平生畏秋暑，老去畏彌極。"]'),
('28547d6c-a5df-49e8-bcef-9c7b4e77cb27','讀漢書二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','猿臂生何晚，彫蟲死較遲。',24,'全唐诗/poet.song.141000.json','["猿臂生何晚，彫蟲死較遲。", "晚生妨底事，遲死獨堪悲。"]'),
('5271c51e-42f8-4b26-a93b-07355b79469b','讀漢書二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','乃祖寬仍豁，曾孫察作明。',24,'全唐诗/poet.song.141000.json','["乃祖寬仍豁，曾孫察作明。", "不將囊底智，分減及元成。"]'),
('7252f503-ae01-4e28-a02f-0e03d5049d1b','送吉州太守朱子淵造朝二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','廬陵難做定何如，請看黟川朱大夫。',64,'全唐诗/poet.song.141000.json','["廬陵難做定何如，請看黟川朱大夫。", "秋月滿懷春滿面，視民如子吏如奴。", "萬艘白粲何曾欠，百雉金城舊更無。", "歸侍玉皇香案了，甘棠便是瑞蓮圖。"]'),
('dea232c0-8202-4146-9e63-88b3ebefb0d9','送吉州太守朱子淵造朝二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','公在鄉邦我在京，百書終不慰生平。',64,'全唐诗/poet.song.141000.json','["公在鄉邦我在京，百書終不慰生平。", "西歸一見還傾蓋，夜坐相看話短檠。", "老去可堪頻送客，古來作惡是離情。", "雲泥隔斷從今始，肯倩征鴻訪死生。"]'),
('ae59df52-0c46-47f0-b867-d2440c64420e','感秋五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','昨扇猶午携，今裳覺晨單。',144,'全唐诗/poet.song.141000.json','["昨扇猶午携，今裳覺晨單。", "起來且復卧，未敢窺柴關。", "不知病至此，爲復老使然。", "平生性剛燥，畏熱長喜寒。", "念昔忝鄉賦，踐雪詣春官。", "布褐背不纊，芒鞋繭且穿。", "長亭夜濯足，吹燈呻故編。", "買酒破孤悶，浩歌殷屋椽。", "何曾悲廩秋，山稜聳臞肩。", "秋風吹我髓，秋露滴我肝。", "我欲與秋敵，秋先令我酸。", "歎息復歎息，誰是長少年。"]'),
('b1c01e9f-ad9b-4208-9b41-ce7b00edfe8d','感秋五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','盥漱已云畢，危坐正冠衣。',96,'全唐诗/poet.song.141000.json','["盥漱已云畢，危坐正冠衣。", "攬鏡忽見我，不識我爲誰。", "自倚身尚强，不悟年已衰。", "舉頭視嘉木，向人慘無姿。", "我欲訴渠老，渠乃懷秋悲。", "木悲不解飲，瑟瑟聲怨咨。", "我且呼麴生，細細斟酌之。", "我醉不知我，更知春秋爲。"]'),
('6981f03e-2140-4910-9195-09998f58f1a9','感秋五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','隤照趣夕黯，孤燈啟宵明。',96,'全唐诗/poet.song.141000.json','["隤照趣夕黯，孤燈啟宵明。", "老夫倦欲睡，似醉復如醒。", "寸心無寸恨，坦如江海清。", "秋蛩何爲者，四面作怨聲。", "淒惻竟未已，抑揚殊不平。", "切切百千語，遞遞三四更。", "遶砌尋不得，靜坐復爭鳴。", "有口汝自苦，我醉不汝聽。"]'),
('b16f4de1-23fb-4618-bd3f-e425ad6dbab1','感秋五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','秋曉寒可忍，秋夕永難度。',96,'全唐诗/poet.song.141000.json','["秋曉寒可忍，秋夕永難度。", "青燈照書冊，兩眼如隔霧。", "掩卷却孤坐，塊然與誰語。", "倒卧卧不得，起行行無處。", "屋角忽生明，山月到庭戶。", "似憐幽獨人，深夜約清晤。", "我吟月解聽，月轉我亦步。", "何必更讀書，且與月聯句。"]'),
('c77d6eaa-e1bf-492e-877c-7aad57374af1','感秋五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','平生畏長夏，一念願清秋。',72,'全唐诗/poet.song.141000.json','["平生畏長夏，一念願清秋。", "如何遇秋至，不喜却成愁。", "書冊秋可讀，詩句秋可搜。", "永夜宜痛飲，曠野宜遠遊。", "江南萬山川，一夕入寸眸。", "請辦雙行纏，何處無一丘。"]'),
('b42e1b97-4163-48a8-a1d5-cea07e4573bf','寄題蕭民望齊雲樓','楊萬里','宋','宋诗','song-poetry','','[]','下泳山尖碧雲起，添得奇峰三四觜。',64,'全唐诗/poet.song.141000.json','["下泳山尖碧雲起，添得奇峰三四觜。", "老人登樓來看雲，下瞰雲端在平地。", "急呼雲師令執鞭，我欲乘此追群仙。", "蓬萊閬風徧遊覽，歸來落月滿晴川。"]'),
('ca88c917-f619-4101-b926-1abcb59d4778','寄題李俊臣南樓','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','庾家南樓天下無，李家南樓何似渠。',66,'全唐诗/poet.song.141000.json','["庾家南樓天下無，李家南樓何似渠。", "玉篸碧山羅带水，眼界風煙且千里。", "何須橫陳鸚鵡洲，月挂欄干西角頭。", "謫仙子孫五鳳手，安得長江化作一杯酒。"]'),
('bcae89be-d9dc-4d6a-88c3-0bcdd64de90e','送劉子思往衡湘','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','浩齋先生第一孫，秀峰後進第一人。',82,'全唐诗/poet.song.141000.json','["浩齋先生第一孫，秀峰後進第一人。", "向來著論三分國，喚起阿瞞戮姦魄。", "有司手持金粟尺，越羅蜀錦遺道側。", "洞庭昨夜起霜風，翩然欲登石廩與祝融。", "歸來定有驚人句，肯寄江西道院翁。"]'),
('2464e1a7-388f-4b9a-a9c3-ab146cf8e59a','夢作碾試館中所送建茶絕句','楊萬里','宋','宋诗','song-poetry','','[]','天上蓬山新水芽，羣仙遠寄野人家。',32,'全唐诗/poet.song.141000.json','["天上蓬山新水芽，羣仙遠寄野人家。", "坐看寶带黄金銙，吹作春風白雪花。"]'),
('bc7d84d0-c199-4617-9005-0b5bb7da4e4c','寄題安福彭文昌春風樓二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','沂水何人解問津，樓中蠹簡拂蛛塵。',32,'全唐诗/poet.song.141000.json','["沂水何人解問津，樓中蠹簡拂蛛塵。", "杏花壇下朱絃瑟，十指風生別是春。"]'),
('a6f8faa9-3c9e-439f-b5de-c444b097dcaa','寄題安福彭文昌春風樓二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不到安成二十年，故人相憶兩依然。',32,'全唐诗/poet.song.141000.json','["不到安成二十年，故人相憶兩依然。", "彭家樓上春風裏，夢倚危欄俯百川。"]'),
('4c0aa7e0-ffc8-4fd9-a3af-e10befef5234','將赴高安出吉水報謁縣官歸塗宿五峰寺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','風暄雨暖日和柔，道是穠春不道秋。',32,'全唐诗/poet.song.141000.json','["風暄雨暖日和柔，道是穠春不道秋。", "楚楚江楓新結束，柿紅衫子錦纏頭。"]'),
('7961eb57-f320-447d-ba5e-183d0d332718','將赴高安出吉水報謁縣官歸塗宿五峰寺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','野寺重來記昨遊，一彈指頃幾經秋。',32,'全唐诗/poet.song.141000.json','["野寺重來記昨遊，一彈指頃幾經秋。", "五峰絕頂雙松樹，相識兒時到白頭。"]'),
('c773367e-5203-4b60-bc34-947b45ee7b31','明發五峰寺','楊萬里','宋','宋诗','song-poetry','','[]','歸時路何近，去時路何遠。',144,'全唐诗/poet.song.141000.json','["歸時路何近，去時路何遠。", "山路無短長，人心有往返。", "每因赴官期，一出謁鄉縣。", "若非人事牽，無奈老身嬾。", "初心作此行，夜雨醒醉眼。", "孤愁念群騶，尺泥滑雙趼。", "首塗天全濕，回轍雲半捲。", "投寺借松牀，呼僧同野飯。", "頹然佳眠足，得此行役倦。", "暫勞新不堪，遐征舊所歎。", "松菊豈不懷，樊籠何時免。", "瘦藤要覓閑，到了古道院。"]'),
('2f1feb9e-49d5-46e6-88ef-0b4965750571','初入筠州界高岡鋪','楊萬里','宋','宋诗','song-poetry','','[]','千尺霜松夾道周，國初涼繖至今留。',32,'全唐诗/poet.song.141000.json','["千尺霜松夾道周，國初涼繖至今留。", "筠州舊是朝天路，六十年來行信州。"]'),
('26f5f954-c057-49d9-ba76-81a1d69bb9a1','贈別羅時清','楊萬里','宋','宋诗','song-poetry','','[]','四歲相從亦快哉，東游興盡却西回。',64,'全唐诗/poet.song.141000.json','["四歲相從亦快哉，東游興盡却西回。", "詩中風月無疆界，聖處宮庭元洞開。", "握手論文兩淒斷，登山臨水重徘徊。", "亦山亭下梅花徑，明日先生獨自來。"]'),
('dcd1617d-35df-444a-bb4c-ef9d764ff477','己酉上元後贈劉子才','楊萬里','宋','宋诗','song-poetry','','[]','書臺城西幽絕處，古木排霄草荒路。',96,'全唐诗/poet.song.141000.json','["書臺城西幽絕處，古木排霄草荒路。", "空齋深夜四無人，維予二人聽春雨。", "我如病鶴子茁蘭，長幼不同同少年。", "聞子誦書金應玉，看子落筆山飛泉。", "別來幾何如昨日，我老過前子非昔。", "來年裹硯試集英，側耳臚傳第一聲。"]'),
('a7d9a72d-5630-43fa-90dd-b2ee32b5c1d5','二月十一日夜夢作東都蚤春絕句','楊萬里','宋','宋诗','song-poetry','','[]','道是春來早，如何未見春。',24,'全唐诗/poet.song.141000.json','["道是春來早，如何未見春。", "小桃三四點，偏報有情人。"]'),
('880aeae0-fe82-45da-ae7d-1c80fc8bff2c','和尤延之見戲觸藩之韻以寄之','楊萬里','宋','宋诗','song-poetry','','[]','儂愛山行君水遊，尊前風味獨宜秋。',64,'全唐诗/poet.song.141000.json','["儂愛山行君水遊，尊前風味獨宜秋。", "文戈却日玉無價，器寶羅胸金欲流。", "欬唾清圜談者詘，詩章精悍古人羞。", "子房莫笑身三尺，會看功成自擇留。"]'),
('1c83ef2a-bda7-4e65-93dc-2304c617c5e0','郡圃上巳二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','旋收雨夕放晴晨，禊日風光正可人。',32,'全唐诗/poet.song.141000.json','["旋收雨夕放晴晨，禊日風光正可人。", "間白參紅方是錦，疎桃散李不成春。"]'),
('c43239bc-56c2-43c8-bd77-ac833ffc8790','郡圃上巳二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','尋春不見只思還，却在來僊小崦間。',32,'全唐诗/poet.song.141000.json','["尋春不見只思還，却在來僊小崦間。", "映出一川桃李好，只消外面矮青山。"]'),
('45e7b455-e92a-4024-acae-52460a53d47c','看小舟除萍二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','花伴吟哦柳伴行，生憎庭外晚衙聲。',32,'全唐诗/poet.song.141000.json','["花伴吟哦柳伴行，生憎庭外晚衙聲。", "獨携便面巡荷沼，自課蘭舟掠水萍。"]'),
('d8c1d3d3-1c6d-44a3-8c3c-c51229fb7137','看小舟除萍二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','歲歲荷花苦未多，綠萍蓋水礙新荷。',32,'全唐诗/poet.song.141000.json','["歲歲荷花苦未多，綠萍蓋水礙新荷。", "請君六月重來看，雲錦千機不犯梭。"]'),
('b03497fc-8038-40d6-af47-7e2d325c3207','讀退之李花詩','楊萬里','宋','宋诗','song-poetry','','[]','近紅暮看失燕支，遠白宵明雪色奇。',32,'全唐诗/poet.song.141000.json','["近紅暮看失燕支，遠白宵明雪色奇。", "花不見桃惟見李，一生不曉退之詩。"]'),
('30c37bc0-cf83-49a3-b473-3341c8144825','郡圃曉步因登披僊閣四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','昨來風日較暄些，破曉來遊特地佳。',32,'全唐诗/poet.song.141000.json','["昨來風日較暄些，破曉來遊特地佳。", "也自低頭花下過，依前撞落一頭花。"]'),
('5917b418-7a1c-48db-8245-a4e285ad6872','郡圃曉步因登披僊閣四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','李花半落雪成堆，末後桃花陸續開。',32,'全唐诗/poet.song.141000.json','["李花半落雪成堆，末後桃花陸續開。", "白錦地衣紅錦障，侵晨供張等儂來。"]'),
('05dcf870-fdc1-4acb-b007-445e2f5f5194','郡圃曉步因登披僊閣四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','百五佳時更絕晨，園丁猶未放遊人。',32,'全唐诗/poet.song.141000.json','["百五佳時更絕晨，園丁猶未放遊人。", "瘦藤拄上披僊閣，四面花光照殺春。"]'),
('a301a1ea-f9fa-48b0-9dea-28212cf0a559','郡圃曉步因登披僊閣四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','只道春來不見痕，風邀雨勒未忺人。',32,'全唐诗/poet.song.141000.json','["只道春來不見痕，風邀雨勒未忺人。", "暄雲淑日消多少，花柳匆匆了却春。"]'),
('0b59da62-8685-4840-a4e4-cd7c12f79cc2','嘲報春花','楊萬里','宋','宋诗','song-poetry','','[]','嫩黄老碧已多時，騃紫癡紅略萬枝。',32,'全唐诗/poet.song.141000.json','["嫩黄老碧已多時，騃紫癡紅略萬枝。", "始有報春三兩朶，春深猶自不曾知。"]'),
('0e024978-31c6-425a-b205-d9c6e5b78874','垂絲海棠盛開','楊萬里','宋','宋诗','song-poetry','','[]','垂絲別得一風光，誰道全輸蜀海棠。',64,'全唐诗/poet.song.141000.json','["垂絲別得一風光，誰道全輸蜀海棠。", "風攪玉皇紅世界，日烘青帝紫衣裳。", "嬾無氣力仍春醉，睡起精神欲曉粧。", "舉似老夫新句子，看渠桃杏敢承當。"]'),
('251d236f-7c3e-4c32-9b60-acf860477746','酴醾初發','楊萬里','宋','宋诗','song-poetry','','[]','一春長是怨春遲，過却春光總不知。',32,'全唐诗/poet.song.141000.json','["一春長是怨春遲，過却春光總不知。", "已負海棠桃李了，再三莫更負酴醾。"]'),
('84817867-01fa-4266-8782-23c57222a29f','荷亭倚欄','楊萬里','宋','宋诗','song-poetry','','[]','魚跳龜戲不曾閑，萍盡荷生尚未繁。',32,'全唐诗/poet.song.141000.json','["魚跳龜戲不曾閑，萍盡荷生尚未繁。", "水面圜紋亂相入，玻瓈盆旋玉連環。"]'),
('b067ed4d-a1cc-4c15-a9a8-fc1f359d0d61','披僊閣上觀酴醾二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','仰架遥看時見些，登樓下瞰脫然佳。',32,'全唐诗/poet.song.141000.json','["仰架遥看時見些，登樓下瞰脫然佳。", "酴醾蝴蝶渾無辨，飛去方知不是花。"]'),
('ad0dcd1b-0e18-411d-ba67-8b6f6a2008e5','披僊閣上觀酴醾二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','酴醾約我早來看，及至來看花已殘。',32,'全唐诗/poet.song.141000.json','["酴醾約我早來看，及至來看花已殘。", "動地寒風君莫怯，亂吹香雪灑欄干。"]'),
('eaa82f50-82c3-4d21-aca9-3d9461dcff95','亦山亭前梅子','楊萬里','宋','宋诗','song-poetry','','[]','道傍小樹復低枝，摘盡青梅肯更遺。',32,'全唐诗/poet.song.141000.json','["道傍小樹復低枝，摘盡青梅肯更遺。", "偶爾葉間留一箇，且看漏眼幾多時。"]'),
('3b4ecbaa-24e0-4b8d-a540-06e31357fd21','塹荷池水','楊萬里','宋','宋诗','song-poetry','','[]','雨中來看塹池塘，自與畦丁細校量。',32,'全唐诗/poet.song.141000.json','["雨中來看塹池塘，自與畦丁細校量。", "更放水痕高幾許，浮荷猶剩若干長。"]'),
('e0436f09-5828-4cad-9c6e-704249c5a838','初夏玉井亭晚立','楊萬里','宋','宋诗','song-poetry','','[]','冶蕊倡花一雨空，鮮晴新漲未虧儂。',64,'全唐诗/poet.song.141000.json','["冶蕊倡花一雨空，鮮晴新漲未虧儂。", "竹兼樹影眠天底，人憑欄干立鏡中。", "看盡水衣投北岸，方知今日是南風。", "黄鸝對語無尋處，忽見雙飛入別叢。"]'),
('9f20e4a3-29e3-49ca-b202-999e9413767c','送曾無逸入爲掌故','楊萬里','宋','宋诗','song-poetry','','[]','吉文江水走玉虹，我家水西君水東。',128,'全唐诗/poet.song.141000.json','["吉文江水走玉虹，我家水西君水東。", "有時相思即命駕，連牀夜兩聽松風。", "中間薄宦各分散，南飛鴐鵝北飛雁。", "朝來驛騎打譙門，有客有客來相見。", "聞君携家入帝京，椎鼓發船天上行。", "也能枉轍九十里，來訪江西道院僧。", "詩家兩僊宿臺省，紅藥蒼苔紫薇影。", "若問山僧作麽生，日晏鶑啼眠不醒。"]'),
('de47a8a3-2ad5-42ab-8d75-4f5b4b18b27c','觀荷上雨','楊萬里','宋','宋诗','song-poetry','','[]','細雨霑荷散玉塵，聚成顆顆小珠新。',32,'全唐诗/poet.song.141000.json','["細雨霑荷散玉塵，聚成顆顆小珠新。", "跳來跳去還收去，祇有瓊柈弄水銀。"]'),
('1dfbe5de-62fe-45f4-bbb0-1bdf72c8532f','筠庵','楊萬里','宋','宋诗','song-poetry','','[]','故老談李僊，晉日上寥廓。',192,'全唐诗/poet.song.141000.json','["故老談李僊，晉日上寥廓。", "隨身無長物，止跨一隻鶴。", "鶴本非胎生，古卵尚遺殻。", "千年石似堅，覆在鳳山脚。", "寒宵晦風雨，神光照巖壑。", "犬嘷雞夜鳴，龍泣人寢愕。", "祇今筠庵是，因物非繩削。", "當時菢破處，作門不關鑰。", "蓋以一把茅，聊以護霜雹。", "遐瞻如釣翁，蓑衣逐層著。", "我來驗幽討，意尚疑諺謔。", "霧中披羽衣，砌下脫芒屩。", "入戶環仰觀，中空生響諾。", "不見朱頂雛，猶存雪色膜。", "松梢雙老鸛，戛然下簷角。", "老夫忽心驚，不敢小盤礴。"]'),
('030e7dc1-06d8-45a1-aa82-b64124508d95','晚步','楊萬里','宋','宋诗','song-poetry','','[]','清水芙蓉未肯開，暑天花草底差排。',32,'全唐诗/poet.song.141000.json','["清水芙蓉未肯開，暑天花草底差排。", "鹿葱金鳳何爲者，也得園亭護兩階。"]'),
('d2926dcf-7f08-4c65-a585-810955a11286','翠樾亭前鶑巢','楊萬里','宋','宋诗','song-poetry','','[]','仰聽金衣語，偶窺鶑婦巢。',48,'全唐诗/poet.song.141000.json','["仰聽金衣語，偶窺鶑婦巢。", "深穿喬木裏，危挂弱枝稍。", "啄菢雙雙子，經營寸寸茅。", "何時雛脫殻，新哢響交交。"]'),
('c48f96bb-a075-4c7d-be24-73c835f6180b','新暑追凉','楊萬里','宋','宋诗','song-poetry','','[]','去歲衝炎橫大江，今年度暑卧筠陽。',64,'全唐诗/poet.song.141000.json','["去歲衝炎橫大江，今年度暑卧筠陽。", "滿園無數好亭子，一夏不知何許涼。", "待等老夫親勘當，更招幽鳥細商量。", "朝慵午倦誰相伴，貓枕桃笙苦竹牀。"]'),
('a0d3c8ae-b02f-4fff-9966-86134016e7ca','書孫公談圃談圃載子由爲黄白術將舉火一貓據爐而溺須臾不見','楊萬里','宋','宋诗','song-poetry','','[]','少許丹砂和水銀，鍊成紫磨賺癡人。',32,'全唐诗/poet.song.141000.json','["少許丹砂和水銀，鍊成紫磨賺癡人。", "潁濱莫笑貍奴著，却恐貍奴笑潁濱。"]'),
('cdbc4da8-5d2e-4740-ad97-2611cc144bc0','無訟堂觀簷間蛛絲','楊萬里','宋','宋诗','song-poetry','','[]','蜘蛛作網祇愁疎，密了還遭小雨餘。',32,'全唐诗/poet.song.141000.json','["蜘蛛作網祇愁疎，密了還遭小雨餘。", "漏却飛蟲渾細事，無妨網得萬真珠。"]'),
('0d62bfc1-3f93-42ef-b57c-191d7b2c4c93','黄世成挽辭','楊萬里','宋','宋诗','song-poetry','','[]','文行高無對，功名莫動渠。',48,'全唐诗/poet.song.141000.json','["文行高無對，功名莫動渠。", "寧登逸民傳，不著茂陵書。", "誰謂風流盡，猶疑信息疎。", "九京何所憾，玉樹滿庭除。"]'),
('5555e27c-8362-4c46-a2d4-89d5957432ba','筠庵午憩','楊萬里','宋','宋诗','song-poetry','','[]','筠庵稍不至，一至一回好。',96,'全唐诗/poet.song.141000.json','["筠庵稍不至，一至一回好。", "風從林梢落，吹亂竹根草。", "巾屨上下涼，鶑鵲左右噪。", "市聲元不近，靜聽遠亦到。", "石磴坐來溫，蘚徑浄如掃。", "書空作愁字，已忘偏旁了。", "猶自忘了愁，而況記得老。", "客來談世事，欲笑還嬾笑。"]'),
('06fc88dc-7814-4035-a1b3-19281fe322f5','玉井亭觀荷花','楊萬里','宋','宋诗','song-poetry','','[]','蕖僊初出波，照日穉猶怯。',84,'全唐诗/poet.song.141000.json','["蕖僊初出波，照日穉猶怯。", "密排碧羅蓋，低護紅玉頰。", "館之水精宮，環以瑠璃堞。", "珠明浮盤戲，酒漾流杯曄。", "青筆尖欲試，綠牋皺還摺。", "老龜大於錢，辛勤上團葉。", "忽聞人履聲，入水一何捷。"]'),
('b1a2b572-8485-417b-83a5-fbb24932dddf','碧落堂暮景轆轤體','楊萬里','宋','宋诗','song-poetry','','[]','碧落堂中夕眺餘，一聲哀角裂晴虛。',64,'全唐诗/poet.song.141000.json','["碧落堂中夕眺餘，一聲哀角裂晴虛。", "滿城煙靄忽然合，隔水人家恰似無。", "坐看荷山沉半脊，急歸道院了殘書。", "意行花底尋燈處，失脚偏嗔小史扶。"]'),
('55de9f8e-9185-4e0c-a17a-6a62a8032471','金鳳花','楊萬里','宋','宋诗','song-poetry','','[]','細看金鳳小花叢，費盡司花染作工。',32,'全唐诗/poet.song.141000.json','["細看金鳳小花叢，費盡司花染作工。", "雪色白邊袍色紫，更饒深淺四般紅。"]'),
('f0668a9b-41ca-43db-a739-2df934377894','雨後郡圃行散','楊萬里','宋','宋诗','song-poetry','','[]','劍池一日百週遭，雨後閑來照鬢毛。',64,'全唐诗/poet.song.141000.json','["劍池一日百週遭，雨後閑來照鬢毛。", "主管園林鶑稱意，巡行荷芰鷺宣勞。", "不須見我還飛去，便與移文告汝曹。", "一事惱人無問處，南山高是北山高。"]'),
('967815c1-d4d0-4bc1-ac36-8654c7297f91','閏五月十四日因哭小孫子蓬孫歸志浩然','楊萬里','宋','宋诗','song-poetry','','[]','憲孫哭了哭蓬孫，老眼元枯也濕巾。',64,'全唐诗/poet.song.141000.json','["憲孫哭了哭蓬孫，老眼元枯也濕巾。", "名宦何須深插脚，山林從此早抽身。", "禍無避處唯辭福，命不如渠强學人。", "吟了此詩還毀了，莫令一讀一傷神。"]'),
('a395c899-d723-403a-a3d2-4d24deaf5981','感興','楊萬里','宋','宋诗','song-poetry','','[]','去國還家一歲陰，鳳山錦水更登臨。',64,'全唐诗/poet.song.141000.json','["去國還家一歲陰，鳳山錦水更登臨。", "別來蠻觸幾百戰，險盡山川多少心。", "何似閑人無藉在，不妨冷眼看昇沉。", "荷花正閙蓮蓬嫩，月下松醪且滿斟。"]'),
('ca88e738-9490-4a3c-916b-a2d6eef231d6','後圃散策','楊萬里','宋','宋诗','song-poetry','','[]','花徑雨後涼，樹聲風外戰。',96,'全唐诗/poet.song.141000.json','["花徑雨後涼，樹聲風外戰。", "杖屨頓輕鬆，兒女同行散。", "少者前已失，老者後仍倦。", "隔林吹笑語，相聞如對面。", "明明去人近，眇眇彌步遠。", "松杉滿地影，一瞬忽不見。", "仰觀紫日輪，偶度白雲片。", "佳處留再來，前山未須徧。"]'),
('cb9b8340-d00c-4e24-ae79-f9d2a62f90dc','筠庵晚睡三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','碧玉新篁翳洞天，紺珉方斛貯山泉。',32,'全唐诗/poet.song.141000.json','["碧玉新篁翳洞天，紺珉方斛貯山泉。", "脫巾赤脚長松下，何處人間更有僊。"]'),
('6b1b432f-6323-4496-b858-d517baf85f37','筠庵晚睡三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一戶元無白板遮，兩窗新染藕絲紗。',32,'全唐诗/poet.song.141000.json','["一戶元無白板遮，兩窗新染藕絲紗。", "竹床品字排三隻，睡殺山風醉殺霞。"]'),
('82c62467-e9c5-4dd1-a9ae-6924e0362cb5','筠庵晚睡三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','享了荷花上番香，却穿竹徑百弓長。',32,'全唐诗/poet.song.141000.json','["享了荷花上番香，却穿竹徑百弓長。", "滿園亭榭都參遍，祇有筠庵第一涼。"]'),
('b00100d2-0d4f-44d0-a676-1bea4a7aaa13','觀迎神小兒社','楊萬里','宋','宋诗','song-poetry','','[]','花帽銖來重，綃裳水樣秋。',48,'全唐诗/poet.song.141000.json','["花帽銖來重，綃裳水樣秋。", "强行終較嬾，妍唱却成羞。", "鸚鵡棲葱指，芙蕖載錦舟。", "休看小兒社，只益老人愁。"]'),
('2dcbf0bf-3023-4318-a3da-f08ad911ff34','寄奉新鍾宰','楊萬里','宋','宋诗','song-poetry','','[]','傳語清心閣，欣逢詩主人。',48,'全唐诗/poet.song.141000.json','["傳語清心閣，欣逢詩主人。", "鶑花無恙否，風月一番新。", "舊日行吟處，今來跡已陳。", "應憐楊縣尹，鬚鬢兩如銀。"]'),
('69febb9b-7af8-4fcb-889f-df4b347d1b81','雨後曉登碧落堂','楊萬里','宋','宋诗','song-poetry','','[]','清晨上碧落，親手啟後戶。',96,'全唐诗/poet.song.141000.json','["清晨上碧落，親手啟後戶。", "斜東見西山，粹碧無纖霧。", "須臾半崦間，冉冉動微絮。", "吹作千峰雲，立變萬姿度。", "正北尋米山，遥隔一片雨。", "亭亭如仙子，曉起澣月露。", "天衣異人世，一色製輕素。", "兩山誰不奇，裴回未能去。"]'),
('7391cf0c-9a43-48a3-b503-993c82511f05','玉井亭觀白蓮二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','紅芙蕖雜白芙蕖，紅底終稠白底疎。',32,'全唐诗/poet.song.141000.json','["紅芙蕖雜白芙蕖，紅底終稠白底疎。", "速折當頭一蓮葉，莫令遮却雪肌膚。"]'),
('40d46f99-ef11-4217-8440-6b6456b3644c','玉井亭觀白蓮二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','白蓮出水是青蓮，昨日微舒带酒顔。',32,'全唐诗/poet.song.141000.json','["白蓮出水是青蓮，昨日微舒带酒顔。", "踏月來看開盡了，露華新洗玉杯寒。"]'),
('dc0d5f4f-0d46-4316-a4f6-edf4838c9350','新秋晚酌','楊萬里','宋','宋诗','song-poetry','','[]','胡床東鄉坐，秋風忽淒其。',108,'全唐诗/poet.song.141000.json','["胡床東鄉坐，秋風忽淒其。", "老夫衰病骨，急令閉東扉。", "西扉亦半掩，壓風作東吹。", "何必風及我，風入涼自馳。", "晚蟬見誰說，我飲渠便知。", "飛從何方來，徑集庭樹枝。", "三歎復九詠，話盡新秋悲。", "我老悲已忘，汝語復爲誰。", "老烏啼一聲，不知蟬所之。"]'),
('84488b6e-abcd-4965-8795-3f79dc4072dd','碧落堂曉望荷山','楊萬里','宋','宋诗','song-poetry','','[]','荷山非不高，城裏自不見。',120,'全唐诗/poet.song.141000.json','["荷山非不高，城裏自不見。", "一登碧落堂，山色正對面。", "如人卧平地，躍起立天半。", "指揮出伏兵，萬騎橫隔岸。", "後乘來未已，前驅瞻已遠。", "晨光到巖壑，人物俱蒨絢。", "綠屏紛開闔，翠旗閃舒卷。", "安得垂天虹，橋虛度雲巘。", "老鈴偶報事，郡庭集賓贊。", "匆匆換山巾，默默下林坂。"]'),
('8f4489bd-bbdc-4c0d-8ba1-fc044c169ddb','午憩筠庵','楊萬里','宋','宋诗','song-poetry','','[]','筠庵偶坐處，適當樹闕間。',84,'全唐诗/poet.song.141000.json','["筠庵偶坐處，適當樹闕間。", "遠山不見我，而我見遠山。", "清風隔江來，宛轉入松關。", "翠蕉自摇扇，白羽得暫閑。", "可憐三竹床，睡徧復循環。", "秋暑自秋暑，山寒自山寒。", "小吟聊適意，美惡不必刪。"]'),
('64bf2fbc-2795-473e-aa8c-67e6593cea0c','題無訟堂屏上袁安卧雪圖','楊萬里','宋','宋诗','song-poetry','','[]','雲窗避三伏，竹床橫一丈。',144,'全唐诗/poet.song.141000.json','["雲窗避三伏，竹床橫一丈。", "退食急袒跣，病身聊偃仰。", "有夢元無夢，似想亦非想。", "滿堂變冥晦，寒陰起森爽。", "門外日如焚，屏間雪如掌。", "蕭然聳毛髮，皎若照襟幌。", "拔地排瑶松，倚天立銀嶂。", "遥見幽人廬，茅棟壓欲響。", "有客叩柴門，高軒隘村巷。", "剝啄久不聞，徙倚覺深悵。", "幽人寐政熟，何知有令長。", "誰作卧雪圖，我得洗炎瘴。"]'),
('4c689872-3f33-4017-b375-492a7a2ca922','七月十日大雨曉霽登碧落堂','楊萬里','宋','宋诗','song-poetry','','[]','青天送歸雲，整如勞還師。',108,'全唐诗/poet.song.141000.json','["青天送歸雲，整如勞還師。", "顔行有喜色，廝役爭奔隨。", "晨曦映疎雨，寶燈貫銀絲。", "落面何曾濕，灑空不勝微。", "老夫銳登山，半嶺驚欲歸。", "仰視得奇觀，徙倚爲久之。", "誰言李成巧，此畫天下稀。", "却登碧落堂，四面天風吹。", "葛製忍秋寒，前夕酷暑時。"]'),
('87c60997-4ec2-4412-99fd-87e6f6a3ebe8','微雨玉井亭觀荷','楊萬里','宋','宋诗','song-poetry','','[]','猛雨打萬荷，怒聲戰秋鼙。',72,'全唐诗/poet.song.141000.json','["猛雨打萬荷，怒聲戰秋鼙。", "水銀忽成泓，一寫無復遺。", "不如微雨來，翠盤萬珠璣。", "荷翻珠不落，細響密更稀。", "清如雪觸窗，三更夢聞時。", "語君君不信，對境當自知。"]'),
('a40c9402-55e1-4764-8ba5-70382e69c358','碧落堂晚望','楊萬里','宋','宋诗','song-poetry','','[]','暮笳聲裏暮雲生，白白非煙覆一城。',32,'全唐诗/poet.song.141000.json','["暮笳聲裏暮雲生，白白非煙覆一城。", "祇有青林遮不得，兜羅綿上綠琴橫。"]'),
('a8e5c47c-7385-4dc0-9e10-f3ce81b5a839','觀書','楊萬里','宋','宋诗','song-poetry','','[]','書冊不可逢，逢得放不得。',60,'全唐诗/poet.song.141000.json','["書冊不可逢，逢得放不得。", "看得眼昏花，放了還太息。", "掩卷味方深，豈問忘與憶。", "是身何曾動，忽然超八極。", "祇言半窗間，不是華胥國。"]'),
('19599fdd-443e-4d88-bfab-76dc50b0882a','中元日曉登碧落堂望南北山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','節裏少公事，底忙起侵晨。',48,'全唐诗/poet.song.141000.json','["節裏少公事，底忙起侵晨。", "望秋怯殘暑，及此東未暾。", "登山俯平野，萬壑皆白雲。", "身在白雲上，不知雲繞身。"]'),
('160fb1d2-f5d0-4a15-8be7-3e659a804c59','中元日曉登碧落堂望南北山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','米山不知重，近見三兩疊。',48,'全唐诗/poet.song.141000.json','["米山不知重，近見三兩疊。", "遠者淡不真，眇與天相接。", "晨光染紅雲，正向山外貼。", "映出青萬層，還與雲俱滅。"]'),
('d9509b04-ccc7-4990-9eda-a17545e3273d','答陸務觀佛祖道院之戲','楊萬里','宋','宋诗','song-poetry','','[]','老禪分得破叢林，薄供微齋也不曾。',64,'全唐诗/poet.song.141000.json','["老禪分得破叢林，薄供微齋也不曾。", "道院敕差權院事，筠庵身是住庵僧。", "人間赤日方如火，松下清風獨似冰。", "別有暮春沂水在，爲君一滴灑千燈。"]'),
('70c28871-2903-4721-a43c-3feaa22d0615','寄中洲茶與尤延之延之有詩再寄黄檗茶仍和其韻','楊萬里','宋','宋诗','song-poetry','','[]','詩人可笑信虛名，擊節茶芽意不輕。',64,'全唐诗/poet.song.141000.json','["詩人可笑信虛名，擊節茶芽意不輕。", "爾許中洲真後輩，與君顧渚敢連衡。", "山中寄去無多子，天上歸來太瘦生。", "更送玉塵澆錫水，爲搜孔思攪周情。"]'),
('f6935cc3-3fa9-477b-8679-3511e3c3f330','延之寄詩覓道院集遣騎送呈和韻謝之','楊萬里','宋','宋诗','song-poetry','','[]','與君鬢髮總星星，詩句輸君老更成。',64,'全唐诗/poet.song.141000.json','["與君鬢髮總星星，詩句輸君老更成。", "別去多時頻夢見，夜來一雨又秋生。", "故人金石情猶在，贈我瓊琚雪似清。", "誰把尤楊語同日，不教李杜獨齊名。"]'),
('60cab2de-5329-49a4-b9df-421a110f8558','祗召還京題江西道院','楊萬里','宋','宋诗','song-poetry','','[]','病身祇要早投閑，乞得高安政小安。',64,'全唐诗/poet.song.141000.json','["病身祇要早投閑，乞得高安政小安。", "山水秋來渾是畫，樓臺高處自生寒。", "登臨未足還辭去，老大重來畢竟難。", "碧落翠微好將息，清風明月夢中看。"]'),
('8a682036-391a-423f-8849-97cabfb49568','問塗有日戲題郡圃','楊萬里','宋','宋诗','song-poetry','','[]','今年郡圃放遊人，懊惱遊人作撻春。',64,'全唐诗/poet.song.141000.json','["今年郡圃放遊人，懊惱遊人作撻春。", "到得老夫來散策，亂吹花片總成塵。", "商量歲後牢關鎖，拘管風光屬病身。", "造物嗔儂先遣去，遣儂儂去不須嗔。"]'),
('278739e8-daad-44de-9cef-c4d684a12c28','辭棲真室蓋晉僊人李八百故居之址中有遺像云','楊萬里','宋','宋诗','song-poetry','','[]','李真宅子故依然，道院西偏古洞前。',64,'全唐诗/poet.song.141000.json','["李真宅子故依然，道院西偏古洞前。", "一日身遊八百里，三番花落九千年。", "劍池丹井俱蒼蘚，絳節霓旌已碧天。", "借問飛僊那用步，步行猶是地行僊。"]'),
('d3be59a2-d5a5-4cf1-a055-9fb97f6a1176','留題筠庵以茅蓋層出如蓑衣然','楊萬里','宋','宋诗','song-poetry','','[]','茂林脩竹翠光中，那得披蓑一老翁。',64,'全唐诗/poet.song.141000.json','["茂林脩竹翠光中，那得披蓑一老翁。", "白石砌成珠子徑，黄茅裹却水晶宮。", "夏涼冬暖非人境，雪打霜封即釣篷。", "老子明朝便東去，更携瓦枕享松風。"]'),
('4e1e4a60-c883-4f28-923c-7f7a8b36d36e','留題碧落堂','楊萬里','宋','宋诗','song-poetry','','[]','僊人白日上青冥，千載如聞月下笙。',64,'全唐诗/poet.song.141000.json','["僊人白日上青冥，千載如聞月下笙。", "南北萬山俱在下，中間一水獨穿城。", "江西箇是絕奇處，天下幾多虛得名。", "滕閣孤臺非不好，祇緣猶带市朝聲。"]'),
('05c9c40f-3548-4438-8cbb-55eaa0ca21ba','明發生米市西林寺進退格','楊萬里','宋','宋诗','song-poetry','','[]','貪睡能無起，挑燈强未殘。',48,'全唐诗/poet.song.141000.json','["貪睡能無起，挑燈强未殘。", "舂聲忙野店，月色澹柴門。", "又踏黄塵路，前追紅葉村。", "秋衣那敢薄，病骨自難溫。"]'),
('967c467e-b25f-472e-9281-166c43a3fa46','自生米小路出舞陽渡','楊萬里','宋','宋诗','song-poetry','','[]','獨徑千盤繞水田，初逢官路一欣然。',32,'全唐诗/poet.song.141000.json','["獨徑千盤繞水田，初逢官路一欣然。", "舞陽渡口新河水，白髮重來二十年。"]'),
('de229d01-f3db-4e8c-b20d-eee2595f7444','羲娥謠','楊萬里','宋','宋诗','song-poetry','','[]','羲和夢破欲啟行，紫金畢逋啼一聲。',112,'全唐诗/poet.song.141000.json','["羲和夢破欲啟行，紫金畢逋啼一聲。", "聲從天上落人世，千村萬落雞爭鳴。", "素娥西征未歸去，簸弄銀盤浣風露。", "一丸玉彈東飛來，打落桂林雪毛兔。", "誰將紅錦幕半天，赤光絳氣貫山川。", "須臾却駕丹砂轂，推上寒空輾蒼玉。", "詩翁已行十里强，羲和早起道無雙。"]'),
('91dd9503-095d-43d4-8b36-479ef5417cf6','小憩土坊鎮新店進退格','楊萬里','宋','宋诗','song-poetry','','[]','下轎逢新店，排門得小軒。',48,'全唐诗/poet.song.141000.json','["下轎逢新店，排門得小軒。", "中間一棐几，相對兩蒲團。", "椽竹青留節，簷茅白带根。", "明窗有遺恨，接處紙痕班。"]'),
('608798bb-15f4-4fd6-b26a-a4f1652a4efa','過羅溪南望撫州泉嶺','楊萬里','宋','宋诗','song-poetry','','[]','泉嶺諸峰太劣生，與儂爭走學儂行。',32,'全唐诗/poet.song.141000.json','["泉嶺諸峰太劣生，與儂爭走學儂行。", "蒼官總上山頭去，一色前驅娖翠旌。"]'),
('3f8e5f7f-0680-485d-8e10-3dfea69cdfbe','羅溪望夫嶺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','藁砧不寄大刀頭，化作峰頭石也愁。',32,'全唐诗/poet.song.141000.json','["藁砧不寄大刀頭，化作峰頭石也愁。", "豈有心情管風雨，向人彈淚繞天流。"]'),
('8b30812f-6b04-42bc-b497-2c9feee3e8da','羅溪望夫嶺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','行役家家寄刀尺，誰將枯骨带心頭。',32,'全唐诗/poet.song.141000.json','["行役家家寄刀尺，誰將枯骨带心頭。", "惟有望夫心志苦，甘霖偏爲七娘流。"]'),
('4cbbc4a5-c030-4fc9-a341-82485682b151','題羅溪李店  其一','楊萬里','宋','宋诗','song-poetry','','[]','棟宇整齊窗戶明，一峰對面一江橫。',32,'全唐诗/poet.song.141000.json','["棟宇整齊窗戶明，一峰對面一江橫。", "下程長是無佳店，佳店偏當未下程。"]'),
('775c0e92-6043-48c0-b5df-4990bfdd6b84','題羅溪李店  其二','楊萬里','宋','宋诗','song-poetry','','[]','誰道村郊野味侵，柴扉竹榻草花清。',32,'全唐诗/poet.song.141000.json','["誰道村郊野味侵，柴扉竹榻草花清。", "行行且止成佳夢，不減崔張驚夢身。"]'),
('4085bc33-9f31-467b-9b6f-bd77242edffc','羅溪道中','楊萬里','宋','宋诗','song-poetry','','[]','每歲秋猶熱，今年閏故涼。',48,'全唐诗/poet.song.141000.json','["每歲秋猶熱，今年閏故涼。", "松稀青有數，山遠碧無常。", "陣陣金風細，家家玉粒香。", "祇言官路短，堠子暗添長。"]'),
('188b84c0-af39-4a2f-bbe2-509c9fa617ef','戲贈江干蘆花','楊萬里','宋','宋诗','song-poetry','','[]','避世水雲國，卜鄰鷗鷺家。',48,'全唐诗/poet.song.141000.json','["避世水雲國，卜鄰鷗鷺家。", "風前揮玉麈，霜後幻楊花。", "骨相緣詩瘦，秋聲訴月華。", "欲招盧處士，歸共老生涯。"]'),
('28379425-1ee0-4f59-8030-750c34f00b31','詠十里塘姜店水亭前竹林','楊萬里','宋','宋诗','song-poetry','','[]','一見此君面，荒村不是村。',48,'全唐诗/poet.song.141000.json','["一見此君面，荒村不是村。", "斜陽與可筆，棲雀子猷魂。", "客思方無那，詩愁得共論。", "問渠能飲否，把酒酹霜根。"]'),
('d287f61d-f135-439f-b5c2-17719f3b8d8b','題姜店水亭子','楊萬里','宋','宋诗','song-poetry','','[]','簾拂雲間竹，窗摇水下天。',48,'全唐诗/poet.song.141000.json','["簾拂雲間竹，窗摇水下天。", "欄干斜倚處，風物正淒然。", "送眼看群叟，收罾得小鮮。", "可憐碧玉沼，不種一枝蓮。"]'),
('30628373-fdbb-4c60-bdfa-ee3631915ae5','待家釀未至且買姜店村酒','楊萬里','宋','宋诗','song-poetry','','[]','奔走人都倦，檐檠酒未來。',48,'全唐诗/poet.song.141000.json','["奔走人都倦，檐檠酒未來。", "那能待竹葉，隨喜喚茅柴。", "蘆菔仍多煮，菴摩带淺煨。", "深村市無肉，草草兩三杯。"]'),
('378d0a7e-45f8-4928-9b8e-5eadcab7ea76','十里塘觀魚','楊萬里','宋','宋诗','song-poetry','','[]','銀塘打盡萬銀梭，岸上笭箵來正多。',32,'全唐诗/poet.song.141000.json','["銀塘打盡萬銀梭，岸上笭箵來正多。", "船載月明猶有月，無船無月欲如何。"]'),
('028cad93-00d1-4179-9137-74afc50feeee','再觀十里塘捕魚有歎','楊萬里','宋','宋诗','song-poetry','','[]','漁者都星散，那知不是真。',48,'全唐诗/poet.song.141000.json','["漁者都星散，那知不是真。", "忽然重舉網，何許有逃鱗。", "暗漉泥中玉，光跳日下銀。", "江湖無避處，而況野塘濱。"]'),
('0688a45a-9575-4966-9280-b0bc79a4fc0d','題十里塘夜景','楊萬里','宋','宋诗','song-poetry','','[]','物色當秋半，登臨更夜闌。',48,'全唐诗/poet.song.141000.json','["物色當秋半，登臨更夜闌。", "山光倒眠水，水影上摇山。", "宿鷺都飛去，漁人獨未還。", "老夫與明月，分割一清灣。"]'),
('c35908d1-817a-4b8e-afc5-9f6ea55455f1','南望閣皂山','楊萬里','宋','宋诗','song-poetry','','[]','慚愧多情閣皂山，去年迎我上西船。',32,'全唐诗/poet.song.141000.json','["慚愧多情閣皂山，去年迎我上西船。", "今來送我還東去，四日相隨到進賢。"]'),
('1ea00f4b-9bf1-4dcb-9d0c-9f6a1a5d639b','晨炊熊家莊','楊萬里','宋','宋诗','song-poetry','','[]','朝饑一眼望炊煙，繞盡長溪過盡山。',32,'全唐诗/poet.song.141000.json','["朝饑一眼望炊煙，繞盡長溪過盡山。", "承露絲囊世無樣，蜘蛛偷得掛籬間。"]'),
('37c0a4d4-f20f-4309-a030-db3637468093','道傍小松','楊萬里','宋','宋诗','song-poetry','','[]','小松如小兒，能坐未能立。',48,'全唐诗/poet.song.141000.json','["小松如小兒，能坐未能立。", "亂髮覆地皮，勁氣排雪汁。", "誰將救暍手，種此青戢戢。", "秋陽暴行人，清蔭何時及。"]'),
('fe712a1f-61ad-4744-9a9f-f5c99b88c630','行役有歎  其一','楊萬里','宋','宋诗','song-poetry','','[]','去年丐西歸，謂可休餘生。',48,'全唐诗/poet.song.141000.json','["去年丐西歸，謂可休餘生。", "今年復東下，駕言入神京。", "卧治方小安，趨召豈不榮。", "何如還家樂，醉吟聽溪聲。"]'),
('d733f7c5-8db7-46f5-850f-94890c3b6bb5','行役有歎  其二','楊萬里','宋','宋诗','song-poetry','','[]','百年幾暄涼，再歲三征行。',48,'全唐诗/poet.song.141000.json','["百年幾暄涼，再歲三征行。", "却羨路旁叟，白首不到城。", "人生如風花，去來能與爭。", "且隨風吹起，會當風自停。"]'),
('f88e7707-cc76-41bd-b911-840150d251ff','山店松聲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','脩塗殘暑僕夫勞，午憩茅簷尺許高。',32,'全唐诗/poet.song.141000.json','["脩塗殘暑僕夫勞，午憩茅簷尺許高。", "忽有涼風颯然起，小松呼舞大松號。"]'),
('2cda3d33-1f59-4686-a137-840ab07a6fbd','山店松聲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','松本無聲風亦無，適然相值兩相呼。',32,'全唐诗/poet.song.141000.json','["松本無聲風亦無，適然相值兩相呼。", "非金非石非絲竹，萬頃雲濤殷五湖。"]'),
('3ec87169-7360-4760-9491-4e4796008c1e','池陂鄧店松林','楊萬里','宋','宋诗','song-poetry','','[]','破店誰相伴，疎松對作行。',48,'全唐诗/poet.song.141000.json','["破店誰相伴，疎松對作行。", "捲鱗乾不脫，落子拆猶香。", "聲攪三更夢，陰和片月涼。", "吾廬萬株碧，回首暮蒼蒼。"]'),
('e33738e7-8461-4227-a5b0-d8f6fd19e6e3','嘗諸店酒醉吟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','飲酒定不醉，嘗酒方有味。',48,'全唐诗/poet.song.141000.json','["飲酒定不醉，嘗酒方有味。", "清濁與醇醨，雜酌注愁肺。", "偶爾遇真趣，頹然得佳寐。", "醒人作醉語，語好終不是。"]'),
('c624aab4-e9ed-4949-92d4-c1827de049aa','嘗諸店酒醉吟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','我飲無定數，一杯復一杯。',48,'全唐诗/poet.song.141000.json','["我飲無定數，一杯復一杯。", "醉來我自止，不須問樽罍。", "白眼望青天，青天爲我開。", "青天不開時，我醉眠蒼苔。"]'),
('c6e9cb9c-7898-48bb-b675-e6680374ba6d','煙林曉望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一疊青松一疊煙，橫鋪平野有無間。',32,'全唐诗/poet.song.141000.json','["一疊青松一疊煙，橫鋪平野有無間。", "真成萬丈鵝溪絹，畫出江西秋曉山。"]'),
('1ac7681e-c00c-41e9-978f-d79cbefc6b3f','煙林曉望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','也沒炊煙也沒雲，日光烘起楚山氛。',32,'全唐诗/poet.song.141000.json','["也沒炊煙也沒雲，日光烘起楚山氛。", "却將重碧施輕素，不見天工一筆痕。"]'),
('6950d07e-9225-44c4-8550-0f15fb991780','過土筧岡','楊萬里','宋','宋诗','song-poetry','','[]','木落初宜菜，亭荒不復茅。',48,'全唐诗/poet.song.141000.json','["木落初宜菜，亭荒不復茅。", "牛分叉路口，鸛立秃松梢。", "秋熱方昇日，朝涼更迥郊。", "衰年走塵鞅，何計返雲巢。"]'),
('d6786cc9-2e85-4c41-9003-23c37aa15d24','曉風','楊萬里','宋','宋诗','song-poetry','','[]','剩暑遲旋旆，新風急解紛。',48,'全唐诗/poet.song.141000.json','["剩暑遲旋旆，新風急解紛。", "白翻蕎處雪，黄擺稻中雲。", "動地休多怒，披襟且一欣。", "長松十里徑，樹樹供清聞。"]'),
('ef352950-7efe-4baa-b4e0-5f29807126a0','晨炊旱塘','楊萬里','宋','宋诗','song-poetry','','[]','一歲官拘守一州，天將行役賜清游。',64,'全唐诗/poet.song.141000.json','["一歲官拘守一州，天將行役賜清游。", "青山綠水留連客，碧樹丹楓點綴秋。", "夜夢晝思都是景，左來右去不勝酬。", "我無韋偃丹青手，只向囊中句裏收。"]'),
('3355cb69-188c-4571-94ee-68118b821048','進賢初食白菜因名之以水精菜云二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','新舂雲子滑流匙，更嚼冰蔬與雪虀。',32,'全唐诗/poet.song.141000.json','["新舂雲子滑流匙，更嚼冰蔬與雪虀。", "靈隠山前水精菜，近來種子到江西。"]'),
('229e4f62-e917-4cc5-a42d-7e6f62eb92ac','進賢初食白菜因名之以水精菜云二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江西菜甲要霜栽，逗到炎天總不佳。',32,'全唐诗/poet.song.141000.json','["江西菜甲要霜栽，逗到炎天總不佳。", "浪說水菘水蘆菔，硬根瘦葉似生柴。"]'),
('02895aed-0369-436f-9dc6-a83ad8e87b78','田家樂','楊萬里','宋','宋诗','song-poetry','','[]','稻穗堆場穀滿車，家家雞犬更桑麻。',32,'全唐诗/poet.song.141000.json','["稻穗堆場穀滿車，家家雞犬更桑麻。", "漫栽木槿成籬落，已得清陰又得花。"]'),
('239d2dd0-1c80-4023-83df-defcb3b1aef4','道傍怪松','楊萬里','宋','宋诗','song-poetry','','[]','夾道長松去去幽，一松奇怪獨凌秋。',32,'全唐诗/poet.song.141000.json','["夾道長松去去幽，一松奇怪獨凌秋。", "兩枝垂地却翻上，活走雙龍戲翠毬。"]'),
('41f5cd83-b9ae-4f55-9318-bc6ca1d89cb7','過潤陂橋三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','潤陂初上板橋時，欲入江東尚未知。',32,'全唐诗/poet.song.141000.json','["潤陂初上板橋時，欲入江東尚未知。", "忽見橋心界牌子，脚根一半出江西。"]'),
('6ac5cc96-5cdc-432e-9a56-50c878edee89','過潤陂橋三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','却憶庚寅侍板輿，過橋橋斷費人扶。',32,'全唐诗/poet.song.141000.json','["却憶庚寅侍板輿，過橋橋斷費人扶。", "重來一見新橋了，淚濕秋風眼欲枯。"]'),
('85749e34-1336-4ed1-bb20-afd6da257794','過潤陂橋三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','歷覽溪中有底鳴，蕭然蘆葉蓼花汀。',32,'全唐诗/poet.song.141000.json','["歷覽溪中有底鳴，蕭然蘆葉蓼花汀。", "元來轎頂嗚嗚響，將謂風聲是雁聲。"]'),
('f4e4e90b-dc0a-4d61-b3af-d48e3f3cddaf','小憩揭家岡諦觀桐陰','楊萬里','宋','宋诗','song-poetry','','[]','仰看陽光只見空，不如影裏看梧桐。',32,'全唐诗/poet.song.141000.json','["仰看陽光只見空，不如影裏看梧桐。", "莫言日脚無行跡，偷轉零分破寸中。"]'),
('95e0b592-b25b-4bb7-9e60-baf4437eaf3f','宿花斜橋見雞冠花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','出牆那得丈高雞，只露紅冠隔錦衣。',32,'全唐诗/poet.song.141000.json','["出牆那得丈高雞，只露紅冠隔錦衣。", "却是吳兒工料事，會稽真箇不能啼。"]'),
('f28ef7ab-ebc1-4748-9cf3-5e427c785631','宿花斜橋見雞冠花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','陳倉金碧夜雙斜，一隻今棲紀渻家。',32,'全唐诗/poet.song.141000.json','["陳倉金碧夜雙斜，一隻今棲紀渻家。", "別有飛來矮人國，化成玉樹後庭花。"]'),
('1c2e7f18-d934-4b96-b4fb-fadbb04b6e26','小箬嶺望見靈山','楊萬里','宋','宋诗','song-poetry','','[]','青鞋紫陌倦黄埃，送眼靈山一快哉。',64,'全唐诗/poet.song.141000.json','["青鞋紫陌倦黄埃，送眼靈山一快哉。", "碧玉熏爐天半立，青蓮花萼霧中開。", "宿雲準擬偷將去，曉日殷勤喚出來。", "欲琢新詩鑱絕壁，梯空上去御風回。"]'),
('cc240186-1a2b-4083-8ba3-d2af5b03e823','入玉山七里頭','楊萬里','宋','宋诗','song-poetry','','[]','諸村不雨數旬餘，此地瀕江萬寶蘇。',64,'全唐诗/poet.song.141000.json','["諸村不雨數旬餘，此地瀕江萬寶蘇。", "晚紫豆花初總角，早黄稻穗已長鬚。", "回頭金步野徑遠，當面玉山秋塔孤。", "偶見年時解船處，客愁依舊掛菰蒲。"]'),
('842958b2-1616-43fb-81c6-b3949860ba64','過玉山東三塘五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','筍輿拾得小涼天，旋與開窗急捲簾。',32,'全唐诗/poet.song.141000.json','["筍輿拾得小涼天，旋與開窗急捲簾。", "十里輕雲閣秋日，日光移在遠峰尖。"]'),
('b95e5bb5-1ba2-4b37-b25c-20a1b61e66ea','過玉山東三塘五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','遠峰隔水醒人心，一半斜陽一半陰。',32,'全唐诗/poet.song.141000.json','["遠峰隔水醒人心，一半斜陽一半陰。", "僊子更衣晚粧束，紫茸領子翠毛衿。"]'),
('dfcc13ad-35cf-451a-b3df-dbd7fad37f7d','過玉山東三塘五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','赤日中塗綠樹陰，肯將碧繖借行人。',32,'全唐诗/poet.song.141000.json','["赤日中塗綠樹陰，肯將碧繖借行人。", "片雲忽在樹頭上，失却勳勞庇得身。"]'),
('23de3f43-7e4d-4afb-84ce-083358f6e494','過玉山東三塘五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','身行衢信兩中間，夾路尖峰面面寒。',32,'全唐诗/poet.song.141000.json','["身行衢信兩中間，夾路尖峰面面寒。", "只道秋山似春笋，不知春笋似秋山。"]'),
('2240ee15-bced-474c-99c3-9e669626bb2f','過玉山東三塘五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','繰車香裏過征衫，白繭黄絲兩兩三。',32,'全唐诗/poet.song.141000.json','["繰車香裏過征衫，白繭黄絲兩兩三。", "不是秋風上饒路，一生不信有冰蠶。"]'),
('c73a0c19-367c-4da2-ba3c-b7fc73c36f75','金雞石在玉山東二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','相傳石裏兩金雞，不記胡商鑿取時。',32,'全唐诗/poet.song.141000.json','["相傳石裏兩金雞，不記胡商鑿取時。", "一隻遭擒一飛去，至今月落不曾啼。"]'),
('12058492-ed71-4a0a-9543-3ce15c79223b','金雞石在玉山東二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','頭高尾下翠毿毿，却恐相傳是妄談。',32,'全唐诗/poet.song.141000.json','["頭高尾下翠毿毿，却恐相傳是妄談。", "十七里頭徐老店，簷東道北北橋南。"]'),
('63050f6b-b735-4617-880f-b0233c6710b3','秋山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','休道秋山索莫人，四時各自一番新。',32,'全唐诗/poet.song.141000.json','["休道秋山索莫人，四時各自一番新。", "西風儘有東風手，柿葉楓林別樣春。"]'),
('13afa169-d8f1-42b9-a373-ad64e0da75bc','秋山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','烏臼平生老染工，錯將鐵皂作猩紅。',32,'全唐诗/poet.song.141000.json','["烏臼平生老染工，錯將鐵皂作猩紅。", "小楓一夜偷天酒，却倩孤松掩醉容。"]'),
('c51f9ecf-e9ef-47f0-824c-92416a5964fa','宿查瀨','楊萬里','宋','宋诗','song-poetry','','[]','寒流一带檻前橫，落日諸峰霞外明。',64,'全唐诗/poet.song.141000.json','["寒流一带檻前橫，落日諸峰霞外明。", "水斷新洲添五里，客尋舊路却重行。", "江車自轉非人踏，沙碓長舂徹夜鳴。", "疇昔穉桑今秃樹，如何白髮不教生。"]'),
('a99de9e8-57a3-4f36-9d95-91054d2a3ffb','栟楮江濱芙蓉一株發紅白二色二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','芙蓉照水弄嬌斜，白白紅紅各一家。',32,'全唐诗/poet.song.141000.json','["芙蓉照水弄嬌斜，白白紅紅各一家。", "近日司花出新巧，一枝能著兩般花。"]'),
('a68e82d4-e4c6-429e-9eb6-2c5e8580c26a','栟楮江濱芙蓉一株發紅白二色二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','司花手法我能知，說破當知未大奇。',32,'全唐诗/poet.song.141000.json','["司花手法我能知，說破當知未大奇。", "亂剪素羅裝一樹，略將數朶蘸燕支。"]'),
('9c3f6f8e-bbae-41cf-83c5-d9a06974d38e','過上湖嶺望招賢江南北山四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','遠山高絕近山低，未必低山肯下伊。',32,'全唐诗/poet.song.141000.json','["遠山高絕近山低，未必低山肯下伊。", "定是遠山矜狡獪，跳青湧碧角幽奇。"]'),
('195d8f0d-3699-42b7-a166-10a608b08984','過上湖嶺望招賢江南北山四首  其二','楊萬里','宋','宋诗','song-poetry','','["\u6292\u60c5"]','嶺下看山似伏濤，見人上嶺旋爭豪。',32,'全唐诗/poet.song.141000.json','["嶺下看山似伏濤，見人上嶺旋爭豪。", "一登一陟一回顧，我脚高時他更高。"]'),
('e5ba5753-d803-4496-97dd-d8df10b4a718','過上湖嶺望招賢江南北山四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一水橫拖兩岸峰，千痕萬摺碧重重。',32,'全唐诗/poet.song.141000.json','["一水橫拖兩岸峰，千痕萬摺碧重重。", "誰言老子經行處，身在江山障子中。"]'),
('cb29f41d-a7cd-4e49-a8c6-ab70dba83a4b','過上湖嶺望招賢江南北山四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','曉日秋山破格奇，青紅明滅舞清漪。',32,'全唐诗/poet.song.141000.json','["曉日秋山破格奇，青紅明滅舞清漪。", "畫工著色饒渠巧，便有此容無此姿。"]'),
('25bbea49-83cd-42a6-bc85-6bf095fb21c6','觀田中鸜鵒啄粟因悟象耕鳥耘之說戲題二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','烏衣緇布外無華，白錦中單分外嘉。',32,'全唐诗/poet.song.141000.json','["烏衣緇布外無華，白錦中單分外嘉。", "只麽跳行人不覺，忽然飛起自成花。"]'),
('083bf064-08f2-40ca-b7fa-e61e9767c41b','觀田中鸜鵒啄粟因悟象耕鳥耘之說戲題二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','粟黄蕎白未全秋，誰報烏衣早作偷。',32,'全唐诗/poet.song.141000.json','["粟黄蕎白未全秋，誰報烏衣早作偷。", "只在林梢築倉廩，便知去處若爲搜。"]'),
('303a3565-47bb-4842-9da2-0fdd7e248e6e','衢州近城果園','楊萬里','宋','宋诗','song-poetry','','[]','未到衢州五里時，果林一望蔽江湄。',32,'全唐诗/poet.song.141000.json','["未到衢州五里時，果林一望蔽江湄。", "黄柑綠橘深紅柿，樹樹無風縋脫枝。"]'),
('80697971-7503-4286-9a46-177992c6f5ba','過三衢徐載叔採菊載酒夜酌走筆二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','征塗半月客塵黄，今夕初逢一雨涼。',32,'全唐诗/poet.song.141000.json','["征塗半月客塵黄，今夕初逢一雨涼。", "冷笑菊花堪計會，爲君八月作重陽。"]'),
('24b07364-697b-417f-b75b-57c6b0508850','過三衢徐載叔採菊載酒夜酌走筆二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','疾風動地雨傾荷，一事商量君信麽。',32,'全唐诗/poet.song.141000.json','["疾風動地雨傾荷，一事商量君信麽。", "試問糟床與簷溜，雨聲何似酒聲多。"]'),
('795e6154-54fd-4055-856c-424419ced4fb','浮石清曉放船遇雨','楊萬里','宋','宋诗','song-poetry','','[]','破曉開船船正行，忽然頭上片雲生。',64,'全唐诗/poet.song.141000.json','["破曉開船船正行，忽然頭上片雲生。", "秋江得雨茶鼎沸，怒點打篷荷葉鳴。", "遠聽灘喧心欲碎，近看浪戰眼初明。", "夜來暗長前村水，絕喜舟人好語聲。"]'),
('0bd65342-2fe5-4734-bfe2-bd30268697ae','船過硯石步','楊萬里','宋','宋诗','song-poetry','','[]','雨中初厭篛篷遮，撐起篷來景更佳。',64,'全唐诗/poet.song.141000.json','["雨中初厭篛篷遮，撐起篷來景更佳。", "岸上長松立如筆，波中寒影走成蛇。", "忽看雲外吐銀鏡，一點晨光射玉沙。", "却出船頭聊放目，遠峰無數碧橫斜。"]'),
('c3ee77b1-af68-40f0-ac96-900adef8c277','下雞鳴山諸灘望柯山不見三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','地近蓮花江漸深，一灘一過快人心。',32,'全唐诗/poet.song.141000.json','["地近蓮花江漸深，一灘一過快人心。", "貪看下水船如箭，失却柯山無處尋。"]'),
('437c17b6-eb77-4a8b-958d-be9d3b9cc0d8','下雞鳴山諸灘望柯山不見三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','莫怯諸灘水怒號，下灘不似上灘勞。',32,'全唐诗/poet.song.141000.json','["莫怯諸灘水怒號，下灘不似上灘勞。", "長年三老無多巧，穩送驚湍只一篙。"]'),
('473f9347-597a-4fe1-b967-aa0f48c0dc00','下雞鳴山諸灘望柯山不見三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','却憶歸舟是去年，上灘渾似上青天。',32,'全唐诗/poet.song.141000.json','["却憶歸舟是去年，上灘渾似上青天。", "諸灘知我懷餘怨，急送秋風下水船。"]'),
('0b8c40a7-bb46-461d-b62b-d6cc02e1168b','過章戴岸二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山水教無暑，牛羊報有村。',48,'全唐诗/poet.song.141000.json','["山水教無暑，牛羊報有村。", "近沙經雨凈，遠樹入煙昏。", "奔走何時了，升沉未要論。", "江鷗大自在，雪影正孤翻。"]'),
('f560fce4-ad09-4862-95bb-4961bfe5a8c5','過章戴岸二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','港汊村村出，江流節節添。',48,'全唐诗/poet.song.141000.json','["港汊村村出，江流節節添。", "可憐千嶂好，輸與一峰尖。", "過雨日初軟，順風波更恬。", "旋褰篷作屋，更掛簟爲簾。"]'),
('e6a79bae-620f-4bac-a092-39959aa45aea','江水','楊萬里','宋','宋诗','song-poetry','','[]','水色本正白，積深自成綠。',48,'全唐诗/poet.song.141000.json','["水色本正白，積深自成綠。", "江妃將底藥，軟此千里玉。", "詩人酒未醒，快吸一川淥。", "無物嚥清甘，和露嚼野菊。"]'),
('1d5dd567-9c76-4799-b8fe-13dda7cb4b31','晨炊泊楊村','楊萬里','宋','宋诗','song-poetry','','[]','沙步未多遠，里名還異原。',48,'全唐诗/poet.song.141000.json','["沙步未多遠，里名還異原。", "對江穿野店，各路入深村。", "秋水乘新汲，春芽煮不渾。", "舟中爭上岸，竹裏有清樽。"]'),
('25549583-887d-47e7-b307-ee300a4ea528','觀水歎二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','我方卧舟中，仰讀淵明詩。',108,'全唐诗/poet.song.141000.json','["我方卧舟中，仰讀淵明詩。", "忽聞灘聲急，起視惟恐遲。", "八月濺飛雪，清覽良獨奇。", "好風從天來，翛然吹我衣。", "涼生固足樂，氣變亦可悲。", "眷然慨此水，念我年少時。", "迄今四十年，往來九東西。", "此日順流下，何日泝流歸。", "出處未可必，一笑姑置之。"]'),
('895ee8f0-54c6-4a92-a96d-7589860d03d6','觀水歎二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','亂石厄江水，要使水無路。',84,'全唐诗/poet.song.141000.json','["亂石厄江水，要使水無路。", "不知石愈密，激得水彌怒。", "回鋒打別港，勇往遮不住。", "我舟歷諸灘，閲盡水態度。", "一聞一喜觀，屢過屢驚顧。", "不是見不多，觀覽不足故。", "舟人笑我癡，癡黠未易語。"]'),
('d3ec63a2-b8b5-4701-99ec-ac10e6585cf4','九月一日夜宿盈川市','楊萬里','宋','宋诗','song-poetry','','[]','下灘一日抵三程，到得盈川也發更。',64,'全唐诗/poet.song.141000.json','["下灘一日抵三程，到得盈川也發更。", "兩岸漁樵稍燈火，滿江風露更波聲。", "病身只合山間老，半世長懷客裏情。", "西畔大星如玉李，伴人不睡向人明。"]'),
('9158ad68-6505-4eb0-8fb9-3ad067200ecc','舟過柴步寺','楊萬里','宋','宋诗','song-poetry','','[]','野寺隔疎樾，遠舟見深殿。',84,'全唐诗/poet.song.141000.json','["野寺隔疎樾，遠舟見深殿。", "獨逕通絕崖，長縈度微線。", "曩遊携童弱，攀岸已震眩。", "前瞻足未到，下窺意先轉。", "朝來經雲根，塵思起清羨。", "野夫三二輩，走過疾於箭。", "俛仰二十年，今老懷昔健。"]'),
('bc58924f-2cb0-4e96-a6a5-566e89bc35ed','舟過青羊望橫山塔二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','莫問蘭溪雙隻牌，青羊已見玉崔嵬。',32,'全唐诗/poet.song.141000.json','["莫問蘭溪雙隻牌，青羊已見玉崔嵬。", "去年辭了橫山塔，不謂今年却再來。"]'),
('677b9072-73d3-48f5-83fa-865ae02fce61','舟過青羊望橫山塔二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','孤塔分明是故人，一回一見一情親。',32,'全唐诗/poet.song.141000.json','["孤塔分明是故人，一回一見一情親。", "朝來走上山頭望，報道蘭溪酒恰新。"]'),
('7cc274c5-4fe9-4e87-b67b-c5087faf8ccf','過金臺望橫山塔','楊萬里','宋','宋诗','song-poetry','','[]','昨夜愁勤雨，今朝喜嬾風。',48,'全唐诗/poet.song.141000.json','["昨夜愁勤雨，今朝喜嬾風。", "金臺斜岸北，玉塔正船東。", "灘改呈新磧，山回隠暗峰。", "蘭溪水亭子，作意定留儂。"]'),
('6d35c9d1-12b3-4fe9-9dc7-c1b32ce882f9','下橫山灘頭望金華山四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','篙師只管信船流，不作前灘水石謀。',32,'全唐诗/poet.song.141000.json','["篙師只管信船流，不作前灘水石謀。", "却被驚湍漩三轉，倒將船尾作船頭。"]'),
('35e3f169-0b4a-4a93-a10a-5703354e41d1','下橫山灘頭望金華山四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山思江情不負伊，雨姿晴態總成奇。',32,'全唐诗/poet.song.141000.json','["山思江情不負伊，雨姿晴態總成奇。", "閉門覓句非詩法，只是征行自有詩。"]'),
('cad8fe35-f6e9-4826-a922-f67f5ee79ae9','下橫山灘頭望金華山四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','道是蘭溪水較寬，蘭溪欲到怪生難。',32,'全唐诗/poet.song.141000.json','["道是蘭溪水較寬，蘭溪欲到怪生難。", "後船只羨前船快，不覺前船閣在灘。"]'),
('f0de8d4d-5b97-43da-bfe1-f96f964d2f6a','下橫山灘頭望金華山四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','玉立金華霄漢間，帝封天女錫仙山。',32,'全唐诗/poet.song.141000.json','["玉立金華霄漢間，帝封天女錫仙山。", "被他走下嚴灘去，一水窮追竟不還。"]'),
('edf2d659-25ad-4010-a107-c77a81b5a4ea','過橫山塔下','楊萬里','宋','宋诗','song-poetry','','[]','隔岸山迎我，沿江柳拜人。',48,'全唐诗/poet.song.141000.json','["隔岸山迎我，沿江柳拜人。", "日摇秋水面，波閃白龍鱗。", "不遣船迷路，俱從塔問津。", "一生將玉鏡，千古照金身。"]'),
('508f20ab-15b3-4e89-8ba0-1830afd01f2b','出橫山江口','楊萬里','宋','宋诗','song-poetry','','[]','白壁當江岸，青旗定酒家。',48,'全唐诗/poet.song.141000.json','["白壁當江岸，青旗定酒家。", "斷崖侵屋窄，細路入門斜。", "縣近瞻雙塔，洲橫隔一沙。", "何須後來客，如信此詩嘉。"]'),
('ec07dca2-250b-44c2-bb10-c8e63f3784d1','蘭溪雙塔','楊萬里','宋','宋诗','song-poetry','','[]','高塔無尖低塔尖，一披錦衲一銀衫。',32,'全唐诗/poet.song.141000.json','["高塔無尖低塔尖，一披錦衲一銀衫。", "問渠何故終不語，却倩灘聲替佛談。"]'),
('e559b22a-6d64-4f02-a86d-b26e984dc040','宿蘭溪水驛前三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','繫纜蘭溪岸，開襟柳驛窗。',48,'全唐诗/poet.song.141000.json','["繫纜蘭溪岸，開襟柳驛窗。", "人爭趨夜市，月自浴秋江。", "燈火疎還密，帆檣隻更雙。", "平生經此縣，今夕駐孤幢。"]'),
('bc1558c4-1054-4e9f-b43a-23424164302a','宿蘭溪水驛前三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','合眼波吹枕，開篷月入船。',48,'全唐诗/poet.song.141000.json','["合眼波吹枕，開篷月入船。", "奇哉一江水，寫此二更天。", "剩欲酣清賞，翻愁敗醉眠。", "今宵懷昨夕，雨卧萬峰前。"]'),
('9f9e1f47-d30e-4454-bb64-582385f963e9','宿蘭溪水驛前三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','水色秋逾白，山光夜不青。',48,'全唐诗/poet.song.141000.json','["水色秋逾白，山光夜不青。", "一眉畫天月，萬粟種江星。", "小酌居然醉，當風不覺醒。", "誰家教兒子，清誦隔疎櫺。"]'),
('292262ea-d053-4088-839a-6bd39dd1295a','過石塘','楊萬里','宋','宋诗','song-poetry','','[]','萬石中通一線流，千盤百折過孤舟。',32,'全唐诗/poet.song.141000.json','["萬石中通一線流，千盤百折過孤舟。", "灘頭未下人猶笑，下了灘頭始覺愁。"]'),
('9cddb32a-7e3a-4730-98bb-b1ff72313eba','烏祈酒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','入到嚴州不識田，一江兩岸萬青山。',32,'全唐诗/poet.song.141000.json','["入到嚴州不識田，一江兩岸萬青山。", "烏祈酒味君休問，費盡江波賣盡錢。"]'),
('1fffecc2-c7d1-4cc5-8aa9-3ccbe377056f','烏祈酒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','毛永烏祈山兩崖，家家酒肆向江開。',32,'全唐诗/poet.song.141000.json','["毛永烏祈山兩崖，家家酒肆向江開。", "也知第一蒲萄色，只問米從何處來。"]'),
('2c68c74a-55dd-4b6c-a88c-59291b90a7c4','過白沙竹枝歌六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','穹崖絕嶂入雲天，烏鵲纔飛半壁間。',32,'全唐诗/poet.song.141000.json','["穹崖絕嶂入雲天，烏鵲纔飛半壁間。", "遠渚長汀草如積，牛羊須上最高山。"]'),
('8e00dce4-ea23-4b22-999d-113e8c25552a','過白沙竹枝歌六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','田畝渾無寸尺强，真成水國更山鄉。',32,'全唐诗/poet.song.141000.json','["田畝渾無寸尺强，真成水國更山鄉。", "夾江黄去堤堤粟，一望青來谷谷桑。"]'),
('ccfb5621-989f-41dd-a82e-a578aad21396','過白沙竹枝歌六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','絕憐山崦兩三家，不種香秔只種麻。',32,'全唐诗/poet.song.141000.json','["絕憐山崦兩三家，不種香秔只種麻。", "耕徧沿堤鋤徧嶺，都來能得幾生涯。"]'),
('16282a7c-1ec0-4522-b507-5e1481ca4acd','過白沙竹枝歌六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','東沿西泝浙江津，去去來來暮復晨。',32,'全唐诗/poet.song.141000.json','["東沿西泝浙江津，去去來來暮復晨。", "上岸牽檣推穉子，隔船招手認鄉人。"]'),
('5908f705-acee-4e2d-a06b-3b34fb714d30','過白沙竹枝歌六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','昨日下灘風打頭，羨他上水似輕鷗。',32,'全唐诗/poet.song.141000.json','["昨日下灘風打頭，羨他上水似輕鷗。", "朝來上水帆都卸，真箇輕鷗也自愁。"]'),
('6f99fc7b-efdf-4139-a7d4-fa4d8de3b06e','過白沙竹枝歌六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','絕壁臨江千尺餘，上頭一徑過肩輿。',32,'全唐诗/poet.song.141000.json','["絕壁臨江千尺餘，上頭一徑過肩輿。", "舟人仰看膽俱破，爲問行人知得無。"]'),
('48175885-35d9-4f1c-b58e-6f41d513ae0f','過烏石大小二浪灘俗呼浪爲郎因戲作竹枝歌二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','灘聲十里響千鼙，躍雪跳霜入眼奇。',32,'全唐诗/poet.song.141000.json','["灘聲十里響千鼙，躍雪跳霜入眼奇。", "記得年時上灘苦，如今也有下灘時。"]'),
('c6309b52-f9bf-4871-95c3-57106786995e','過烏石大小二浪灘俗呼浪爲郎因戲作竹枝歌二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','小郎灘下大郎灘，伯仲分司水府關。',32,'全唐诗/poet.song.141000.json','["小郎灘下大郎灘，伯仲分司水府關。", "誰爲行媒教作贅，大姑山與小姑山。"]'),
('03e47cd0-85ff-498f-a895-e589815a685a','過嚴州章村放歌','楊萬里','宋','宋诗','song-poetry','','[]','石崖削得瘦到筋，半點也無塵土痕。',96,'全唐诗/poet.song.141000.json','["石崖削得瘦到筋，半點也無塵土痕。", "正如狻猊走得渴，下赴江水一口吞。", "嚴灘過却烏龍觜，兩岸秋山夾秋水。", "舟中小酌亦不遑，眼底生愁失蒼翠。", "尖峰已自刺太虛，峰頭更立玉浮屠。", "好山千隻復萬隻，家裏門前一隻無。"]'),
('089027f0-7247-44d6-97ec-f61f2ff5867a','晚過側溪山下','楊萬里','宋','宋诗','song-poetry','','[]','看山妙處幾曾知，落照斜明始覺奇。',64,'全唐诗/poet.song.141000.json','["看山妙處幾曾知，落照斜明始覺奇。", "皺盡衣裳紋欲裂，爭先頭角遠相追。", "松梢別放六峰出，江底倒將千嶂垂。", "一路詩篇渾漫與，側溪端的不相虧。"]'),
('a7a28c83-5505-4000-96e3-306fc8e9f603','自嘲白鬚三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','强惜數莖鬚，惟愁白却渠。',24,'全唐诗/poet.song.141000.json','["强惜數莖鬚，惟愁白却渠。", "朝來都白盡，愁惜兩何如。"]'),
('ceeb8991-a468-44c1-b587-8a05bbfec8c0','自嘲白鬚三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','客傳涅鬚法，老子付一笑。',24,'全唐诗/poet.song.141000.json','["客傳涅鬚法，老子付一笑。", "借令白再玄，能令年再少。"]'),
('6d8aef82-53ef-4762-b91a-9f1adc76365e','自嘲白鬚三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','涅髭只誑客，那可誑妻兒。',24,'全唐诗/poet.song.141000.json','["涅髭只誑客，那可誑妻兒。", "誑得妻兒著，還能誑面皮。"]'),
('f34c33e5-b8c3-4cf1-921c-4649d49580dd','夜宿東渚放歌三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','前山欺我船兀兀，結約江妃行小譎。',64,'全唐诗/poet.song.141000.json','["前山欺我船兀兀，結約江妃行小譎。", "乘我船摇忽遠逃，見我船定還孤出。", "老夫敢與山爭强，受侮不可更禁當。", "醉立船頭看到夕，不知山於何許藏。"]'),
('a22437f1-d1bf-4be6-b750-5c4234fb68c0','夜宿東渚放歌三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','看山須看山表裏，不然看山還誤事。',64,'全唐诗/poet.song.141000.json','["看山須看山表裏，不然看山還誤事。", "平時只愛萬峰青，落日惟存數尖紫。", "浙江船上多少人，往來看山誰識真。", "丁寧舟人莫浪語，却恐兒輩不肯去。"]'),
('9bb45d2f-d693-4f4a-a58c-85836385c447','夜宿東渚放歌三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','天公要飽詩人眼，生愁秋山太枯淡。',64,'全唐诗/poet.song.141000.json','["天公要飽詩人眼，生愁秋山太枯淡。", "旋裁蜀錦展吳霞，低低抹在秋山半。", "須臾紅錦作翠紗，機頭織出暮歸鴉。", "暮鴉翠紗忽不見，只見澄江浄如練。"]'),
('d15c837e-6226-4d0c-9d95-c8400ca2f383','舟中夜坐','楊萬里','宋','宋诗','song-poetry','','[]','與月隔一簟，去天爭半篷。',24,'全唐诗/poet.song.141000.json','["與月隔一簟，去天爭半篷。", "若無篷與簟，身在大虛中。"]'),
('97da67b7-8a2e-4113-aa4a-89abc53b6a71','富陽曉望','楊萬里','宋','宋诗','song-poetry','','[]','江氛海霧暗前村，四望秋空一白雲。',32,'全唐诗/poet.song.141000.json','["江氛海霧暗前村，四望秋空一白雲。", "忽有數峰雲上出，好山何故總無根。"]'),
('c213e8b0-45f7-46f4-a99f-ebd2fa34e4b3','楊村園戶栽芙蓉爲塹一路凡數萬枝','楊萬里','宋','宋诗','song-poetry','','[]','楊村江上繞江園，十里霜紅爛欲燃。',64,'全唐诗/poet.song.141000.json','["楊村江上繞江園，十里霜紅爛欲燃。", "都種芙蓉作籬落，真將錦繡裹山川。", "晚粧照水密如積，春色入秋寒更鮮。", "客舍瓶中兩三朶，可憐向客强嬋娟。"]'),
('6d238a00-f5bb-4f2f-8d65-715c83f1525e','贈法才師','楊萬里','宋','宋诗','song-poetry','','[]','才公南華別，不見八年許。',48,'全唐诗/poet.song.141000.json','["才公南華別，不見八年許。", "瓣香宗混融，隻眼半唐舉。", "聊將笋蕨觜，戲作冠劍語。", "天還在壺中，雲却歸何處。"]'),
('87b53694-621e-4813-8e7f-7853205dca78','爲崇辨法澐師作林野二大字','楊萬里','宋','宋诗','song-poetry','','[]','天下何人不愛官，棄官出世古今難。',32,'全唐诗/poet.song.141000.json','["天下何人不愛官，棄官出世古今難。", "向來一覺鈞天夢，便作林居野處看。"]'),
('d704ee01-07ae-4749-aa59-ccc1e44e8395','跋徐恭仲省幹近詩三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','仰枕糟丘俯墨池，左提大劍右毛錐。',32,'全唐诗/poet.song.141000.json','["仰枕糟丘俯墨池，左提大劍右毛錐。", "朝蘭夕菊都餐却，更斫生柴爛煮詩。"]'),
('b007577c-252b-47cd-a882-83a839f3f37f','跋徐恭仲省幹近詩三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','君家詩伯老師川，解道蘆花落釣船。',32,'全唐诗/poet.song.141000.json','["君家詩伯老師川，解道蘆花落釣船。", "莫笑東湖秋水冷，近來新吐一枝蓮。"]'),
('33d80698-6549-4ba8-82c2-bf55d236127a','跋徐恭仲省幹近詩三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','傳派傳宗我替羞，作家各自一風流。',32,'全唐诗/poet.song.141000.json','["傳派傳宗我替羞，作家各自一風流。", "黄陳籬下休安脚，陶謝行前更出頭。"]'),
('242fc4d1-f84a-4317-9d87-5470156acb5d','送顔幾聖龍學尚書出守泉州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','聽履星辰北斗寒，三能只隔寸雲間。',64,'全唐诗/poet.song.141000.json','["聽履星辰北斗寒，三能只隔寸雲間。", "周家冢宰均四海，漢制尚書本百官。", "鵷鷺班齊瞻進步，鳳凰池近却飛還。", "河圖冠出西清上，莫作尋常五馬看。"]'),
('d94628f4-7de0-4c4f-b834-dd9534db7254','送顔幾聖龍學尚書出守泉州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','我昔綾衾下直時，公爲璧水大宗師。',64,'全唐诗/poet.song.141000.json','["我昔綾衾下直時，公爲璧水大宗師。", "清風明月行樂耳，布襪青鞋隨所之。", "顛倒壺觴留落日，翻騰山水入新詩。", "我來公去如相避，送眼行塵不得追。"]'),
('a5dc7d36-8781-4714-b065-5d42a96da869','寓仙林寺待班戲題','楊萬里','宋','宋诗','song-poetry','','[]','聽盡鐘魚半月聲，浪傳移住竟何曾。',32,'全唐诗/poet.song.141000.json','["聽盡鐘魚半月聲，浪傳移住竟何曾。", "莫教少欠叢林債，更作今宵旦過僧。"]'),
('4e92da90-9214-4e1e-b665-146d949dea18','送殘秋','楊萬里','宋','宋诗','song-poetry','','[]','夢游帝里送殘秋，重九真爲帝里游。',32,'全唐诗/poet.song.141000.json','["夢游帝里送殘秋，重九真爲帝里游。", "十月初頭方賜對，癡兒枉却一生愁。"]'),
('e3612bcf-e48b-4478-8290-03619f0c109c','自跋江西道院集戲答客問  其一','楊萬里','宋','宋诗','song-poetry','','[]','問我來朝南內南，便從花底趁朝參。',32,'全唐诗/poet.song.141000.json','["問我來朝南內南，便從花底趁朝參。", "新詩猶作江西集，爲带筠州刺史銜。"]'),
('399d629b-e74b-485f-838d-7660e06e2c7c','自跋江西道院集戲答客問  其二','楊萬里','宋','宋诗','song-poetry','','[]','客從南渡向儂來，我馬西征拜此臺。',32,'全唐诗/poet.song.141000.json','["客從南渡向儂來，我馬西征拜此臺。", "若問箇中何所有，一腔熱血和詩裁。"]'),
('ce485b4d-5466-412b-8a5b-ae3f7952c01c','和陸務觀見賀歸館之韻','楊萬里','宋','宋诗','song-poetry','','[]','君詩如精金，入手知價重。',120,'全唐诗/poet.song.141000.json','["君詩如精金，入手知價重。", "鑄作鼎及鼒，所向一一中。", "我如駑並驥，夷塗不應共。", "難追紫蛇電，徒掣青絲鞚。", "折膠偶投漆，異榻豈同夢。", "不知清廟茅，可望明堂棟。", "平生憐坡老，高眼薄蕭統。", "渠若有猗那，心肯師晉宋。", "破琴聊再行，新笛正三弄。", "因君發狂言，湖山春已動。"]'),
('ac3ce409-8342-4a57-a771-5ebe22da0d74','銜命郊勞使客船過崇德縣三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','北關落日送船行，欲到嘉興天已明。',32,'全唐诗/poet.song.141000.json','["北關落日送船行，欲到嘉興天已明。", "睡起一河冰片滿，槌瓊摐玉夢中聲。"]'),
('9a46cd3b-2012-4d65-bab8-25a067abb5dd','銜命郊勞使客船過崇德縣三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水面光浮赤玉盤，也應知我牽夫寒。',32,'全唐诗/poet.song.141000.json','["水面光浮赤玉盤，也應知我牽夫寒。", "滿河圭璧無人要，吹入詩翁凍筆端。"]'),
('7b0fe971-27a7-4a47-9d51-1940472e7cd6','銜命郊勞使客船過崇德縣三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','岸樹低欹一雪餘，枝頭半葉已全無。',32,'全唐诗/poet.song.141000.json','["岸樹低欹一雪餘，枝頭半葉已全無。", "油窗過盡千梢影，濃處還濃枯處枯。"]'),
('4f5e208e-5d44-4d52-8aef-e82cfaea4e87','讀笠澤叢書三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','笠澤詩名千載香，一回一讀斷人腸。',32,'全唐诗/poet.song.141000.json','["笠澤詩名千載香，一回一讀斷人腸。", "晚唐異味同誰賞，近日詩人輕晚唐。"]'),
('f9e8e1c1-8998-468f-9437-64128e28ea14','讀笠澤叢書三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','松江縣尹送圖經，中有唐詩喜不勝。',32,'全唐诗/poet.song.141000.json','["松江縣尹送圖經，中有唐詩喜不勝。", "看到燈青仍火冷，雙眸如割脚如冰。"]'),
('faf9d918-fec5-4d08-a9d1-6a9db7aba078','讀笠澤叢書三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','拈著唐詩廢晚餐，傍人笑我病詩癲。',32,'全唐诗/poet.song.141000.json','["拈著唐詩廢晚餐，傍人笑我病詩癲。", "世間尤物言西子，西子何曾直一錢。"]'),
('12c28e60-6362-40d5-aaa9-4fc5bf77eff0','船過蘇州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','垂近姑蘇特轉灣，盤門只隔柳行間。',32,'全唐诗/poet.song.141000.json','["垂近姑蘇特轉灣，盤門只隔柳行間。", "望來望去何時到，且倚船窗看遠山。"]'),
('95906793-a303-4580-adb7-13f87b068225','船過蘇州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','暮風似箭復如刀，落照那能暖客袍。',32,'全唐诗/poet.song.141000.json','["暮風似箭復如刀，落照那能暖客袍。", "天遠地平城更闊，千尋玉塔尺來高。"]'),
('d6b51055-fa1e-4914-8f66-83edfc5440cc','五更過無錫縣寄懷范參政尤侍郎','楊萬里','宋','宋诗','song-poetry','','[]','蘇州欲見石湖老，到得蘇州發更了。',64,'全唐诗/poet.song.141000.json','["蘇州欲見石湖老，到得蘇州發更了。", "錫山欲見尤梁溪，過却錫山元不知。", "起來靈巖在何許，回首惠山亦無處。", "人生萬事不可期，怏然却向常州去。"]'),
('0bd976a9-c1b5-4ba7-b58b-0d06f29a3db1','午過橫林回望惠山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','道是冰銷快水程，不知青女解藏冰。',32,'全唐诗/poet.song.141000.json','["道是冰銷快水程，不知青女解藏冰。", "蘆花多處竹陰底，砌作瑶堤不計層。"]'),
('23c59715-8388-4847-b4f8-53fe908167ff','午過橫林回望惠山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雪餘官路已生塵，猶喜長河水稍深。',32,'全唐诗/poet.song.141000.json','["雪餘官路已生塵，猶喜長河水稍深。", "恨殺惠山尋不見，忽然追我到橫林。"]'),
('5bec2625-fb2a-4bb9-8151-1d1e098d2007','晚過常州','楊萬里','宋','宋诗','song-poetry','','[]','常州曾作兩年住，一別重來十年許。',64,'全唐诗/poet.song.141000.json','["常州曾作兩年住，一別重來十年許。", "岸頭楊柳記得無，總是行春繫船處。", "自笑恍如丁令威，老懷成喜亦成悲。", "人民城郭依然是，只有向來鬚鬢非。"]'),
('f86590ac-d938-45fe-8f79-afc3a15f332a','望多稼亭','楊萬里','宋','宋诗','song-poetry','','[]','遥望城頭多稼亭，亭邊霜檜老更青。',96,'全唐诗/poet.song.141000.json','["遥望城頭多稼亭，亭邊霜檜老更青。", "當年老守携穉子，芒鞋葵扇繞城行。", "臘前移梅春插柳，蹋雪衝泥不停手。", "柳未成陰梅穉花，著帽又迎新太守。", "後來新守復迎新，到今新舊知幾人。", "向來手植今在否，寄與此詩聊問春。"]'),
('4b772a8a-d2ea-459d-b271-5dd6c8ff2452','晚日二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日影穿波跳碎銀，波光弄日走寒星。',32,'全唐诗/poet.song.141000.json','["日影穿波跳碎銀，波光弄日走寒星。", "一時飛入船窗裏，萬草千花變未停。"]'),
('2b135011-664e-48fa-a84c-5a800097cf7c','晚日二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','貪看波日弄船窗，奇觀人間不作雙。',32,'全唐诗/poet.song.141000.json','["貪看波日弄船窗，奇觀人間不作雙。", "忽被竹陰偷捲去，只餘一面撥醅釭。"]'),
('0c2e7ee6-9384-4e57-8b45-975d51ed3b1f','舟中追和張功父賀赴召之句','楊萬里','宋','宋诗','song-poetry','','[]','兩歲千愁寡一欣，故人多問謝張君。',64,'全唐诗/poet.song.141000.json','["兩歲千愁寡一欣，故人多問謝張君。", "又瞻東闕闕前月，只負南溪溪上雲。", "賓日扶桑遭聖旦，客星釣瀨愧天文。", "人生離合風前葉，聚首亡何復離羣。"]'),
('9472841f-5ffa-41c3-949a-4e51e52f4979','又追和功父病起寄謝之韻','楊萬里','宋','宋诗','song-poetry','','[]','霜何曾傍繡簾寒，酒不能令客臉丹。',64,'全唐诗/poet.song.141000.json','["霜何曾傍繡簾寒，酒不能令客臉丹。", "勤向竹爐溫手脚，嬾尋銅鏡正衣冠。", "無人孤坐月將落，擁鼻清吟夜向闌。", "忽憶約齋詩債在，自吹燈火起來看。"]'),
('3f3f5bb9-9679-4030-bbe7-5ca6b222430d','曉過丹陽縣五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','朝來稍敢出船門，霜熟依然冷逼人。',32,'全唐诗/poet.song.141000.json','["朝來稍敢出船門，霜熟依然冷逼人。", "刮地風來何處避，可憐岸篠猛回身。"]'),
('eda09489-948a-43e6-95b7-d3898ee168b6','曉過丹陽縣五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','風從船裏出船前，漲起簾幃紫拂天。',32,'全唐诗/poet.song.141000.json','["風從船裏出船前，漲起簾幃紫拂天。", "點檢風來無處覓，破窗一隙小於錢。"]'),
('8a34553e-cfa9-4305-98b7-8a4f259a4fd1','曉過丹陽縣五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','朱簷碧瓦照青瀾，潔館佳亭使往還。',32,'全唐诗/poet.song.141000.json','["朱簷碧瓦照青瀾，潔館佳亭使往還。", "船上高橋三十尺，市人倚折石欄干。"]'),
('ae686a80-7638-4d9b-a733-fc66fafad6c5','曉過丹陽縣五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','雞犬漁翁共一船，生涯都在篛篷間。',32,'全唐诗/poet.song.141000.json','["雞犬漁翁共一船，生涯都在篛篷間。", "小兒不耐初長日，自織筠籃勝打閑。"]'),
('7929a535-e42e-4165-aa19-a398bf62d092','曉過丹陽縣五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','水從常潤路都迷，曲曲長河曲曲堤。',32,'全唐诗/poet.song.141000.json','["水從常潤路都迷，曲曲長河曲曲堤。", "不是兩窗供日脚，更無南北與東西。"]'),
('10759601-b479-48eb-af13-665c08521ed1','練湖放閘二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','滿耳雷聲動地來，窺窗銀浪打船開。',32,'全唐诗/poet.song.141000.json','["滿耳雷聲動地來，窺窗銀浪打船開。", "練湖纔放一寸水，跳作冰河萬雪堆。"]'),
('465433cc-1dbb-48a5-b5d3-aeb16d59e389','練湖放閘二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水簟南舒去轉虛，天簷北卸望來無。',32,'全唐诗/poet.song.141000.json','["水簟南舒去轉虛，天簷北卸望來無。", "相傳一萬四千頃，老眼初驚見練湖。"]'),
('32b4a319-6ed3-449b-aed0-b4933241691c','過張王廟','楊萬里','宋','宋诗','song-poetry','','[]','地迥人煙寂，山盤水勢回。',48,'全唐诗/poet.song.141000.json','["地迥人煙寂，山盤水勢回。", "怪松欹岸出，古廟背河開。", "晚色催征棹，斜陽戀去桅。", "丹徒誰道遠，一眺正悠哉。"]'),
('7ac1314d-f77b-45b0-bfa3-ca06c39869a0','舟中晚望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','河岸前頭松樹林，樹林盡處見行人。',32,'全唐诗/poet.song.141000.json','["河岸前頭松樹林，樹林盡處見行人。", "行人又被山遮斷，風颭酒家青布巾。"]'),
('45384add-92fa-48cd-a36f-1f114ba33e61','舟中晚望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','晚浪翻風玉作鱗，夕陽捲玉藥成金。',32,'全唐诗/poet.song.141000.json','["晚浪翻風玉作鱗，夕陽捲玉藥成金。", "忽然濯出西川錦，製就霞衣不用針。"]'),
('078514d6-f38f-4739-b406-e828671ff391','晚風二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','晚日暄溫稍霽威，晚風豪橫大相欺。',32,'全唐诗/poet.song.141000.json','["晚日暄溫稍霽威，晚風豪橫大相欺。", "做寒做冷何須怒，來早一霜誰不知。"]'),
('268f271c-642a-4fc2-a30c-c108cc5c2975','晚風二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','晚風不許鑑清漪，却許重簾到地垂。',32,'全唐诗/poet.song.141000.json','["晚風不許鑑清漪，却許重簾到地垂。", "平野無山遮落日，西窗紅到月來時。"]'),
('f6193eac-00e1-418b-8a0e-9fb9ccbf47bf','未到丹徒二十里間見石翁石婆','楊萬里','宋','宋诗','song-poetry','','[]','詔許詩人江海游，丹徒初到晉徐州。',64,'全唐诗/poet.song.141000.json','["詔許詩人江海游，丹徒初到晉徐州。", "爐邊暘谷日長晝，盞底醉鄉天不秋。", "六代興亡何處問，一生奔走幾時休。", "石翁石媼霜前笑，管得南朝陵墓愁。"]'),
('fa313a68-efc1-4eac-b681-7f4589be5267','暮經新豐市望遠山','楊萬里','宋','宋诗','song-poetry','','[]','小市寒仍靜，斜陽澹欲晡。',48,'全唐诗/poet.song.141000.json','["小市寒仍靜，斜陽澹欲晡。", "偶看平野去，不是遠山無。", "處處遮船住，家家有酒酤。", "朱樓臨碧水，曾駐玉鑾輿。"]'),
('b3e8863e-f6d8-48f4-bda2-6155a4184786','小泊新豐市','楊萬里','宋','宋诗','song-poetry','','[]','也知小倦泊樓船，何苦爭先柳岸邊。',32,'全唐诗/poet.song.141000.json','["也知小倦泊樓船，何苦爭先柳岸邊。", "須把碧篙摇綠浄，舟人不惜水中天。"]'),
('3dafed0b-b396-4bc0-a03f-e8270e37dbba','曉泊丹陽館','楊萬里','宋','宋诗','song-poetry','','[]','夕凍朝還積，寒曦暖未多。',48,'全唐诗/poet.song.141000.json','["夕凍朝還積，寒曦暖未多。", "霜輕猶著草，冰重亦浮河。", "山盡酣餘勢，潮歸殿去波。", "六朝遺迹在，故老尚傳麽。"]'),
('dd669c13-b301-4e8d-96c1-69075556b410','題連滄觀呈太守張幾仲','楊萬里','宋','宋诗','song-poetry','','[]','開窗納盡大江秋，天半飛樓不是樓。',64,'全唐诗/poet.song.141000.json','["開窗納盡大江秋，天半飛樓不是樓。", "獨立南徐鼇絕頂，下臨北固虎回頭。", "蒜山舊址空黄鶴，瓜步新城照白鷗。", "好事主人酌詩客，風煙一眼到揚州。"]'),
('82be33e3-f3ca-445d-9b0c-a3a867cc858f','丹陽舍舟登車渡江','楊萬里','宋','宋诗','song-poetry','','[]','小泊樓船鐵甕城，匆匆又作絕江行。',64,'全唐诗/poet.song.141000.json','["小泊樓船鐵甕城，匆匆又作絕江行。", "看他蠟燭幾回剪，聽盡雞聲不肯明。", "水底霜寒還十倍，夜來月上恰三更。", "篙師好語君知否，江面侵晨鏡樣平。"]'),
('96f11b73-15bc-4de5-8980-15dea03860f7','過楊子江二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','祇有清霜凍太空，更無半點荻花風。',64,'全唐诗/poet.song.141000.json','["祇有清霜凍太空，更無半點荻花風。", "天開雲霧東南碧，日射波濤上下紅。", "千載英雄鴻去外，六朝形勝雪晴中。", "携瓶自汲江心水，要試煎茶第一功。"]'),
('5bbc55dd-2155-4b2c-9f25-99329474bec1','過楊子江二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','天將天塹護吳天，不數殽函百二關。',64,'全唐诗/poet.song.141000.json','["天將天塹護吳天，不數殽函百二關。", "萬里銀河瀉瓊海，一雙玉塔表金山。", "旌旗隔岸淮南近，鼓角吹霜塞北閑。", "多謝江神風色好，滄波千頃片時間。"]'),
('0bb531c3-9013-4e11-97d8-6ed7a08c3769','過瓜洲鎮','楊萬里','宋','宋诗','song-poetry','','[]','夜愁風浪不成眠，曉渡清平却晏然。',64,'全唐诗/poet.song.141000.json','["夜愁風浪不成眠，曉渡清平却晏然。", "數棒金鉦到江步，一檣霜日上淮船。", "佛狸馬死無遺骨，阿亮臺傾只野田。", "南北休兵三十載，桑疇麥壠正連天。"]'),
('3b6f85d7-b8a6-4e6c-a8e5-7e7a964fe8cc','皂角林','楊萬里','宋','宋诗','song-poetry','','[]','水漾霜風冷客襟，苔封戰骨動人心。',32,'全唐诗/poet.song.141000.json','["水漾霜風冷客襟，苔封戰骨動人心。", "河邊獨樹知何木，今古相傳皂角林。"]'),
('d20bc876-5e34-44d9-9a95-3a8b59c13958','舟過楊子橋遠望','楊萬里','宋','宋诗','song-poetry','','[]','此日淮堧號北邊，舊時南服紀淮堧。',64,'全唐诗/poet.song.141000.json','["此日淮堧號北邊，舊時南服紀淮堧。", "平蕪盡處渾無壁，遠樹梢頭便是天。", "今古戰場誰勝負，華夷險要豈山川。", "六朝未可輕嘲謗，王謝諸賢不偶然。"]'),
('90aa09c4-becb-4309-9f90-5bf609cce083','晚泊楊州','楊萬里','宋','宋诗','song-poetry','','[]','楊子橋西轉綵航，粉城如練是維楊。',64,'全唐诗/poet.song.141000.json','["楊子橋西轉綵航，粉城如練是維楊。", "百年舊觀兵戈後，近歲新開草木荒。", "傑閣高臺雲上出，野梅官柳雪中香。", "史君領客週遭看，走馬歸船欲夕陽。"]'),
('6a376d62-6fe8-44fc-b1a9-312a7414613a','過高郵','楊萬里','宋','宋诗','song-poetry','','[]','解纜維楊欲夕陽，過舟覆盎已晨光。',64,'全唐诗/poet.song.141000.json','["解纜維楊欲夕陽，過舟覆盎已晨光。", "夾河漁屋都編荻，背日船篷尚滿霜。", "城外城中四通水，堤南堤北萬垂楊。", "一州斗大君休笑，國士秦郎此故鄉。"]'),
('760a3aff-3d0a-438b-8891-c5f88a6589ee','過甓社諸湖進退格東西長七十里南北闊五十里','楊萬里','宋','宋诗','song-poetry','','[]','爲愛淮中掌似平，忽逢巨浸却心驚。',64,'全唐诗/poet.song.141000.json','["爲愛淮中掌似平，忽逢巨浸却心驚。", "怪來萬頃不生浪，凍合五湖都是冰。", "碧玉湖寬容我到，白銀地滑沒人行。", "茲游只道清無價，清殺詩翁老不勝。"]'),
('16947ab1-ffc6-40d0-acc4-31c2be5b207a','湖天暮景五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','湖面黏天不見堤，湖心茭葑水周圍。',32,'全唐诗/poet.song.141000.json','["湖面黏天不見堤，湖心茭葑水周圍。", "暮鴻成陣鴉成隊，已落還飛久未棲。"]'),
('d1956209-9d41-484c-b4fa-fa2f5afb3562','湖天暮景五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','坐看西日落湖濱，不是山銜不是雲。',32,'全唐诗/poet.song.141000.json','["坐看西日落湖濱，不是山銜不是雲。", "寸寸低來忽全沒，分明入水只無痕。"]'),
('30ea1dcc-2584-4d0d-8711-6a3194a78ef4','湖天暮景五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','抵暮漁郎初上船，一竿摇入水精天。',32,'全唐诗/poet.song.141000.json','["抵暮漁郎初上船，一竿摇入水精天。", "忍寒不睡妨底事，來早賣魚充酒錢。"]'),
('a978b2af-0c56-48de-9905-12ec831f8208','湖天暮景五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','琱碎肝脾只坐詩，鬚髯成雪鬢成絲。',32,'全唐诗/poet.song.141000.json','["琱碎肝脾只坐詩，鬚髯成雪鬢成絲。", "暮雲薄倖斜陽劣，合造清愁付阿誰。"]'),
('db10090e-a464-490f-81e5-3c006aebe840','湖天暮景五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','斷腸浪說賀方回，未抵秦郎翦水才。',32,'全唐诗/poet.song.141000.json','["斷腸浪說賀方回，未抵秦郎翦水才。", "欲向湖邊問遺唱，鴛鴦鸚鵡兩相推。"]'),
('750e9dd4-62ca-41e3-8179-9651679182b5','曉霜過寶應縣三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','江南霜重莫嫌渠，草上還多樹上無。',32,'全唐诗/poet.song.141000.json','["江南霜重莫嫌渠，草上還多樹上無。", "淮甸曉來霜似雪，瓊田千里玉平鋪。"]'),
('a57bcc37-0e23-41a7-bc51-fb38e2732971','曉霜過寶應縣三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','看來不信是霜華，白日青天散曉霞。',32,'全唐诗/poet.song.141000.json','["看來不信是霜華，白日青天散曉霞。", "只怪野田生玉樹，更於臘月發瓊花。"]'),
('ca01a20f-6931-4da9-ad4f-c852663f991a','曉霜過寶應縣三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','落木枯林一夜蘇，枝枝節節糝瓊酥。',32,'全唐诗/poet.song.141000.json','["落木枯林一夜蘇，枝枝節節糝瓊酥。", "看來忘却臘前景，一色李花三月初。"]'),
('24e023d7-90d1-4860-a767-9c0b7b6f1b06','登楚州城','楊萬里','宋','宋诗','song-poetry','','[]','望中白處日爭明，箇是淮河凍作冰。',32,'全唐诗/poet.song.141000.json','["望中白處日爭明，箇是淮河凍作冰。", "此去中原三里許，一條玉带界天橫。"]'),
('8252d371-51cd-4a5f-98da-aaec60206b51','初食淮白','楊萬里','宋','宋诗','song-poetry','','[]','淮白須將淮水煮，江南水煮正相違。',64,'全唐诗/poet.song.141000.json','["淮白須將淮水煮，江南水煮正相違。", "霜吹柳葉落都盡，魚喫雪花方解肥。", "醉卧糟丘名不惡，下來鹽豉味全非。", "饔人且莫供羊酪，更買銀刀二尺圍。"]'),
('7778c34f-d2da-400c-8f1c-3483a96b886a','清曉洪澤放閘四絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','起來霜重滿淮船，更覺今朝分外寒。',32,'全唐诗/poet.song.141000.json','["起來霜重滿淮船，更覺今朝分外寒。", "放閘老兵殊耐冷，一絲不挂下冰灘。"]'),
('8fb3eb91-a340-41a6-bdff-ed1b7cd041e4','清曉洪澤放閘四絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','滿閘浮河是斷冰，等人放閘要前行。',32,'全唐诗/poet.song.141000.json','["滿閘浮河是斷冰，等人放閘要前行。", "劣能開得兩三板，爭作摧瓊裂玉聲。"]'),
('c91e3792-9225-4b0c-a41b-cb875302537f','清曉洪澤放閘四絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','遮藏水面被殘冰，流盡殘冰水正明。',32,'全唐诗/poet.song.141000.json','["遮藏水面被殘冰，流盡殘冰水正明。", "幸自奔流總驩喜，落洪須做不平聲。"]'),
('7792ba34-6b06-4924-9f64-919c23d97319','清曉洪澤放閘四絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','沿河過閘夢中聞，奇觀何曾似此晨。',32,'全唐诗/poet.song.141000.json','["沿河過閘夢中聞，奇觀何曾似此晨。", "雪濺雷奔乍明眼，天跳地趠也驚人。"]'),
('33de1da4-5179-45f8-a7c2-2665728213a7','初入淮河四絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','船離洪澤岸頭沙，入到淮河意不佳。',32,'全唐诗/poet.song.141000.json','["船離洪澤岸頭沙，入到淮河意不佳。", "何必桑乾方是遠，中流以北即天涯。"]'),
('28b168a3-ea82-4b67-9273-a0329965f1bd','初入淮河四絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','劉岳張韓宣國威，趙張二相築皇基。',32,'全唐诗/poet.song.141000.json','["劉岳張韓宣國威，趙張二相築皇基。", "長淮咫尺分南北，淚濕秋風欲怨誰。"]'),
('cdb1a650-2509-42db-bd5b-6643d0ba0445','初入淮河四絕句  其三','楊萬里','宋','宋诗','song-poetry','','["\u63cf\u5199\u6c34", "\u7231\u56fd", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6292\u60c5", "\u5b8b\u8bd7", "\u5199\u9e1f"]','兩岸舟船各背馳，波痕交涉亦難爲。',32,'全唐诗/poet.song.141000.json','["兩岸舟船各背馳，波痕交涉亦難爲。", "只餘鷗鷺無拘管，北去南來自在飛。"]'),
('e5134de0-caab-4d42-83e7-112da3e6f8e9','初入淮河四絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','中原父老莫空談，逢著王人訴不堪。',32,'全唐诗/poet.song.141000.json','["中原父老莫空談，逢著王人訴不堪。", "却是歸鴻不能語，一年一度到江南。"]'),
('f458dfbf-8a72-456a-bc2a-4c522a21742e','題盱眙軍東南第一山  其一','楊萬里','宋','宋诗','song-poetry','','[]','第一山頭第一亭，聞名未到負平生。',64,'全唐诗/poet.song.141000.json','["第一山頭第一亭，聞名未到負平生。", "不因王事略小出，那得高人同此行。", "萬里中原青未了，半篙淮水碧無情。", "登臨不覺風煙暮，腸斷漁燈隔岸明。"]'),
('5d134a50-3c25-4769-a93e-489ec7828496','題盱眙軍東南第一山  其二','楊萬里','宋','宋诗','song-poetry','','[]','建隆家業大於天，慶曆春風一萬年。',64,'全唐诗/poet.song.141000.json','["建隆家業大於天，慶曆春風一萬年。", "廊廟謀謨出童蔡，笑談京洛博幽燕。", "白溝舊在鴻溝外，易水今移淮水前。", "川后年來世情了，一波分護兩涯船。"]'),
('2eb8a482-9c14-4bec-9ab3-d8910dca089d','題盱眙軍玻瓈泉','楊萬里','宋','宋诗','song-poetry','','[]','清如淮水未爲佳，泉迸淮山好煮茶。',64,'全唐诗/poet.song.141000.json','["清如淮水未爲佳，泉迸淮山好煮茶。", "鎔出玻瓈開海眼，更和月露瀹春芽。", "仰看絕壁一千丈，削下青瓊無點瑕。", "從事不澆愁肺渴，臨泓带雪吸冰花。"]'),
('74e580cd-a343-4dbe-b616-4d4e7cdc2e29','盱眙軍東山飛步亭和太守霍和卿韻','楊萬里','宋','宋诗','song-poetry','','[]','杏花巖左斸東巖，驅使淮山指顧間。',64,'全唐诗/poet.song.141000.json','["杏花巖左斸東巖，驅使淮山指顧間。", "招信上流總奔赴，僧伽孤塔政彎環。", "今來古往空陳跡，遠草斜陽祇慘顔。", "走馬看山真懡㦬，忙中拾得片時閒。"]'),
('591b9231-d4dd-49eb-9832-95ddf8a08677','初食太原生蒲萄時十二月二日','楊萬里','宋','宋诗','song-poetry','','[]','淮南蒲萄八月酸，只可生喫不可乾。',131,'全唐诗/poet.song.141000.json','["淮南蒲萄八月酸，只可生喫不可乾。", "淮北蒲萄十月熟，縱可作羓也無肉。", "老夫臘裏來都梁，飣坐那得馬乳香。", "分明猶带龍鬚在，徑寸玄珠肥十倍。", "太原青霜熬絳餳，甘露凍作紫水精。", "隆冬壓架無人摘，雪打冰封不曾拆。", "風吹日炙不曾腊，玉盤一朶直萬錢。", "與渠傾蓋真忘年，君不見道逢麴車口流涎。"]'),
('46fd86c3-9802-4ac9-872d-0172bb446f5e','檃括東坡瓶笙詩序','楊萬里','宋','宋诗','song-poetry','','[]','餞飲東坡月三更，中觴忽聞笙簫聲。',72,'全唐诗/poet.song.141000.json','["餞飲東坡月三更，中觴忽聞笙簫聲。", "杳杳若在雲霄間，抑揚往返中八音。", "徐而察之出雙瓶，水火相得自嘯吟。", "食頃乃已不可尋，坐客驚歎得未曾。", "八月四七歲庚辰。"]'),
('cac000ad-6c3e-488a-ba1c-697d3411067b','與長孺共讀東坡詩前用唐律後用進退格  其一','楊萬里','宋','宋诗','song-poetry','','[]','急性平生不少徐，讀書不喜喜觀書。',64,'全唐诗/poet.song.141000.json','["急性平生不少徐，讀書不喜喜觀書。", "十行俱下未心醒，兩目頓昏還月餘。", "偶與兒曹繙故紙，共看詩句煮春蔬。", "問來却是東坡集，久別相逢味勝初。"]'),
('a96ab50b-cf3d-4df9-b821-bbf246dc8a62','與長孺共讀東坡詩前用唐律後用進退格  其二','楊萬里','宋','宋诗','song-poetry','','[]','枉看平生多少書，分明便是蠹書魚。',64,'全唐诗/poet.song.141000.json','["枉看平生多少書，分明便是蠹書魚。", "萬籤過眼還休去，一字經心恰似無。", "急讀何如徐讀妙，共看更勝獨看渠。", "麴生冷笑仍相勸，惜取殘零覓句鬚。"]'),
('1fadd46e-fc85-4b7b-8f1f-914614e2d087','嘲淮風進退格','楊萬里','宋','宋诗','song-poetry','','[]','絮帽貂裘莫出船，北窗最緊且深關。',64,'全唐诗/poet.song.141000.json','["絮帽貂裘莫出船，北窗最緊且深關。", "顛風無頼知何故，做雪不成空自寒。", "不去掃清天北霧，只來捲起浪頭山。", "便能吹倒僧伽塔，未直先生一笑看。"]'),
('f2d5dd33-5d55-4d4a-a65d-9e71d9e64452','嘲淮浪','楊萬里','宋','宋诗','song-poetry','','[]','碧瑠璃地展青羅，橫作一波仍萬波。',64,'全唐诗/poet.song.141000.json','["碧瑠璃地展青羅，橫作一波仍萬波。", "突起銀山倚空立，碎成雪陣掠人過。", "爭先打岸終誰勝，淘盡浮沙奈汝何。", "借與樓船泄餘怒，摇來兀去儘從佗。"]'),
('a2b04c50-a0bd-43ec-a8e9-13aa2029106d','舟中不寐','楊萬里','宋','宋诗','song-poetry','','[]','醉去昏然卧綠窗，醒來一枕好淒涼。',64,'全唐诗/poet.song.141000.json','["醉去昏然卧綠窗，醒來一枕好淒涼。", "意中爲許無佳況，夢裏分明到故鄉。", "淮水打船千浪雪，燕鴻叫月滿天霜。", "山城更點元無準，偏到雞鳴分外長。"]'),
('0c3a19af-20a5-46bf-840a-6d0f070d8670','檃括東坡觀棋詩引并四言詩二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','老坡獨往到廬山，白鶴觀中俱晝眠。',32,'全唐诗/poet.song.141000.json','["老坡獨往到廬山，白鶴觀中俱晝眠。", "只有棋聲人不見，寂然流水古松間。"]'),
('f7cf7428-961b-4d35-a8e8-9db2b6779184','檃括東坡觀棋詩引并四言詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','五老峰前松蔭庭，風光清美日華明。',32,'全唐诗/poet.song.141000.json','["五老峰前松蔭庭，風光清美日華明。", "獨游略不逢一士，時有紋枰落子聲。"]'),
('6232b413-233d-46fd-bef6-ca931519c55a','雨作抵暮復晴五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','棲鵲無陰庇濕衣，行人仄傘避斜絲。',32,'全唐诗/poet.song.141000.json','["棲鵲無陰庇濕衣，行人仄傘避斜絲。", "船兵歸後轎兵去，獨立淮河暮雨時。"]'),
('31d564e3-43f8-48d7-8331-2ed9a61b4e65','雨作抵暮復晴五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','細雨如塵復似煙，兩淮渡口各收船。',32,'全唐诗/poet.song.141000.json','["細雨如塵復似煙，兩淮渡口各收船。", "南商北賈俱星散，古廟無人燒紙錢。"]'),
('6472a42a-74e9-464e-87ad-7ee52eddfd5b','雨作抵暮復晴五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雨痕拂水有如無，雨點飛空密復疎。',32,'全唐诗/poet.song.141000.json','["雨痕拂水有如無，雨點飛空密復疎。", "白鷺窺魚渾欲下，被風吹起不由渠。"]'),
('67933601-bc6c-4329-9257-b4d5caac6769','雨作抵暮復晴五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','清平如席是淮流，風起雷奔怒不休。',32,'全唐诗/poet.song.141000.json','["清平如席是淮流，風起雷奔怒不休。", "一浪飛來驚落膽，早知祇要打船頭。"]'),
('a73ff24d-5c32-4ab8-ab9a-464ce3b86211','雨作抵暮復晴五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','風伯顛狂太劣生，雨師嬾困灑來輕。',32,'全唐诗/poet.song.141000.json','["風伯顛狂太劣生，雨師嬾困灑來輕。", "若言不被雲君誤，誰放斜陽作晚晴。"]'),
('c608a646-d00b-4873-a7fb-f49cde9d71e8','盱眙軍無梅郡圃止有蠟梅兩株二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','只道橫枝春未回，又疑不肯犯寒開。',32,'全唐诗/poet.song.141000.json','["只道橫枝春未回，又疑不肯犯寒開。", "逢人問訊花消息，不識江梅只蠟梅。"]'),
('91e35a4b-df09-45c6-b175-168e76decbc2','盱眙軍無梅郡圃止有蠟梅兩株二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','臘裏花開已是遲，西湖十月見瓊肌。',32,'全唐诗/poet.song.141000.json','["臘裏花開已是遲，西湖十月見瓊肌。", "嶺頭猶說南枝暖，却向淮南覓北枝。"]'),
('9365400f-1fbe-4c7c-be4a-756ed2545100','前苦寒歌','楊萬里','宋','宋诗','song-poetry','','[]','四大海潮打清淮，三萬里風平地來。',80,'全唐诗/poet.song.141000.json','["四大海潮打清淮，三萬里風平地來。", "龜山橫身攔不住，潮波怒飛風倒回。", "欲晴不晴雪不雪，併作苦寒凍人絕。", "古寺大鐘十字裂，東山石崖一峰蹶。", "勸君莫出君須出，冰脫君髯折君骨。"]'),
('d4d8f2f4-1165-404a-b20b-8f54f946f7f3','淮河舟中曉起看雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','三日顛風刮地來，不成一雪肯空回。',64,'全唐诗/poet.song.141000.json','["三日顛風刮地來，不成一雪肯空回。", "何曾半點漏春信，只怪千花連夜開。", "頃刻裝嚴銀世界，中間徧滿玉樓臺。", "瓊船撐入玻瓈國，琪樹瑶林不用栽。"]'),
('0952a472-7ac5-4591-93f6-80c9673ae295','淮河舟中曉起看雪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅花腦子撒成雲，明月珠胎屑作塵。',64,'全唐诗/poet.song.141000.json','["梅花腦子撒成雲，明月珠胎屑作塵。", "愛水舞來飛就影，怯風斜去却回身。", "真成一臘逢三白，併把三冬博一春。", "開放船窗儘渠入，天差滕六訪詩人。"]'),
('41ae6726-c406-4a42-9109-31a80dc38ee7','舟中雪作和沈虞卿寄雪詩韻','楊萬里','宋','宋诗','song-poetry','','[]','霜風吹船著淮陰，淮山高高淮水深。',64,'全唐诗/poet.song.141000.json','["霜風吹船著淮陰，淮山高高淮水深。", "津亭飲散浪如屋，篷窗曉起雪滿林。", "兩袖拂空捎舞片，數點落几撩孤吟。", "卷舒東陽琢冰句，不羨銷金歌淺斟。"]'),
('2498b043-39e2-4bcd-8fdd-ee0f70406072','暖熱兩生行','楊萬里','宋','宋诗','song-poetry','','[]','秃穎凍得鬚作冰，老泓飲湯成水精。',88,'全唐诗/poet.song.141000.json','["秃穎凍得鬚作冰，老泓飲湯成水精。", "先生定交兩書生，兩生號寒語不能。", "先生自作饑蟲鳴，夜檄祝融戰玄冥。", "更遣紅玉十麒麟，相與部領有脚春，暖熱兩生出精神。", "兩生炙手淚縱橫，彊和先生仄仄平。"]'),
('840bffed-50c8-49a8-a060-b6ccc0a68259','淮河再雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','風打波頭波打船，併來枕底攪清眠。',32,'全唐诗/poet.song.141000.json','["風打波頭波打船，併來枕底攪清眠。", "先生夜起篷窗看，月滿長淮雪滿天。"]'),
('05e994d8-8cc8-4cca-b50f-a6c105f2cd7f','淮河再雪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','昨晡日脚盪波紅，今早天花舞鏡中。',32,'全唐诗/poet.song.141000.json','["昨晡日脚盪波紅，今早天花舞鏡中。", "雪了又晴晴又雪，海神渾不惜神通。"]'),
('39ecfef8-7b18-4137-bae1-70993abf04d3','淮河中流肅使客','楊萬里','宋','宋诗','song-poetry','','[]','淮水中流各一波，南船小住北船過。',32,'全唐诗/poet.song.141000.json','["淮水中流各一波，南船小住北船過。", "生憎兩岸旌旗脚，引得霜風分外多。"]'),
('ea7a1adf-7e97-4e51-9bfe-b1c08ce27524','歸舟大雪中入運河過萬家湖','楊萬里','宋','宋诗','song-poetry','','[]','雪漫水面淡模糊，釀出羔兒酒一壺。',64,'全唐诗/poet.song.141000.json','["雪漫水面淡模糊，釀出羔兒酒一壺。", "已被羶腴翳醽醁，更添牛乳點春酥。", "銷金帳下有此否，藥玉船中不用酤。", "忽見瓊缸清徹底，蒲萄一色萬家湖。"]'),
('98435144-4b45-404a-9d82-1f1cb3d5a1a5','過淮陰縣題韓信廟前用唐律後用進退格  其一','楊萬里','宋','宋诗','song-poetry','','[]','來時月黑過淮陰，歸路天花舞故城。',64,'全唐诗/poet.song.141000.json','["來時月黑過淮陰，歸路天花舞故城。", "一劍光寒千古淚，三家市出萬人英。", "少年跨下安無忤，老父圯邊愕不平。", "人物若非觀歲暮，淮陰何必減宣成。"]'),
('bab484d1-ea5f-4cc6-9527-6ed3225420c7','過淮陰縣題韓信廟前用唐律後用進退格  其二','楊萬里','宋','宋诗','song-poetry','','[]','鴻溝祗道萬夫雄，雲夢何銷武士功。',64,'全唐诗/poet.song.141000.json','["鴻溝祗道萬夫雄，雲夢何銷武士功。", "九死不分天下鼎，一生還負室前鐘。", "古來犬斃愁無蓋，此後禽空悔作弓。", "兵火荒餘非舊廟，三間破屋兩株松。"]'),
('63828f95-5548-407a-8291-a499a30c6a3d','後苦寒歌','楊萬里','宋','宋诗','song-poetry','','[]','白鷗立雪脛透冷，鸕鷀避風飛不正。',96,'全唐诗/poet.song.141000.json','["白鷗立雪脛透冷，鸕鷀避風飛不正。", "一雙野鴨欺晚寒，出沒冰河底心性。", "絕憐紅船黄帽郎，綠蓑青篛牽牙檣。", "生愁墮指脫兩耳，蘆花亦無何許藏。", "遣騎前頭買乾荻，速烘燄火與一炙。", "三足老鴉寒不出，看雲訴天天不泣。"]'),
('dface4f2-f313-4190-859a-6a4b2e74d379','晚寒熾炭','楊萬里','宋','宋诗','song-poetry','','[]','老子平生不附炎，雪間爐炭晚間添。',64,'全唐诗/poet.song.141000.json','["老子平生不附炎，雪間爐炭晚間添。", "紅光亂拆銀花碎，翠燄雙抽柳葉尖。", "愛惜麒麟牢禁手，驅除鹽絮密垂簾。", "急分一炬牽船底，岸上霜風正似鎌。"]'),
('3b1df86e-bfde-40ef-a6eb-50d4ea216fc3','雪小霽順風過謝陽湖','楊萬里','宋','宋诗','song-poetry','','[]','都梁三日雪沒屋，小船行水如行陸。',128,'全唐诗/poet.song.141000.json','["都梁三日雪沒屋，小船行水如行陸。", "山陽一朝帆遇風，大船行水如行空。", "昨來牽夫凍得泣，買蘆燎衣蘆自濕。", "朝來牽夫皆上船，收纜脫巾篷底眠。", "樓船忽然生兩翼，橫飛直過陽侯國。", "千村一抹片子時，四岸人家眼中失。", "似聞咫尺是楊州，更數寶應兼高郵。", "青天萬里當徑度，不堪回首都梁路。"]'),
('d2eb09c5-d865-48fd-9d6e-212627c26335','夜過高郵','楊萬里','宋','宋诗','song-poetry','','[]','水鳥舟人兩不棲，波聲風響總堪悲。',64,'全唐诗/poet.song.141000.json','["水鳥舟人兩不棲，波聲風響總堪悲。", "覺來枕上三更後，夢到江南一霎時。", "邵伯問來還漸近，高郵過了不曾知。", "滿天星月銀河濕，明早新晴也大奇。"]'),
('e65c5e68-2e45-4b5d-b1c7-51c2697248a7','雪曉舟中生火二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','烏銀見火生綠霧，便當水沉一濃炷。',96,'全唐诗/poet.song.141000.json','["烏銀見火生綠霧，便當水沉一濃炷。", "却因斷續更氤氳，散作霏微暖袍袴。", "須臾霧霽吐紅光，炯如雲表昇扶桑。", "陽春和日曛滿室，蒼顔渥丹疑醉鄉。", "忽然火冷霧亦滅，只見紅爐堆白雪。", "窗外雪深三尺强，窗裏雪深一寸香。"]'),
('c7af57f1-f4a4-4374-a5c3-07874fce172e','雪曉舟中生火二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','烏銀玉質金石聲，見火忽學爆竹鳴。',80,'全唐诗/poet.song.141000.json','["烏銀玉質金石聲，見火忽學爆竹鳴。", "腷腷膊膊久不停，白日坐上飛繁星。", "不知何怒泄不平，不知何喜唧唧吟。", "待渠自靜勿與爭，切莫借箸怒復生。", "到渠緘口兩耳熱，銅瓶在旁却饒舌。"]'),
('70d1a6c1-30cb-498d-866c-99cd94fedb10','雪晴','楊萬里','宋','宋诗','song-poetry','','[]','天公有詔放朝晴，排遣雲師嬾未行。',64,'全唐诗/poet.song.141000.json','["天公有詔放朝晴，排遣雲師嬾未行。", "頭上忽張青玉傘，海東湧出紫金鉦。", "雪山冰谷居然暖，銀屋瑶臺分外明。", "二十四船人笑語，寒聲一變作春聲。"]'),
('ba989e27-ad3f-4e46-ad19-b30d76e825e6','晚晴','楊萬里','宋','宋诗','song-poetry','','[]','日光射雪雪透紅，雪光射日日吐虹。',64,'全唐诗/poet.song.141000.json','["日光射雪雪透紅，雪光射日日吐虹。", "何人鑄銀作大地，萬象都入銀光中。", "詩翁兩眼老病裏，愛看晚晴聊仰視。", "眼睛空花忽亂起，紫暈一輪三萬里。"]'),
('b890943e-c88f-4bcf-98e7-92b6da8e50a1','甘露子一名地蠶','楊萬里','宋','宋诗','song-poetry','','[]','甘露子，甘露子，喚作地蠶亦良似。',82,'全唐诗/poet.song.141000.json','["甘露子，甘露子，喚作地蠶亦良似。", "不食柘葉不食桑，何須走入地底藏。", "不能作繭不上簇，如何也蒙賜湯沐。", "呼我果，謂之果，呼我蔌，謂之蔌。", "唐林晁錯莫逢它，高陽酒徒咀爾不摇牙。"]'),
('eb3efeba-17b6-468d-9ef5-c54c73d6f2ae','夜過楊州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','祗今何許問迷樓，更有垂楊記御溝。',32,'全唐诗/poet.song.141000.json','["祗今何許問迷樓，更有垂楊記御溝。", "除却瓊花與紅藥，楊州不是古楊州。"]'),
('963dcb27-ce56-41c1-bee6-9de65b94ead1','夜過楊州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','新晴殘凍未全銷，月戀冰河雪戀橋。',32,'全唐诗/poet.song.141000.json','["新晴殘凍未全銷，月戀冰河雪戀橋。", "兩岸紅燈成白晝，楊州臘月看元宵。"]'),
('743b60da-2fcf-4475-8cb5-e6422fc4a9a4','雪霽曉登金山','楊萬里','宋','宋诗','song-poetry','','[]','焦山東，金山西，金山排霄南斗齊。',174,'全唐诗/poet.song.141000.json','["焦山東，金山西，金山排霄南斗齊。", "天將三江五湖水，併作一江字楊子。", "來從九天上，瀉入九地底。", "遇嶽嶽立摧，逢石石立碎。", "乾坤氣力聚此江，一波打來誰敢當。", "金山一何强，上流獨立江中央。", "一塵不隨海風舞，一礫不隨海潮去。", "四旁無蔕下無根，浮空躍出江心住。", "金宮銀闕起峰頭，槌鼓撞鐘聞九州。", "詩人踏雪來清游，天風吹儂上瓊樓，不爲浮玉飲玉舟。", "大江端的替人羞，金山端的替人愁。"]'),
('2a82a281-bc49-4931-88b3-1763d49a1f48','題金山妙高臺','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','金山未到時，羨渠奄有萬里之長江。',232,'全唐诗/poet.song.141000.json','["金山未到時，羨渠奄有萬里之長江。", "金山既到了，長江不見只見千步廊。", "老夫平生不奈事，點檢風光難可意。", "老僧覺我見睫眉，引入妙高臺上嬉。", "不知老僧有妙手，卷舒江山在懷袖。", "挂上西窗方丈間，長江浮在爐煙端。", "長江南邊千萬山，一時飛入兩眼寒。", "最愛簷前絕奇處，江心巉然景純墓。", "僧言道許乃浪傳，龍宮特書珠貝編。", "初云謝靈運，愛山如愛命。", "掇取天台雁蕩怪石頭，疊作假山立中流。", "又云王逸少，草聖入神妙。", "天賜瑠璃筆格玉硯屏，仍將大江作陶泓。", "老夫聞二說，沉吟未能決。", "長年抵死催上船，徘徊欲去空茫然。"]'),
('6de7f477-f098-448e-ad2a-073fc982bdbc','竹枝歌七首  其一','楊萬里','宋','宋诗','song-poetry','','[]','吳儂一隊好兒郎，只要船行不要忙。',32,'全唐诗/poet.song.141000.json','["吳儂一隊好兒郎，只要船行不要忙。", "著力大家齊一拽，前頭管取到丹陽。"]'),
('af77c3b2-9c4b-4fee-bad4-c074e5c5bb8d','竹枝歌七首  其二','楊萬里','宋','宋诗','song-poetry','','[]','莫笑樓船不解行，識儂號令聽儂聲。',32,'全唐诗/poet.song.141000.json','["莫笑樓船不解行，識儂號令聽儂聲。", "一人唱了千人和，又得蹉前五里程。"]'),
('facb9518-02a5-4c03-a845-f92ec963dec8','竹枝歌七首  其三','楊萬里','宋','宋诗','song-poetry','','[]','船頭更鼓恰三槌，底事荒雞早箇啼。',32,'全唐诗/poet.song.141000.json','["船頭更鼓恰三槌，底事荒雞早箇啼。", "戲學當年度關客，且圖一笑過前溪。"]'),
('e6a2f972-d285-4381-8e3d-d987d4d7f2aa','竹枝歌七首  其四','楊萬里','宋','宋诗','song-poetry','','[]','積雪初融做晚晴，黄昏恬靜到三更。',32,'全唐诗/poet.song.141000.json','["積雪初融做晚晴，黄昏恬靜到三更。", "小風不動還知麽，且只牽船免打冰。"]'),
('77d4452b-6493-4ca8-9313-ab7dba3f180b','竹枝歌七首  其五','楊萬里','宋','宋诗','song-poetry','','[]','岸旁燎火莫闌殘，須念兒郎手脚寒。',32,'全唐诗/poet.song.141000.json','["岸旁燎火莫闌殘，須念兒郎手脚寒。", "更把綠荷包熱飯，前頭不怕上高灘。"]'),
('fe5446d8-22a0-4093-b548-537ed3522517','竹枝歌七首  其六','楊萬里','宋','宋诗','song-poetry','','[]','月子彎彎照幾州，幾家驩樂幾家愁。',32,'全唐诗/poet.song.141000.json','["月子彎彎照幾州，幾家驩樂幾家愁。", "愁殺人來關月事，得休休處且休休。"]'),
('e660e642-e3f7-4685-9296-ff007311cc98','竹枝歌七首  其七','楊萬里','宋','宋诗','song-poetry','','[]','幸自通宵暖更晴，何勞細雨送殘更。',32,'全唐诗/poet.song.141000.json','["幸自通宵暖更晴，何勞細雨送殘更。", "知儂笠漏芒鞋破，須遣拖泥带水行。"]'),
('01d5dba0-d6a3-42a5-8b65-55cc5b88005d','過京口以南見竹林','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','行從江北別梅兄，歸到江南見竹君。',32,'全唐诗/poet.song.141000.json','["行從江北別梅兄，歸到江南見竹君。", "却憶西湖湖上寺，梅花如雪竹如雲。"]'),
('2077a991-a79c-4025-b87a-ec2dcce1cd79','過呂城閘六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','閘頭洲子許團欒，古廟蕭條暮雨寒。',32,'全唐诗/poet.song.141000.json','["閘頭洲子許團欒，古廟蕭條暮雨寒。", "榆柳千株無半葉，冬青一樹碧琅玕。"]'),
('3e3823bf-824f-4e1c-be45-e7334b50a04c','過呂城閘六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','泊船到得暮鐘時，等待諸船不肯齊。',32,'全唐诗/poet.song.141000.json','["泊船到得暮鐘時，等待諸船不肯齊。", "等得船齊方過閘，又須五鼓到荆溪。"]'),
('cf55d847-4d48-4f2b-b424-724064ae8d6a','過呂城閘六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','昨宵聽盡棹謳聲，愁裏無眠達五更。',32,'全唐诗/poet.song.141000.json','["昨宵聽盡棹謳聲，愁裏無眠達五更。", "今夕雨寒泥又滑，作何計會速天明。"]'),
('93728814-5ce3-4603-aa10-56905bc00b6a','過呂城閘六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','等到船齊閘欲開，船船捩柁整帆桅。',32,'全唐诗/poet.song.141000.json','["等到船齊閘欲開，船船捩柁整帆桅。", "一船最後知何故，日許時間獨不來。"]'),
('b98e8312-9b53-42d8-8e41-179421267187','過呂城閘六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','纔聞開閘總驩欣，第一牽夫有喜聲。',32,'全唐诗/poet.song.141000.json','["纔聞開閘總驩欣，第一牽夫有喜聲。", "只得片時天未黑，後來天黑也甘行。"]'),
('5e11da69-f7ff-42d5-ae42-ca092f5a818f','過呂城閘六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','道是行船也未行，老夫誤喜可憐生。',32,'全唐诗/poet.song.141000.json','["道是行船也未行，老夫誤喜可憐生。", "要知開閘真消息，記取金鉦第二聲。"]'),
('bb509d9f-9d25-4a1c-8f11-54ee4ce3250f','再過常州','楊萬里','宋','宋诗','song-poetry','','[]','淮浦回春舫，荆溪又早炊。',48,'全唐诗/poet.song.141000.json','["淮浦回春舫，荆溪又早炊。", "向來迎客處，還似迓儂時。", "父老今餘幾，山川別後奇。", "舊游休再至，再至只成悲。"]'),
('79d5895b-1857-4f35-80b4-1140122b1a57','晝睡聞雁','楊萬里','宋','宋诗','song-poetry','','[]','夢裏霜鴻叫絕天，䰒鬆睡眼起來看。',32,'全唐诗/poet.song.141000.json','["夢裏霜鴻叫絕天，䰒鬆睡眼起來看。", "殷勤甓社湖中客，送我南歸到惠山。"]'),
('344b8ac5-19ca-42af-a552-43539c7ec507','橫林望見惠山寄懷尤延之三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','惠山一別十年强，雪後精神老更蒼。',32,'全唐诗/poet.song.141000.json','["惠山一別十年强，雪後精神老更蒼。", "白玉屏風三萬丈，半天遮斷太湖光。"]'),
('67afb255-cf9f-40f5-95d1-35277749cfe0','橫林望見惠山寄懷尤延之三首  其二','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','惠山孤絕未爲孤，下有詩仙伴却渠。',32,'全唐诗/poet.song.141000.json','["惠山孤絕未爲孤，下有詩仙伴却渠。", "占斷惠山妨底事，無端更占洞庭湖。"]'),
('dc9f0d82-ebbf-454a-a72a-44fc67a431a8','橫林望見惠山寄懷尤延之三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','平生玉樹伴蒹葭，晚歲春蘭隔菊花。',32,'全唐诗/poet.song.141000.json','["平生玉樹伴蒹葭，晚歲春蘭隔菊花。", "咫尺遂初堂下水，寄詩猶自怨人遐。"]'),
('644270ba-55a2-47c3-a5c8-f5922fc3c98d','遣騎迎家久稽來訊','楊萬里','宋','宋诗','song-poetry','','[]','還家家尚緬，迎家家未來。',204,'全唐诗/poet.song.141000.json','["還家家尚緬，迎家家未來。", "去住兩不知，安否更相猜。", "偶思十年事，誰謂今歲乖。", "始我離高安，述職朝天街。", "中外理難必，骨肉心與偕。", "同室忽分塗，老情非不懷。", "入京就一列，汲汲營尺榱。", "牆屋亟求完，婦子豈我催。", "前知來期杳，更用辛苦爲。", "屬以王事出，寒舲如江淮。", "風霜厲宵泳，山水薦曉瓌。", "六朝幾宿草，事往空餘哀。", "夢收兒女書，喜極睫爲開。", "一欣雖非實，差慰腸九回。", "歸帆拂惠山，良訊傳荆涯。", "啟緘復非真，旅思彌不佳。", "船門且看雪，呼僮滌荷杯。"]'),
('54f81309-5592-4397-b6c0-d35774eb4b31','舟中奉懷三館同舍','楊萬里','宋','宋诗','song-poetry','','[]','岸樹枝枝瘦，汀蕪節節枯。',48,'全唐诗/poet.song.141000.json','["岸樹枝枝瘦，汀蕪節節枯。", "雲留雪且住，風與屋相呼。", "一老凍欲死，羣仙知也無。", "更緣詩作祟，病骨轉清臞。"]'),
('d4566fb4-504c-428d-9544-f11e94b76bcb','過望亭六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','望亭昔歲過歸船，柳爲蹁躚杏爲妍。',32,'全唐诗/poet.song.141000.json','["望亭昔歲過歸船，柳爲蹁躚杏爲妍。", "今日溪山渾似舊，雪蘆風荻兩蕭然。"]'),
('426b6d14-f4b1-4407-b3bf-230103cdc4c8','過望亭六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','窗間雨打淚新斑，破處風來叫得酸。',32,'全唐诗/poet.song.141000.json','["窗間雨打淚新斑，破處風來叫得酸。", "若是詩人都富貴，遣誰忍餓遣誰寒。"]'),
('64095d53-8870-4bb0-bfa4-a700a1671c55','過望亭六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','暮鴻作陣猛相追，風有何忙也急吹。',32,'全唐诗/poet.song.141000.json','["暮鴻作陣猛相追，風有何忙也急吹。", "惱殺詩人真枉却，雲窗霧閣不曾知。"]'),
('cf200b15-fb28-4da7-ba27-c0780b2c313d','過望亭六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','兩岸山林總解行，一層送了一層迎。',32,'全唐诗/poet.song.141000.json','["兩岸山林總解行，一層送了一層迎。", "天公收却春風面，拈出酸寒水墨屏。"]'),
('9ab2afa7-5571-454b-a41f-2e13d394c72c','過望亭六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','朝朝暮暮見長河，見了長河只厭它。',32,'全唐诗/poet.song.141000.json','["朝朝暮暮見長河，見了長河只厭它。", "却愛畫師能畫水，不看死浪與生波。"]'),
('4605dbfe-4143-4e27-b9d0-5dd0cea313d5','過望亭六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','晴河不似雨中看，晴裏波紋只簟斑。',32,'全唐诗/poet.song.141000.json','["晴河不似雨中看，晴裏波紋只簟斑。", "却是雨河新樣巧，簟間織出小金鐶。"]'),
('a19ab901-c553-452d-b28e-117efcb8f425','跋黄文若詩卷','楊萬里','宋','宋诗','song-poetry','','[]','五字長城璧不如，鼠肝蟲臂得關渠。',32,'全唐诗/poet.song.141000.json','["五字長城璧不如，鼠肝蟲臂得關渠。", "竹坡集裏曾相識，驚見蘭亭繭紙書。"]'),
('565c1616-7089-4d9b-9bc5-9bce0d28599f','垂虹亭觀打魚斫鱠四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','橋柱疎疎四寂然，亭前突出八魚船。',32,'全唐诗/poet.song.141000.json','["橋柱疎疎四寂然，亭前突出八魚船。", "一聲磔磔鳴榔起，驚出銀刀躍玉泉。"]'),
('a3c84dbf-5c55-40a8-8dc1-76c585609197','垂虹亭觀打魚斫鱠四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','六隻輕舠攪四旁，兩船不動水中央。',32,'全唐诗/poet.song.141000.json','["六隻輕舠攪四旁，兩船不動水中央。", "網絲一撒還空舉，笑得倚欄人斷腸。"]'),
('02457755-f58e-43a8-8cf6-d496fc7ac71d','垂虹亭觀打魚斫鱠四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','漁郎妙手絕多機，一網收魚未足奇。',32,'全唐诗/poet.song.141000.json','["漁郎妙手絕多機，一網收魚未足奇。", "剛向人前撰勳績，不教速得只教遲。"]'),
('cb3dcb13-116d-4412-8c0a-bdba620374de','垂虹亭觀打魚斫鱠四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','鱸魚小底最爲佳，一白雙腮是當家。',32,'全唐诗/poet.song.141000.json','["鱸魚小底最爲佳，一白雙腮是當家。", "旋看冰盤堆白雪，急風吹去片銀花。"]'),
('1baecaa3-71ef-4c85-937c-913313c3eb6c','過太湖石塘三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','纔轉船頭特地寒，初無風色自生湍。',64,'全唐诗/poet.song.141000.json','["纔轉船頭特地寒，初無風色自生湍。", "堤橫湖面平分白，水拓天圍分外寬。", "一鏡銀濤三萬頃，獨龍玉脊百千蟠。", "若爲結屋蘆花裏，月笠雲蓑把釣竿。"]'),
('a84b4f77-8dfc-4b10-9c3e-28a4272c5f50','過太湖石塘三首  其二','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','每過松江得偉觀，玻璃盆底飣乾坤。',64,'全唐诗/poet.song.141000.json','["每過松江得偉觀，玻璃盆底飣乾坤。", "天邊島嶼空無際，煙外人家澹有痕。", "笠澤古今多浪士，包山近遠在何村。", "季鷹魯望何曾死，雪是衣裳月是魂。"]'),
('84eb3c79-e70e-4435-a736-2e05bd01d81b','過太湖石塘三首  其三','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','兀坐船中只欲眠，不如船外看山川。',64,'全唐诗/poet.song.141000.json','["兀坐船中只欲眠，不如船外看山川。", "松江是物皆詩料，蘭槳穿湖即水仙。", "將取垂虹亭上景，都歸却月觀中篇。", "正緣王事游方外，鑿齒彌天未當賢。"]'),
('24342134-d742-4139-b58b-3a5751c90331','過八尺遇雨三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','垂虹登了劣歸船，又復毛空暗水天。',32,'全唐诗/poet.song.141000.json','["垂虹登了劣歸船，又復毛空暗水天。", "節裏無多好天色，闌風長雨餞殘年。"]'),
('e2b3f8f1-bd28-4a44-a8be-9734aeac4257','過八尺遇雨三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去年今日鳳山頭，兒女團欒爭勸酬。',32,'全唐诗/poet.song.141000.json','["去年今日鳳山頭，兒女團欒爭勸酬。", "不及松江煙雨裏，獨搔華髮一扁舟。"]'),
('90462a08-f9e7-42d7-89c4-f1b2ca3f9443','過八尺遇雨三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','細雨無聲忽有聲，亂珠跳作萬銀釘。',32,'全唐诗/poet.song.141000.json','["細雨無聲忽有聲，亂珠跳作萬銀釘。", "呼僮速買庉村酒，更煮鱸魚蓴菜羹。"]'),
('6faeccf8-dff0-4cc2-9f4d-46f05f4f36cc','過上湖','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','上湖名是實全非，只合松江雁鶩池。',32,'全唐诗/poet.song.141000.json','["上湖名是實全非，只合松江雁鶩池。", "若與五湖通譜系，澹臺湖弟太湖兒。"]'),
('1402f7b6-23b4-4559-a48c-b2687f7c9a63','過平望三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','豈但湖天好，諸村總可人。',48,'全唐诗/poet.song.141000.json','["豈但湖天好，諸村總可人。", "麥苗染不就，茅屋畫來真。", "行止隨緣著，江山到處新。", "十年三過此，贏得鬢如銀。"]'),
('12d2a63f-a74a-455e-8cb7-11c065af6ae4','過平望三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','行得三吳徧，清奇最是蘇。',48,'全唐诗/poet.song.141000.json','["行得三吳徧，清奇最是蘇。", "樹圍平野合，水隔別村孤。", "震澤非塵世，松陵是畫圖。", "更添一詩老，載雪過重湖。"]'),
('e7344935-be27-456c-b9c4-7b151ee8400b','過平望三首  其三','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','小麥田田種，垂楊岸岸栽。',48,'全唐诗/poet.song.141000.json','["小麥田田種，垂楊岸岸栽。", "風從平望住，雨傍下塘來。", "亂港交穿市，高橋過得桅。", "誰言破書篋，擔取太湖回。"]'),
('a6dffcbb-0328-4cba-9dd8-a571a1dd0dcb','葉叔羽集同年九人於櫻桃園錢襲明何同叔即席賦詩追和其韻二首 和錢襲明韻','楊萬里','宋','宋诗','song-poetry','','[]','八座能分一日光，題名猶記榜間黄。',64,'全唐诗/poet.song.141000.json','["八座能分一日光，題名猶記榜間黄。", "看渠超出金閨彥，顧我曾爲同舍郎。", "高會九人尋水石，縱談一笑間宮商。", "越王孫子瓊瑶句，細把重吟恐脫忘。"]'),
('58ace7ec-0271-4349-9777-6443b98485e1','葉叔羽集同年九人於櫻桃園錢襲明何同叔即席賦詩追和其韻二首 和何同叔韻','楊萬里','宋','宋诗','song-poetry','','[]','天門金榜出槐宸，四海同年骨肉親。',64,'全唐诗/poet.song.141000.json','["天門金榜出槐宸，四海同年骨肉親。", "走馬看花纔幾日，曉星殘月半無人。", "談間平叔元如玉，句裏司勳別有春。", "欲把清新比梅雪，却愁梅雪未清新。"]'),
('4cee783b-6d4d-411a-b44e-5c406ed00e93','秀州嘉興館拜賜春幡勝','楊萬里','宋','宋诗','song-poetry','','[]','中使傳宣下紫宸，鏃頭濃染御香雲。',64,'全唐诗/poet.song.141000.json','["中使傳宣下紫宸，鏃頭濃染御香雲。", "綵幡耐夏宜春字，寶勝連環曲水紋。", "癡似土牛鞭不動，老登金馬媿無聞。", "强簪華髮知難稱，只有新詩頌萬分。"]'),
('e255fda3-0835-46ae-8d7f-54388435ff4d','立春日舟前細雨','楊萬里','宋','宋诗','song-poetry','','[]','急風陣陣吹白塵，著人怪底濕衣巾。',64,'全唐诗/poet.song.141000.json','["急風陣陣吹白塵，著人怪底濕衣巾。", "隔溪平林橫素練，起從山脚縈山面。", "近山如霧復如煙，遠山失却只餘天。", "今朝春日得春雨，潤物無聲非浪語。"]'),
('f7fb6490-8335-4a13-be0e-9f17edb22538','漁舟','楊萬里','宋','宋诗','song-poetry','','[]','絕小漁舟葉似輕，荻篷密蓋不聞聲。',32,'全唐诗/poet.song.141000.json','["絕小漁舟葉似輕，荻篷密蓋不聞聲。", "無人無釣無蓑笠，風自吹船船自行。"]'),
('06428245-e887-4191-9483-a65ed05b8112','入長安閘','楊萬里','宋','宋诗','song-poetry','','[]','船入長安恰五更，歸人都喜近臨平。',32,'全唐诗/poet.song.141000.json','["船入長安恰五更，歸人都喜近臨平。", "陰晴天色知何似，篷上惟聞掃雪聲。"]'),
('a5960fd0-bf4c-466c-a6b6-88efd5d9e62a','記夢中紅碧一聯','楊萬里','宋','宋诗','song-poetry','','[]','喜教兒聯句，那知是夢中。',48,'全唐诗/poet.song.141000.json','["喜教兒聯句，那知是夢中。", "天窺波底碧，日抹樹梢紅。", "覺後念何說，意間難强通。", "元來一夜雪，明曉散晴空。"]'),
('8c826b4e-bf34-4e22-9624-e2677e97519a','過臨平二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','臨平放目渺無涯，蓮蕩蘋汀不釘牌。',32,'全唐诗/poet.song.141000.json','["臨平放目渺無涯，蓮蕩蘋汀不釘牌。", "雪後輕船四撈漉，斷蘆殘荻總成柴。"]'),
('abe7c00c-c715-4ae2-8bd7-dda7c9d1358d','過臨平二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','人家點綴荻花林，水繞階除雪濕衿。',32,'全唐诗/poet.song.141000.json','["人家點綴荻花林，水繞階除雪濕衿。", "最是疎籬與脩竹，脚根半入小河深。"]'),
('492d814d-e097-4778-bb8f-ab19f81634f2','庚戌正月三日約同舍游西湖十首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不到西湖又兩年，西湖風物故依然。',32,'全唐诗/poet.song.141000.json','["不到西湖又兩年，西湖風物故依然。", "道旁松檜俱無恙，笑我重來雪滿顛。"]'),
('b5d729de-fbb7-47c6-a83e-3a64b7089363','庚戌正月三日約同舍游西湖十首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春光欲動意猶遲，未許游人浪見伊。',32,'全唐诗/poet.song.141000.json','["春光欲動意猶遲，未許游人浪見伊。", "只有梅花藏不得，隔籬穿竹出橫枝。"]'),
('4f915880-8920-48c1-98c1-3d7c75040655','庚戌正月三日約同舍游西湖十首  其三','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄金榜揭集芳園，只隔牆頭便是天。',32,'全唐诗/poet.song.141000.json','["黄金榜揭集芳園，只隔牆頭便是天。", "西母雲車寒未降，鶑花作意辦新年。"]'),
('33baf945-6364-4b0d-b26c-91c954ec4873','庚戌正月三日約同舍游西湖十首  其四','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南北高峰巧避人，旋生雲霧半腰橫。',32,'全唐诗/poet.song.141000.json','["南北高峰巧避人，旋生雲霧半腰橫。", "縱然遮得青蒼面，玉塔雙尖分外明。"]'),
('e4b1aa9b-25b8-49c9-a995-917ba9140f46','庚戌正月三日約同舍游西湖十首  其五','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','下竺泉從上竺來，前波後浪緊相催。',32,'全唐诗/poet.song.141000.json','["下竺泉從上竺來，前波後浪緊相催。", "泉聲似說西湖好，流到西湖不要回。"]'),
('9b3360e3-b550-40b9-bcbc-dc1d6931a4a2','庚戌正月三日約同舍游西湖十首  其六','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','補種杉松逕已成，泥乾塵浄正堪行。',32,'全唐诗/poet.song.141000.json','["補種杉松逕已成，泥乾塵浄正堪行。", "草芽併作傷心碧，只欠先生屐子聲。"]'),
('88d94edb-7233-4cf4-bec3-764c3a649443','庚戌正月三日約同舍游西湖十首  其七','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','上竺諸峰深復深，一重一掩翠雲衿。',32,'全唐诗/poet.song.141000.json','["上竺諸峰深復深，一重一掩翠雲衿。", "只言人跡無來路，動地鐘聲與梵音。"]'),
('ac650309-8869-4375-8b9a-271ba7339c0e','庚戌正月三日約同舍游西湖十首  其八','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家家砌下過清泉，寺寺雲邊占碧山。',32,'全唐诗/poet.song.141000.json','["家家砌下過清泉，寺寺雲邊占碧山。", "走馬來看已心醒，更教選勝住中間。"]'),
('9f59ed68-be5d-4ff8-8b25-e8e3f5aa2047','庚戌正月三日約同舍游西湖十首  其九','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','樹生石上土全無，只見青葱不見枯。',32,'全唐诗/poet.song.141000.json','["樹生石上土全無，只見青葱不見枯。", "好在冷泉亭下水，爲渠憑檻數游魚。"]'),
('e0b34c63-add1-4111-8c8e-586c979ad2fe','庚戌正月三日約同舍游西湖十首  其一○','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閘住清泉似鏡平，閘開奔浪作潮聲。',32,'全唐诗/poet.song.141000.json','["閘住清泉似鏡平，閘開奔浪作潮聲。", "放開一板還收去，依舊穿沙繞石行。"]'),
('c8d407ef-b851-4d4a-a58a-363c5b2c08ba','題浩然李致政義概堂','楊萬里','宋','宋诗','song-poetry','','[]','非俠非狂非逸民，讀書謀國不謀身。',64,'全唐诗/poet.song.141000.json','["非俠非狂非逸民，讀書謀國不謀身。", "一封北闕三千牘，再活西州六萬人。", "雨露晚從天上落，芝蘭親見掌中新。", "仁心義概絲綸語，長掛巴山月半輪。"]'),
('4e5d8cfd-97c9-43d3-b2f1-51c833adc04b','謝李君亮贈陳中正墨','楊萬里','宋','宋诗','song-poetry','','[]','麝煙薰透大夫松，膠國吹成赤鯶公。',64,'全唐诗/poet.song.141000.json','["麝煙薰透大夫松，膠國吹成赤鯶公。", "龍尾研磨碎蒼璧，鼠鬚飛動出晴虹。", "誰言陳子草玄手，突過蒲家讀墨功。", "老我久無椽樣筆，爲君小楷注魚蟲。"]'),
('942167e1-bdc9-48ea-be2b-482b939fa960','贈倪正甫令子阿麟','楊萬里','宋','宋诗','song-poetry','','[]','精神玉雪眼點漆，總角兩髦錦纏碧。',176,'全唐诗/poet.song.141000.json','["精神玉雪眼點漆，總角兩髦錦纏碧。", "郎君未出客已驚，隔窗讀書鸞鶴聲。", "松煙兔穎小三昧，蠆尾銀鈎略無對。", "鍾王筆法老始成，阿麟今纔十二齡。", "七十列傳十二紀，白頭書生不能記。", "亂抽架上聊試渠，橫誦倒誦如流水。", "二雅三頌已作箋，要與毛鄭爭先鞭。", "吟詩作賦更餘事，不論五言兼七字。", "奉常先生有陰功，翰苑仙人有家風。", "高科好官手可唾，更看聲名塞天破。", "老夫還曾浪語麽，老夫還曾浪語麽。"]'),
('ca350ed0-aa94-42c7-a8b0-ff0a04524d7f','記張定叟煮笋經','楊萬里','宋','宋诗','song-poetry','','[]','江西貓笋未出尖，雪中土膏養新甜。',128,'全唐诗/poet.song.141000.json','["江西貓笋未出尖，雪中土膏養新甜。", "先生別得煮簀法，丁寧勿用醯與鹽。", "巖下清泉須旋汲，熬出霜根生蜜汁。", "寒芽嚼作冰片聲，餘瀝仍和月光吸。", "菘羔楮雞浪得名，不如來參玉板僧。", "醉裏何須酒解酲，此羹一椀爽然醒。", "大都煮菜皆如此，淡處當知有真味。", "先生此法未要傳，爲公作經藏名山。"]'),
('c84955a1-0153-4a17-a434-887ebcd7ee2b','和丘宗卿贈長句之韻','楊萬里','宋','宋诗','song-poetry','','[]','君入脩門纔一見，我出脩門風刮面。',224,'全唐诗/poet.song.141000.json','["君入脩門纔一見，我出脩門風刮面。", "歸來急問有新詩，句句舉似君不疑。", "殿門握手冠纓絕，炯如雲破瞻秋月。", "老懷勃鬰久不開，爲君傾豁情既竭。", "君詩元自過黄初，古雅可敬麗可娛。", "詩壇端是一敵國，乃不自惜下取予。", "向來交游半生死，悼往喜今同彼此。", "老夫懶性不便書，毛穎爲君浴清泚。", "聖賢何時同一中，縱談社燕與秋鴻。", "芒鞋藤杖尋春風，天竺靈隠九里松。", "古來樂事天慳與，怪珍未必逢良賈。", "即今又欲駕官船，淮水中流送歸虜。", "金山獨上妙高臺，再與海若相詼諧。", "歸時藉手無一字，教君笑殺老誠齋。"]'),
('9c54312a-07a1-4af3-b2a1-e6dc2d9831f3','大兒長孺赴零陵簿示以雜言','楊萬里','宋','宋诗','song-poetry','','[]','好官易得忙不得，好人難做須著力。',178,'全唐诗/poet.song.141000.json','["好官易得忙不得，好人難做須著力。", "汝要作好官，令公書考不可鑽。", "借令巧鑽得，遺臭千載心爲寒。", "汝要作好人，東家也是橫目民。", "選官無選處，却與天地長青春。", "老夫今年六十四，大兒壯歲初筮仕。", "先人門戶冷如冰，豈不願汝取高位。", "高位莫愛渠，愛了高位失丈夫。", "老夫老則老，官職不要討。", "白頭官裏捉出來，生愁無面見草萊。", "老夫不足學，聖賢有前作。", "譬如著棋著到國手時，國手頭上猶更儘有著。"]'),
('0e3fe434-cd91-4548-a980-774e9c862c99','正月五日以送伴借官侍宴集英殿十口號  其一','楊萬里','宋','宋诗','song-poetry','','[]','殿下鞭聲再掣雷，玉皇徐下九天來。',32,'全唐诗/poet.song.141000.json','["殿下鞭聲再掣雷，玉皇徐下九天來。", "陰晴不定朝來定，五色祥雲霍地開。"]'),
('20a149ab-2d75-467c-813e-c3945cf1c8a5','正月五日以送伴借官侍宴集英殿十口號  其二','楊萬里','宋','宋诗','song-poetry','','[]','一點胡行朝漢天，英符來自玉門關。',32,'全唐诗/poet.song.141000.json','["一點胡行朝漢天，英符來自玉門關。", "舊時千歲琵琶語，新學三聲萬歲山。"]'),
('1c4a5f0a-f97b-4b7e-9da6-f44b764fc2cb','正月五日以送伴借官侍宴集英殿十口號  其三','楊萬里','宋','宋诗','song-poetry','','[]','金鬣狻猊立玉臺，雙瞻御坐首都回。',32,'全唐诗/poet.song.141000.json','["金鬣狻猊立玉臺，雙瞻御坐首都回。", "水沉山麝薔薇露，漱作香雲噴出來。"]'),
('a490548b-42b2-4874-8f60-0c5a5df86d69','正月五日以送伴借官侍宴集英殿十口號  其四','楊萬里','宋','宋诗','song-poetry','','[]','千官拜舞仰虛皇，奉上瑶池萬壽觴。',32,'全唐诗/poet.song.141000.json','["千官拜舞仰虛皇，奉上瑶池萬壽觴。", "殿上雙傳送御酒，檻前一曲繞虹梁。"]'),
('8a592ee0-9072-4e70-83c8-270be1743512','正月五日以送伴借官侍宴集英殿十口號  其五','楊萬里','宋','宋诗','song-poetry','','[]','太極重開萬物新，紹熙天子宴羣臣。',32,'全唐诗/poet.song.141000.json','["太極重開萬物新，紹熙天子宴羣臣。", "梨園好語君須聽，玉曆初頒第一春。"]'),
('82a2a014-29c4-4b00-a1b8-507544507eb5','正月五日以送伴借官侍宴集英殿十口號  其六','楊萬里','宋','宋诗','song-poetry','','[]','已賜儀鸞錦坐蒲，起來再立聽傳臚。',32,'全唐诗/poet.song.141000.json','["已賜儀鸞錦坐蒲，起來再立聽傳臚。", "君王欲勸羣臣酒，宣示天杯一滴無。"]'),
('b90714ae-9e95-4b04-90b6-095cd91fd4f0','正月五日以送伴借官侍宴集英殿十口號  其七','楊萬里','宋','宋诗','song-poetry','','[]','猛士緣竿亦壯哉，踏空舞闊四裴回。',32,'全唐诗/poet.song.141000.json','["猛士緣竿亦壯哉，踏空舞闊四裴回。", "一聲白雨催花鼓，十二竿頭總下來。"]'),
('0e9071c7-f376-4e56-9832-0f0d5cffd31e','正月五日以送伴借官侍宴集英殿十口號  其八','楊萬里','宋','宋诗','song-poetry','','[]','賜花新剪茜香羅，篸徧烏紗未覺多。',32,'全唐诗/poet.song.141000.json','["賜花新剪茜香羅，篸徧烏紗未覺多。", "花重紗輕人更老，擡頭不起奈春何。"]'),
('5ec38dde-32ae-4846-92ae-ef0f374811d2','正月五日以送伴借官侍宴集英殿十口號  其九','楊萬里','宋','宋诗','song-poetry','','[]','廣場妙戲鬭程材，未得天顔一笑開。',32,'全唐诗/poet.song.141000.json','["廣場妙戲鬭程材，未得天顔一笑開。", "角觝罷時還宴罷，卷班出殿戴花回。"]'),
('ee746e41-0f97-4dd3-b991-8fbe9ab12917','正月五日以送伴借官侍宴集英殿十口號  其一○','楊萬里','宋','宋诗','song-poetry','','[]','賀老如何尾從班，真官也作借官看。',32,'全唐诗/poet.song.141000.json','["賀老如何尾從班，真官也作借官看。", "君恩至重無真假，賜酒何曾味兩般。"]'),
('d318aca9-13d8-402e-9e44-6824f8e68dcf','三花斛三首 瑞香','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','侵雪開花雪不侵，開時色淺未開深。',64,'全唐诗/poet.song.141000.json','["侵雪開花雪不侵，開時色淺未開深。", "碧團欒裏笋成束，紫蓓蕾中香滿襟。", "別派近傳廬阜頂，孤芳元自洞庭心。", "詩人自有薰籠錦，不用衣篝炷水沉。"]'),
('38219515-a1b1-4b88-8cd5-55c5ff423c7b','三花斛三首 水仙','楊萬里','宋','宋诗','song-poetry','','[]','生來體弱不禁風，匹似蘋花較小豐。',64,'全唐诗/poet.song.141000.json','["生來體弱不禁風，匹似蘋花較小豐。", "腦子醲薰衆香國，江妃寒損水精宮。", "銀臺金盞談何俗，礬弟梅兄品未公。", "寄語金華老仙伯，凌波仙子更凌空。"]'),
('138d175b-cd6d-451d-b4fc-93d64dd82c77','三花斛三首 蘭花','楊萬里','宋','宋诗','song-poetry','','[]','雪徑偷開淺碧花，冰根亂吐小紅芽。',64,'全唐诗/poet.song.141000.json','["雪徑偷開淺碧花，冰根亂吐小紅芽。", "生無桃李春風面，名在山林處士家。", "政坐國香到朝市，不容霜節老雲霞。", "江蘺圃蕙非吾耦，付與騷人定等差。"]'),
('3b2b68c6-cabb-489e-8b37-9f5807d9673c','再併賦瑞香水仙蘭三花','楊萬里','宋','宋诗','song-poetry','','[]','水仙頭重力纖弱，碧柳腰支黄玉萼。',112,'全唐诗/poet.song.141000.json','["水仙頭重力纖弱，碧柳腰支黄玉萼。", "娉娉嫋嫋誰爲扶，瑞香在旁扶著渠。", "春蘭初芽嫩仍短，嬌如穉子無人管。", "瑞香綠蔭濃如雲，風日不到況路塵。", "生時各在一山許，畦丁作媒得相聚。", "三花異種復異粧，三花同韻更同香。", "詩人喜渠伴幽獨，不道被渠教斷腸。"]'),
('973a3642-09d4-4a50-8169-e10b31b2d43d','寄題朱元晦武夷精舍十二詠 精舍','楊萬里','宋','宋诗','song-poetry','','[]','憶我南溪北，千巖萬壑亭。',24,'全唐诗/poet.song.141000.json','["憶我南溪北，千巖萬壑亭。", "妬渠紫陽叟，詫殺一峰青。"]'),
('6eb110c5-7e8d-4569-9b19-1136cb69ed18','寄題朱元晦武夷精舍十二詠 仁智堂','楊萬里','宋','宋诗','song-poetry','','[]','學子可憐生，遠來參老子。',24,'全唐诗/poet.song.141000.json','["學子可憐生，遠來參老子。", "仁智若爲談，指似秋山水。"]'),
('d487d8d0-6dcf-4ad8-b9e5-3e7ecbbc7ce8','寄題朱元晦武夷精舍十二詠 隠求堂','楊萬里','宋','宋诗','song-poetry','','[]','夢裏長逢孟，羹中亦見顔。',24,'全唐诗/poet.song.141000.json','["夢裏長逢孟，羹中亦見顔。", "癡兒入吾室，真作采薇看。"]'),
('aeafbf1c-fbb3-4c0c-a3c3-d0df3b0a3f29','寄題朱元晦武夷精舍十二詠 止宿寮','楊萬里','宋','宋诗','song-poetry','','[]','一老說談話，諸君未要眠。',24,'全唐诗/poet.song.141000.json','["一老說談話，諸君未要眠。", "開窗放山月，把酒奏溪泉。"]'),
('270f0643-26f7-4420-a9c4-10cabda7c5a8','寄題朱元晦武夷精舍十二詠 石門塢','楊萬里','宋','宋诗','song-poetry','','[]','亂石堆成玉，雙峰便是門。',24,'全唐诗/poet.song.141000.json','["亂石堆成玉，雙峰便是門。", "莫將塵底脚，踏涴塢中雲。"]'),
('bb8467fe-79a1-42e2-ae09-d7a3ff0afb4e','寄題朱元晦武夷精舍十二詠 觀善齋','楊萬里','宋','宋诗','song-poetry','','[]','觀棋不作秋，觀斲不作石。',24,'全唐诗/poet.song.141000.json','["觀棋不作秋，觀斲不作石。", "要知麗澤功，祇箇是消息。"]'),
('c0a847da-0ec5-47d9-a0a5-22932557f3f7','寄題朱元晦武夷精舍十二詠 寒栖館','楊萬里','宋','宋诗','song-poetry','','[]','鍊玉雲粘杵，朝真露濕衣。',24,'全唐诗/poet.song.141000.json','["鍊玉雲粘杵，朝真露濕衣。", "一聲半夜鶴，月裏羽人歸。"]'),
('9e7583df-348e-424e-b263-de060cfb0897','寄題朱元晦武夷精舍十二詠 晚對亭','楊萬里','宋','宋诗','song-poetry','','[]','大隠翠屏孤，何許最正面。',24,'全唐诗/poet.song.141000.json','["大隠翠屏孤，何許最正面。", "日落未落時，亭上來相見。"]'),
('7f4bcbb5-c12e-4e25-a0d0-97e3d3c3bdee','寄題朱元晦武夷精舍十二詠 鐵笛亭','楊萬里','宋','宋诗','song-poetry','','[]','誰將點漆金，鑄作孤竹笛。',24,'全唐诗/poet.song.141000.json','["誰將點漆金，鑄作孤竹笛。", "林外吹一聲，震落千峰石。"]'),
('1a767691-a4a9-4538-b790-4fdc89d1bde1','寄題朱元晦武夷精舍十二詠 釣磯','楊萬里','宋','宋诗','song-poetry','','[]','月夜乘醉來，垂竿曲溪曲。',24,'全唐诗/poet.song.141000.json','["月夜乘醉來，垂竿曲溪曲。", "水清無寸鱗，釣得半輪玉。"]'),
('7f611c4c-9e82-45fc-b4d4-a50f3e503968','寄題朱元晦武夷精舍十二詠 茶竈','楊萬里','宋','宋诗','song-poetry','','[]','茶竈本笠澤，飛來摘茶國。',24,'全唐诗/poet.song.141000.json','["茶竈本笠澤，飛來摘茶國。", "墮在武夷山，溪心化爲石。"]'),
('bee8da7f-f185-4040-8451-5c6fa44cdcbf','寄題朱元晦武夷精舍十二詠 漁艇','楊萬里','宋','宋诗','song-poetry','','[]','精舍何曾遠，祗在九曲北。',24,'全唐诗/poet.song.141000.json','["精舍何曾遠，祗在九曲北。", "漁艇若不來，弱水萬里隔。"]'),
('54d59e67-5412-432c-8cf7-45ef9b4c3c82','和劉德脩用黄文叔韻贈行','楊萬里','宋','宋诗','song-poetry','','[]','碧玉長篙黄篾篷，兩淮煙月五湖風。',64,'全唐诗/poet.song.141000.json','["碧玉長篙黄篾篷，兩淮煙月五湖風。", "金梭織錦煩詩匠，瓊尺裁雲補化工。", "去路江山隨意綠，歸時桃杏斷腸紅。", "岷峨二妙貽雙璧，萬丈光芒照病翁。"]'),
('503668ce-036c-47de-8b58-fe1d16e46f77','泊舟臨平二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','前窗向市下却簾，後窗臨水開却門。',64,'全唐诗/poet.song.141000.json','["前窗向市下却簾，後窗臨水開却門。", "岸頭楊柳報春動，溪底雲天隨浪翻。", "隔溪數間黄草屋，繞屋千竿翠瓊竹。", "三老鳴鉦檥柂樓，今宵又向臨平宿。"]'),
('daa44982-576f-402a-b893-ca2d3b3c7624','泊舟臨平二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','拂溪十點五點雨，縠紋織出團花縷。',80,'全唐诗/poet.song.141000.json','["拂溪十點五點雨，縠紋織出團花縷。", "花頭細大雖不勻，一花銷時一花吐。", "北風卷雲如卷簾，忽然收盡玉廉纖。", "天光却在水光下，天水鎔作鏡一奩。", "好山隔市望不見，祗有清溪照人面。"]'),
('a986c2e5-b48c-4472-a4d7-63d8c8e286fd','謝王恭父贈梁杲墨','楊萬里','宋','宋诗','song-poetry','','[]','君不見蜀人文字天下工，前有相如後揚雄。',126,'全唐诗/poet.song.141000.json','["君不見蜀人文字天下工，前有相如後揚雄。", "君不見蜀人烏丸天下妙，前有蒲韶後梁杲。", "初得梁墨黐摹糊，老夫道渠不及蒲。", "蓬山藏室王校書，笑我未識真玄菟。", "兩圭水蒼笏，雙團點漆璧。", "一併贈老夫，此意已金石。", "洮州綠玉試松花，星潭黑雲走風沙。", "龍蛇起陸鷹入骨，却愁雷電奪神物。"]'),
('4da3fc61-3982-4e96-ba0f-f0054d7f19e8','蜂兒','楊萬里','宋','宋诗','song-poetry','','[]','蜜蜂不食人間倉，玉露爲酒花爲糧。',120,'全唐诗/poet.song.141000.json','["蜜蜂不食人間倉，玉露爲酒花爲糧。", "作蜜不忙採花忙，蜜成猶带百花香。", "蜜成萬蜂不敢嘗，要輸蜜國供蜂王。", "蜂王未及享，人已割蜜房。", "老蜜已成蠟，嫩蜜方成蜜。", "蜜房蠟片割無餘，老饕更來搜我室。", "老蜂無味祗有滓，幼蜂初化未成兒。", "老饕火攻不知止，既毀我室取我子。"]'),
('3a1c1891-cf70-4d1a-abc4-da4ea825253a','千葉水仙花','楊萬里','宋','宋诗','song-poetry','','[]','薤葉葱根兩不差，重蕤風味獨清嘉。',64,'全唐诗/poet.song.141000.json','["薤葉葱根兩不差，重蕤風味獨清嘉。", "薄揉肪玉圍金鈿，淺染鵝黄剩素紗。", "臺盞元非千葉種，丰容要是小蓮花。", "向來山谷相看日，知是它家是當家。"]'),
('f10d6313-da24-4a83-a158-3e889f559197','臨平解舟','楊萬里','宋','宋诗','song-poetry','','[]','竹籬短短門小小，少年獨立春風曉。',64,'全唐诗/poet.song.141000.json','["竹籬短短門小小，少年獨立春風曉。", "柳芽縮爪尚怯寒，金粟斑斑滿枝了。", "過船橋下橋絕高，波清深見一截篙。", "市人夾水爭出看，無數漁舟避東岸。"]'),
('03bc3850-0198-4e54-b098-1a4950e10e7e','過臨平蓮蕩四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蓮蕩層層鏡樣方，春來嫩玉斬新光。',32,'全唐诗/poet.song.141000.json','["蓮蕩層層鏡樣方，春來嫩玉斬新光。", "角頭一一張蘆箔，不遣魚蝦過別塘。"]'),
('92b56b55-95f9-4edd-bd7c-3a6d47b01c47','過臨平蓮蕩四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','蓮蕩中央劣露沙，上頭便著野人家。',32,'全唐诗/poet.song.141000.json','["蓮蕩中央劣露沙，上頭便著野人家。", "籬邊隨處插垂柳，簷下小船縈釣車。"]'),
('c7ae3bdb-8271-48b3-a903-256497b07b72','過臨平蓮蕩四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','朝來採藕夕來漁，水種菱荷岸種蘆。',32,'全唐诗/poet.song.141000.json','["朝來採藕夕來漁，水種菱荷岸種蘆。", "寒浪落時分作蕩，新流漲後合成湖。"]'),
('1fd39325-f05e-40af-8925-84d026269f21','過臨平蓮蕩四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','人家星散水中央，十里芹羹菰飯香。',32,'全唐诗/poet.song.141000.json','["人家星散水中央，十里芹羹菰飯香。", "想得薰風端午後，荷花世界柳絲鄉。"]'),
('eaf7eb04-e631-4019-a916-9ead10e46a97','藏船屋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','望見官旗銜舳艫，漁船爭入沼中蘆。',32,'全唐诗/poet.song.141000.json','["望見官旗銜舳艫，漁船爭入沼中蘆。", "藏船蘆底猶有雨，屋底藏船雨也無。"]'),
('cdf17f3c-de66-499d-84f0-74ff3779b2f3','藏船屋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','非港非溝別一涯，茅簷元不是人家。',32,'全唐诗/poet.song.141000.json','["非港非溝別一涯，茅簷元不是人家。", "不居黔首居青雀，動地風濤不到它。"]'),
('d9b888ec-1a29-48fd-992b-439bb3941eb9','岸樹二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','岸頭樹子直如筠，誰遣相招住水濱。',32,'全唐诗/poet.song.141000.json','["岸頭樹子直如筠，誰遣相招住水濱。", "不合鏡中貪照影，照來照去總斜身。"]'),
('de3d7061-0d68-463e-89a1-869950eb7d3d','岸樹二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','岸樹枝枝秃影中，雪風一半半春風。',32,'全唐诗/poet.song.141000.json','["岸樹枝枝秃影中，雪風一半半春風。", "楝梢落盡黄金彈，猶有紛紛綴彈茸。"]'),
('1e43032b-a31c-4642-aa0e-e8a32353eb1b','麥田','楊萬里','宋','宋诗','song-poetry','','[]','無邊綠錦織雲機，全幅青羅作地衣。',32,'全唐诗/poet.song.141000.json','["無邊綠錦織雲機，全幅青羅作地衣。", "個是農家真富貴，雪花銷盡麥苗肥。"]'),
('6b5b3c0e-32a0-4fc3-a6bb-fd6dee3dfda9','桑疇','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夾岸瀕河種穉桑，春風吹出萬條長。',32,'全唐诗/poet.song.141000.json','["夾岸瀕河種穉桑，春風吹出萬條長。", "船行老眼渾多忘，喚作西湖插拒霜。"]'),
('0780a8ee-8f2b-4ef9-bc70-0665bc62e131','竹林','楊萬里','宋','宋诗','song-poetry','','[]','珍重人家愛竹林，織籬辛苦護寒青。',32,'全唐诗/poet.song.141000.json','["珍重人家愛竹林，織籬辛苦護寒青。", "那知竹性元薄相，須要穿來籬外生。"]'),
('cdadb599-b17d-416a-bab3-14bb2595ee16','賦金盤露椒花雨','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','金盤夜貯雲表露，椒花曉滴山間雨。',96,'全唐诗/poet.song.141000.json','["金盤夜貯雲表露，椒花曉滴山間雨。", "一涓不用鴨綠波，雙清釀出鵝黄乳。", "老妻知我憎官壺，還家小槽壓真珠。", "江西擔取來西湖，遣我醉倒不要扶。", "更携數尊往淮上，要誇親舊嘗家釀。", "祗堪獨酌不堪分，老夫猶要入脩門。"]'),
('7efec547-7d2a-4da8-8cfb-1b2224f7d488','崇德道中望福嚴寺','楊萬里','宋','宋诗','song-poetry','','[]','一徑青松露，三門白水煙。',48,'全唐诗/poet.song.141000.json','["一徑青松露，三門白水煙。", "殿橫林外脊，塔漏隙中天。", "地曠迎先見，村移眺更妍。", "追程坐行役，不得泊春船。"]'),
('ee0aa663-0964-4042-bb8c-09fc0f2be38a','岸柳','楊萬里','宋','宋诗','song-poetry','','[]','柳梢拂入溪雲陰，柳根插入溪水深。',64,'全唐诗/poet.song.141000.json','["柳梢拂入溪雲陰，柳根插入溪水深。", "祗今立岸一弊帚，歸時弄日千黄金。", "人生榮謝亦如此，謝何足怨榮何喜。", "秋霜春雨自四時，老夫問柳柳不知。"]'),
('66aeb296-182d-4c7c-b4a2-a6be7bb9658f','春菜','楊萬里','宋','宋诗','song-poetry','','[]','雪白蘆菔非蘆菔，喫來自是辣底玉。',164,'全唐诗/poet.song.141000.json','["雪白蘆菔非蘆菔，喫來自是辣底玉。", "花葉蔓菁非蔓菁，喫來自是甜底冰。", "三館宰夫傳食籍，野人蔬譜渠不識。", "用醯不用酸，用鹽不用鹹。", "鹽醯之外別有味，薑牙棖子仍相參。", "不甑亦不釜，非蒸亦非煮。", "壞盡蔬中腴，乃以煙火故。", "霜根雪葉細縷來，瓷瓶夕羃朝即開。", "貴人我知不官樣，肉食我知無骨相。", "祗合南溪嚼菜根，一尊徑醉溪中雲。", "此詩莫讀恐嚥殺，要讀此詩先捉舌。"]'),
('31239bbe-8e63-4fcb-8505-1fa1e7735e6d','過平望','楊萬里','宋','宋诗','song-poetry','','[]','望中不著一山遮，四顧平田接水涯。',64,'全唐诗/poet.song.141000.json','["望中不著一山遮，四顧平田接水涯。", "柳樹行中分港汊，竹林多處聚人家。", "風將春色歸沙草，天放晴光入浪花。", "午睡起來情緒惡，急呼蟹眼瀹龍牙。"]'),
('dc4b904c-69db-46ef-976f-58bf9000a6b4','合路馬坊年年四月殿前諸軍牧馬於此十月復歸都下','楊萬里','宋','宋诗','song-poetry','','[]','地迥湖寬春草酥，年年此地牧天駒。',64,'全唐诗/poet.song.141000.json','["地迥湖寬春草酥，年年此地牧天駒。", "玉花驄裏龍歸去，金粟堆前鳥自呼。", "苑廄尚虛三萬柱，柳林集得許多烏。", "即今未有王良眼，山子飛黄豈是無。"]'),
('6d47de3b-c5bd-4ee1-8846-4369bcf3f26b','過鶑鬬湖三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','畫舫如山水上奔，小船似鴨避河濱。',32,'全唐诗/poet.song.141000.json','["畫舫如山水上奔，小船似鴨避河濱。", "紅旗青蓋鳴鉦處，都是迎來送往人。"]'),
('180f5cf7-484b-4ae4-a21b-18038fa56a27','過鶑鬬湖三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','忽聞江上四驩呼，知近吳江鶑鬭湖。',32,'全唐诗/poet.song.141000.json','["忽聞江上四驩呼，知近吳江鶑鬭湖。", "火炬燈籠不須辦，使家行住按程塗。"]'),
('eca70302-fc21-4a50-8ce6-6adac5236703','過鶑鬬湖三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','春來已自兩旬餘，欲借春看未見渠。',32,'全唐诗/poet.song.141000.json','["春來已自兩旬餘，欲借春看未見渠。", "煙樹隔湖三十里，寒梢依舊向人疎。"]'),
('dae66bb2-dc9e-415c-8834-7acb6b5c7b29','晚寒題水仙花并湖山三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','水仙怯暖愛清寒，兩日微暄嬾欲眠。',32,'全唐诗/poet.song.141000.json','["水仙怯暖愛清寒，兩日微暄嬾欲眠。", "料峭晚風人不會，留花且住伴詩仙。"]'),
('1c557a69-dfad-4d6a-8186-22c30da34b5b','晚寒題水仙花并湖山三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水面無風也自寒，船門已幕更深關。',32,'全唐诗/poet.song.141000.json','["水面無風也自寒，船門已幕更深關。", "莫將若下三杯酒，博與湖邊幾點山。"]'),
('e32bfd2d-c38c-4313-a8f9-4df67f66cde2','晚寒題水仙花并湖山三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','鍊句爐槌豈可無，句成未必盡緣渠。',32,'全唐诗/poet.song.141000.json','["鍊句爐槌豈可無，句成未必盡緣渠。", "老夫不是尋詩句，詩句自來尋老夫。"]'),
('c96fb5f9-b1cf-49b3-b239-87b1cec1234a','月夜阻風泊舟太湖石塘南頭四首  其一','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','到得松江每不欣，何曾晴快遇清真。',64,'全唐诗/poet.song.141000.json','["到得松江每不欣，何曾晴快遇清真。", "此行作意追勝境，入夜阻風還悶人。", "萬里青天一輪月，三更雪浪太湖春。", "若教白日來經此，不見新鎔萬頃銀。"]'),
('89d437e8-ef53-44dc-9674-b6fa0aa965c8','月夜阻風泊舟太湖石塘南頭四首  其二','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','動地顛風政打頭，吳江未到且維舟。',64,'全唐诗/poet.song.141000.json','["動地顛風政打頭，吳江未到且維舟。", "五湖波起衆山動，一片月明千里愁。", "且更放遲些子睡，看它盛怒幾時休。", "陽侯要與詩人敵，未必詩人輸一籌。"]'),
('f2098015-0ab6-46a3-8b75-707ca63ef129','月夜阻風泊舟太湖石塘南頭四首  其三','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','過湖未得匹如閑，何幸湖心泊畫船。',64,'全唐诗/poet.song.141000.json','["過湖未得匹如閑，何幸湖心泊畫船。", "宇宙中間都是月，波濤外面更無天。", "誰知造物將奇觀，不與傖人付謫仙。", "管領渠儂無一物，鏤冰剪雪作新篇。"]'),
('de7e765d-b192-4c88-b557-a8bd56dcdb8c','月夜阻風泊舟太湖石塘南頭四首  其四','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','新年乘興看春風，來過垂虹東復東。',64,'全唐诗/poet.song.141000.json','["新年乘興看春風，來過垂虹東復東。", "誰有工夫寒夜底，獨尋水月五湖中。", "今宵頓覺乾坤大，下筆惟愁造化窮。", "太白青山謝公海，可憐一笑偶然同。"]'),
('3b956a7d-b41d-4a1c-b835-cd06b339c6c9','題吳江三高堂 范蠡','楊萬里','宋','宋诗','song-poetry','','[]','霸越亡吳未害仁，不妨報國併酬身。',64,'全唐诗/poet.song.141000.json','["霸越亡吳未害仁，不妨報國併酬身。", "風雲長頸無遺恨，雪月扁舟更絕塵。", "還了君王採香徑，須饒老子苧羅人。", "鴟夷若是真高士，張陸何堪作近鄰。"]'),
('ba2be1fa-6cb6-401d-b3bf-ab0e19c70cff','題吳江三高堂 張季鷹','楊萬里','宋','宋诗','song-poetry','','[]','京洛緇塵點素衣，秋風日夕喚人歸。',64,'全唐诗/poet.song.141000.json','["京洛緇塵點素衣，秋風日夕喚人歸。", "鱸魚不解疎張翰，羊酪偏能留陸機。", "二晉興亡幾春草，三吳人物尚漁磯。", "空令千古華亭鶴，猶爲諸賢說是非。"]'),
('3b36df78-17be-4e80-8372-7563ecadc18f','題吳江三高堂 陸魯望','楊萬里','宋','宋诗','song-poetry','','[]','讀盡詩書不要官，饑寒欲死豈無田。',64,'全唐诗/poet.song.141000.json','["讀盡詩書不要官，饑寒欲死豈無田。", "生憎俗子慵開眼，逢著詩人便絕絃。", "笠澤弁山三益友，筆床茶竈一魚船。", "羨渠赤脚弄明月，踏破五湖光底天。"]'),
('82d17498-9275-4d03-9ee2-2a22a4a61d6e','松江曉晴','楊萬里','宋','宋诗','song-poetry','','[]','昨夜何緣不峭寒，今晨端要放晴天。',64,'全唐诗/poet.song.141000.json','["昨夜何緣不峭寒，今晨端要放晴天。", "窗間波日如樓上，簾外霜風似臘前。", "近水人家隨處好，上春物色不勝妍。", "歸時二月三吳路，桃杏香中慢過船。"]'),
('f35eb831-042c-4459-b12a-40889248d11b','松江鱸魚','楊萬里','宋','宋诗','song-poetry','','[]','鱸出鱸鄉蘆葉前，垂虹亭上不論錢。',64,'全唐诗/poet.song.141000.json','["鱸出鱸鄉蘆葉前，垂虹亭上不論錢。", "買來玉尺如何短，鑄出銀梭直是圓。", "白質黑章三四點，細鱗巨口一雙鮮。", "秋風想見真風味，祗是春風已迥然。"]'),
('ee6b02d3-5d75-49ba-91e8-649302e9a31e','松江蓴菜','楊萬里','宋','宋诗','song-poetry','','[]','鮫人直下白龍潭，割得龍公滑碧髯。',64,'全唐诗/poet.song.141000.json','["鮫人直下白龍潭，割得龍公滑碧髯。", "曉起相傳蕊珠闕，夜來失却水精簾。", "一杯淡煮宜醒酒，千里何須更下鹽。", "可是士衡殺風景，却將羶膩比清纖。"]'),
('9a31b884-e81c-4084-bb88-c5cc0a3caeb7','泊平江百花洲','楊萬里','宋','宋诗','song-poetry','','[]','吳中好處是蘇州，却爲王程得勝游。',64,'全唐诗/poet.song.141000.json','["吳中好處是蘇州，却爲王程得勝游。", "半世三江五湖棹，十年四泊百花洲。", "岸傍楊柳都相識，眼底雲山苦見留。", "莫怨孤舟無定處，此身自是一孤舟。"]'),
('b6979b82-cea9-4725-bbe2-9fbce739aee2','姑蘇館夜雪','楊萬里','宋','宋诗','song-poetry','','[]','昨朝晴色動春熙，入夜星河弄碧漪。',64,'全唐诗/poet.song.141000.json','["昨朝晴色動春熙，入夜星河弄碧漪。", "誰信雪花能樣巧，等它人睡不教知。", "起來紅日恍開霽，照得玉花光陸離。", "歸去中都說奇事，姑蘇館裏上元時。"]'),
('0c2debb2-f4df-4c0d-86b0-b94bf4e44707','姑蘇館上元前一夕觀燈','楊萬里','宋','宋诗','song-poetry','','[]','茂苑元宵亦盛哉，千紅百紫雪中開。',64,'全唐诗/poet.song.141000.json','["茂苑元宵亦盛哉，千紅百紫雪中開。", "牡丹自是吳門有，蓮莟移從都下來。", "光射瑠璃最精彩，吐成蝃蝀貫昭回。", "歸船尚有殘燈在，更與兒曹飲一杯。"]'),
('21e15a8e-918d-4b4f-b99a-7756202790e6','走筆和袁起巖元夕前一夜雪作','楊萬里','宋','宋诗','song-poetry','','[]','天公極意辦元宵，頃刻挼雲作雪飄。',64,'全唐诗/poet.song.141000.json','["天公極意辦元宵，頃刻挼雲作雪飄。", "茂苑長洲花剪玉，蘇臺香徑砌成瑶。", "千燈剩喜開紅藥，兩鬢還驚插素標。", "客子孤舟寒折骨，無端詩伯苦相撩。"]'),
('c6c73f60-58e3-42fb-9ba3-ecf4ac1d6e44','再和袁起巖韻','楊萬里','宋','宋诗','song-poetry','','[]','一歲驩聲沸此宵，游人麗服正飄飄。',64,'全唐诗/poet.song.141000.json','["一歲驩聲沸此宵，游人麗服正飄飄。", "病夫未暇磚引玉，惡語翻成李報瑶。", "天遣素娥提雪月，江涵公子更風標。", "君家道是關門卧，却有新詩來見撩。"]'),
('e8143c87-7b1c-404c-bf95-f34f4b705679','雪中登姑蘇臺','楊萬里','宋','宋诗','song-poetry','','[]','我亦閑來散病身，游人不用避車塵。',64,'全唐诗/poet.song.141000.json','["我亦閑來散病身，游人不用避車塵。", "插天四塔雲中出，隔水諸峰雪後新。", "道是遠瞻三百里，如何不見六千人。", "吳亡越霸今安在，臺下年年花草春。"]'),
('d5e66309-52d3-44b7-a82e-4a9b9d07bece','姑蘇館上元前一夕陪使客觀燈之集','楊萬里','宋','宋诗','song-poetry','','[]','節物催人又一年，銀花蓮炬照金尊。',64,'全唐诗/poet.song.141000.json','["節物催人又一年，銀花蓮炬照金尊。", "麝䭔官樣陪公讌，粉繭鄉風憶故園。", "何似兒孫談草草，不妨燈火半昏昏。", "人生行止誰能料，今夕蘇州看上元。"]'),
('e765e5ba-7582-449b-bf2a-2f701821ae1b','雪後陪使客游惠山寄懷尤延之','楊萬里','宋','宋诗','song-poetry','','[]','已到蘇州未到常，惠山孤秀蔚蒼蒼。',64,'全唐诗/poet.song.141000.json','["已到蘇州未到常，惠山孤秀蔚蒼蒼。", "一峰飛下如奔馬，萬木深圍古道場。", "錫骨中空都是乳，玉泉致遠久偏香。", "眠雲跂石梁溪叟，恨殺風煙隔草堂。"]'),
('03276db2-270b-4003-80a7-b27f455291ac','惠泉分茶示正孚長老','楊萬里','宋','宋诗','song-poetry','','[]','寒泓不到十餘年，老眼重看意惘然。',64,'全唐诗/poet.song.141000.json','["寒泓不到十餘年，老眼重看意惘然。", "漱裂蒼崖玉龍口，墮成清鏡雪花天。", "須煩佛界三昧手，拈出茶經第二泉。", "珍重贊公驚久別，且談詩句未談禪。"]'),
('b7d15cf3-74c4-4da7-8711-18bd0041f39e','回望惠山','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','惠山分明龍樣活，玉脊瓊腰百千折。',64,'全唐诗/poet.song.141000.json','["惠山分明龍樣活，玉脊瓊腰百千折。", "錫泉泉上吐一珠，簸弄太湖波底月。", "蒼石爲角松爲鬚，鬚裏黄金古佛廬。", "請君更向潘葑看，龍尾繳到珠南畔。"]'),
('a8488979-84fa-4b72-91a3-07fe36f4bc3e','題陸子泉上祠堂','楊萬里','宋','宋诗','song-poetry','','[]','先生喫茶不喫肉，先生飲泉不飲酒。',104,'全唐诗/poet.song.141000.json','["先生喫茶不喫肉，先生飲泉不飲酒。", "饑寒祗忍七十年，萬歲千秋名不朽。", "惠泉遂名陸子泉，泉與陸子名俱傳。", "一瓣佛香炷遺像，幾多衲子拜茶仙。", "麒麟圖畫冷似鐵，凌煙冠劍消如雪。", "惠山成塵惠泉竭，陸子祠堂始應歇，山上泉中一輪月。"]'),
('86e421fd-495e-4cf1-ac37-337e7f56b49d','過洛社望南湖暮景三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','南湖隔水見漁燈，雁落蘆汀八字橫。',32,'全唐诗/poet.song.141000.json','["南湖隔水見漁燈，雁落蘆汀八字橫。", "對面雙峰煙雨裏，雙峰外面是宜興。"]'),
('480cc67b-6ff6-4692-b886-a62fb3b711d0','過洛社望南湖暮景三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','暮煙如雨雨如煙，一把珠簾隔遠山。',32,'全唐诗/poet.song.141000.json','["暮煙如雨雨如煙，一把珠簾隔遠山。", "簾影漸濃山漸淡，恍然移入畫屏間。"]'),
('f73521f1-1a55-42a2-a64d-4532b208e8e7','過洛社望南湖暮景三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一陣南風似箭來，蒲帆飛上最高桅。',32,'全唐诗/poet.song.141000.json','["一陣南風似箭來，蒲帆飛上最高桅。", "兩邊岸柳都奔走，不及追船各自回。"]'),
('4bb6af45-23c0-469c-9a0f-b40cc3d153c3','舟中元夕雨作三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','道是今宵好上元，新晴白晝雨黄昏。',32,'全唐诗/poet.song.141000.json','["道是今宵好上元，新晴白晝雨黄昏。", "紅燈皎月儂無用，關上船門倒一尊。"]'),
('4987a0d4-91cd-4230-b5ce-b6a7289cc836','舟中元夕雨作三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','佳辰三五是今宵，恰則今宵細雨飄。',32,'全唐诗/poet.song.141000.json','["佳辰三五是今宵，恰則今宵細雨飄。", "天念孤舟人寂寞，不教月色故相撩。"]'),
('2cda8d8d-8cd8-4807-8e29-ae7031a6b54e','舟中元夕雨作三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','此生萬事有期程，多取拋饒竟不曾。',32,'全唐诗/poet.song.141000.json','["此生萬事有期程，多取拋饒竟不曾。", "誰遣夜來南館裏，千花預借上元燈。"]'),
('772bca5d-138b-4bf6-98fa-c60b034eaa85','夜過五牧','楊萬里','宋','宋诗','song-poetry','','[]','船頭更鼓打兩聲，如何未到常州城。',64,'全唐诗/poet.song.141000.json','["船頭更鼓打兩聲，如何未到常州城。", "道旁火炬如晝明，道上牽夫如蟻行。", "今宵到得荆溪館，我欲眠時夜還短。", "明朝擁被窺船窗，百尺柳條垂兩岸。"]'),
('8c4267db-5827-4858-94f2-ea68482f0ae6','明發荆溪館下','楊萬里','宋','宋诗','song-poetry','','[]','常州太守曾獨弄，回首向來真一夢。',80,'全唐诗/poet.song.141000.json','["常州太守曾獨弄，回首向來真一夢。", "五月炎天十月寒，東亭迎客西亭送。", "自從別却翟家園，豈謂三經金斗門。", "莫教物色有欠處，剩與新詩三五句。", "猶有歸塗更一來，是時百花開未開。"]'),
('a0a36504-e929-437b-b175-05a60b30cee5','戲題岸柳','楊萬里','宋','宋诗','song-poetry','','[]','斫盡江邊楊柳梢，要教新歲換新條。',32,'全唐诗/poet.song.141000.json','["斫盡江邊楊柳梢，要教新歲換新條。", "老夫也鑷霜鬚鬢，鑷却霜根出雪苗。"]'),
('9ab1a9d2-f5df-4123-9d68-bd414749690a','舟中即事','楊萬里','宋','宋诗','song-poetry','','[]','阿翁阿囝自相隨，賞徧江淮春盛時。',64,'全唐诗/poet.song.141000.json','["阿翁阿囝自相隨，賞徧江淮春盛時。", "熊白同嘗臘前酒，雌黄自改曉間詩。", "醉來忽笑天地窄，老去那能兒女悲。", "身後昇沉各何有，到頭誰黠復誰癡。"]'),
('58ad9e59-8186-4c79-bbb2-44964278fb69','雨中過沙灘二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','常州草蟲天下無，可憐枉却許工夫。',32,'全唐诗/poet.song.141000.json','["常州草蟲天下無，可憐枉却許工夫。", "濛濛拂拂沙灘艇，別是荆溪煙雨圖。"]'),
('26bb3789-2d7c-4051-8096-2b8051d543e9','雨中過沙灘二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','煙雨新圖學不成，煙能明晦雨能聲。',32,'全唐诗/poet.song.141000.json','["煙雨新圖學不成，煙能明晦雨能聲。", "莫教一點春風起，卷盡空濛寫晚晴。"]'),
('4f485f95-736c-4c1a-8823-be33b5c23305','小舟','楊萬里','宋','宋诗','song-poetry','','[]','豎起青篙便是桅，片帆掛了即帆開。',32,'全唐诗/poet.song.141000.json','["豎起青篙便是桅，片帆掛了即帆開。", "漁郎袖手船頭坐，一葉如飛不用催。"]'),
('fcf834fd-b258-4957-af6f-eb348008836c','微雨','楊萬里','宋','宋诗','song-poetry','','[]','要知微雨密還疎，空裏看來直是無。',32,'全唐诗/poet.song.141000.json','["要知微雨密還疎，空裏看來直是無。", "不被波間三兩點，阿誰見破妙工夫。"]'),
('c598aa6f-957c-4673-ba33-7749e3671df7','過奔牛閘','楊萬里','宋','宋诗','song-poetry','','[]','春雨未多河未漲，閘官惜水如金樣。',96,'全唐诗/poet.song.141000.json','["春雨未多河未漲，閘官惜水如金樣。", "聚船久住下河灣，等待船齊不教放。", "忽然三板兩板開，驚雷一聲飛雪堆。", "衆船遏水水不去，船底怒濤跳出來。", "下河半篙水欲滿，上河兩平勢差緩。", "一行二十四樓船，相隨過閘如魚貫。"]'),
('cbc3935a-ae3f-4b14-8cb6-90e64605ea16','蘭花五言','楊萬里','宋','宋诗','song-poetry','','[]','護雨重重膜，凌霜早早春。',48,'全唐诗/poet.song.141000.json','["護雨重重膜，凌霜早早春。", "三菲碧彈指，一笑紫翻唇。", "野竹元同操，官梅晚卜鄰。", "花中不兒女，格外更幽芬。"]'),
('fc0da43c-971e-4559-bd98-312288d20909','次韻寄題馬少張致政亦樂園','楊萬里','宋','宋诗','song-poetry','','[]','亦樂園將獨樂園，兩園誰窄復誰寬。',64,'全唐诗/poet.song.141000.json','["亦樂園將獨樂園，兩園誰窄復誰寬。", "似聞閭里溪深處，下有蛟龍水底蟠。", "黄帽已捐蒼玉佩，朱顔不借紫金丹。", "刺桐花發梅花落，安得乘風去一觀。"]'),
('cef94578-099c-406e-9b53-27797fa5eeef','高郵野望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','望中四野掌般平，遠樹成行一带橫。',32,'全唐诗/poet.song.141000.json','["望中四野掌般平，遠樹成行一带橫。", "樹外天容仍淡白，不愁樹影不分明。"]'),
('cc79ee78-dfab-44b9-99a1-95d2be53dde1','高郵野望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江南十里九青山，江北無山只野田。',32,'全唐诗/poet.song.141000.json','["江南十里九青山，江北無山只野田。", "更遣野田無遠樹，郭熙儘巧若爲傳。"]'),
('b19f09d9-8138-4e75-925f-8958be601356','過新開湖五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','奇哉萬頃水精盆，一線青羅緣却唇。',32,'全唐诗/poet.song.141000.json','["奇哉萬頃水精盆，一線青羅緣却唇。", "只有向南接天去，更和一線也無痕。"]'),
('42943a58-ec1a-4803-90be-c2d6f8e3bcd6','過新開湖五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','漁郎艇子入重湖，老眼殷勤看著渠。',32,'全唐诗/poet.song.141000.json','["漁郎艇子入重湖，老眼殷勤看著渠。", "看去看來成怪事，化爲獨雁立橫蘆。"]'),
('710be9e9-1342-45a9-a6a7-1552c9474521','過新開湖五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','白葦黄蘆尚带秋，長風遠水幾時休。',32,'全唐诗/poet.song.141000.json','["白葦黄蘆尚带秋，長風遠水幾時休。", "愁人對著君休問，不是愁人也作愁。"]'),
('be0044e5-92ff-48d2-91ef-db3c8e75f9c7','過新開湖五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','一鷗得得隔湖來，瞥見魚兒眼頓開。',32,'全唐诗/poet.song.141000.json','["一鷗得得隔湖來，瞥見魚兒眼頓開。", "只爲水深難立脚，翩然飛下却飛回。"]'),
('cdb2059a-61ca-4b45-8f4a-b30547ff6885','過新開湖五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','遠遠人煙點樹梢，船門一望一魂消。',32,'全唐诗/poet.song.141000.json','["遠遠人煙點樹梢，船門一望一魂消。", "幾行野鴨數聲雁，來爲湖天破寂寥。"]'),
('b701247b-35f2-42b6-9c65-cfc22a009633','瓦店雨作四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','斜風吹雨打船窗，一陣疎來一陣忙。',32,'全唐诗/poet.song.141000.json','["斜風吹雨打船窗，一陣疎來一陣忙。", "聽作山齋聲點滴，不知作客在山陽。"]'),
('e9b092e7-47af-4b6f-bc4f-795aeed70141','瓦店雨作四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','天嫌平野樹分明，便恐丹青畫得成。',32,'全唐诗/poet.song.141000.json','["天嫌平野樹分明，便恐丹青畫得成。", "收入晚風煙雨裏，自將水墨替丹青。"]'),
('0ebbba27-7d16-4355-9b33-1fd8fe9580af','瓦店雨作四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','詩人長怨沒詩材，天遣斜風細雨來。',32,'全唐诗/poet.song.141000.json','["詩人長怨沒詩材，天遣斜風細雨來。", "領了詩材還又怨，問天風雨幾時開。"]'),
('4e9c222f-b884-4d55-971d-459e8d29b858','瓦店雨作四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','近岸人家欲閉門，遠林煙樹半昏昏。',32,'全唐诗/poet.song.141000.json','["近岸人家欲閉門，遠林煙樹半昏昏。", "鸕鷀白鷺歸何晚，今夜定投何處村。"]'),
('27809088-941e-42b2-9588-554375d92124','曉出洪澤霜晴風順','楊萬里','宋','宋诗','song-poetry','','[]','又從洪澤泝清淮，積雨連宵曉頓開。',64,'全唐诗/poet.song.141000.json','["又從洪澤泝清淮，積雨連宵曉頓開。", "霜凍水涯如雪厚，波摇日影入船來。", "辛勤送客了未了，珍重順風催復催。", "明早都梁各分手，順風便借一帆回。"]'),
('9a743d9b-a60c-48a4-b7a9-3bf47d5d2aee','題龜山塔前一首唐律後一首進退格  其一','楊萬里','宋','宋诗','song-poetry','','[]','龜山獨出壓淮流，寶塔仍居最上頭。',64,'全唐诗/poet.song.141000.json','["龜山獨出壓淮流，寶塔仍居最上頭。", "銀筆書空天作紙，玉龍拔地海成湫。", "向來一厄遭羣犬，挽以六丁兼萬牛。", "逆血腥羶化爲碧，空餘風雨鬼啾啾。"]'),
('a57f3d95-8953-434a-83d0-3a3520341517','題龜山塔前一首唐律後一首進退格  其二','楊萬里','宋','宋诗','song-poetry','','[]','舊歲新年來往頻，孤標數面便多情。',64,'全唐诗/poet.song.141000.json','["舊歲新年來往頻，孤標數面便多情。", "獨將白髮三千丈，上到瑶臺十二層。", "萬里海風吹不動，半輪淮月爲誰明。", "東坡舊跡無尋處，試問龕中錦帽僧。"]'),
('19a34ca4-65a1-4297-abd0-aa7404136555','薌林五十詠 薌林','楊萬里','宋','宋诗','song-poetry','','[]','一代薌林老，吾生不並時。',24,'全唐诗/poet.song.141000.json','["一代薌林老，吾生不並時。", "來尋白玉柄，祗見紫蘭枝。"]'),
('2ce5b6d0-92ce-47f3-a2e0-b23bc92e18e1','薌林五十詠 虎川','楊萬里','宋','宋诗','song-poetry','','[]','居士欹黄帽，曾來照晚晴。',24,'全唐诗/poet.song.141000.json','["居士欹黄帽，曾來照晚晴。", "至今流㶁㶁，猶學詠詩聲。"]'),
('b58ac329-c521-4455-b07f-d9d2979e4d2e','薌林五十詠 歸來橋','楊萬里','宋','宋诗','song-poetry','','[]','已賡彭澤辭，更擬輞川詩。',24,'全唐诗/poet.song.141000.json','["已賡彭澤辭，更擬輞川詩。", "未老還山了，猶嫌歸較遲。"]'),
