('6f1b50d4-585f-4022-abf6-300bf0583a04','薌林五十詠 瓜田','楊萬里','宋','宋诗','song-poetry','','[]','獨酌聖賢酒，新嘗子母瓜。',24,'全唐诗/poet.song.141000.json','["獨酌聖賢酒，新嘗子母瓜。", "丁寧林下友，莫道故侯家。"]'),
('7e6dff1d-413d-48dc-82df-a9e9e5ac7f07','薌林五十詠 連輝觀','楊萬里','宋','宋诗','song-poetry','','[]','極目斜陽樹，乘風落月梁。',24,'全唐诗/poet.song.141000.json','["極目斜陽樹，乘風落月梁。", "更和山與水，併作一秋光。"]'),
('c59f581e-1ebc-4495-a985-e6de64f56840','瀆頭阻風','楊萬里','宋','宋诗','song-poetry','','[]','天寒春淺蟄未開，船頭一聲出地雷。',144,'全唐诗/poet.song.141000.json','["天寒春淺蟄未開，船頭一聲出地雷。", "老夫驚倒卷簾看，白浪飛從東海來。", "東海復東幾萬里，扶桑頃刻到長淮。", "琉璃地上玉山起，玉山自走非人推。", "似聞海若怒川后，雨師風伯同抽差。", "夜提橫水明光甲，大呼一戰龜山頹。", "老夫送客理歸棹，適逢奇觀亦壯哉。", "豈不懷歸船不進，繫纜古柳依雲堆。", "須臾驚定却成喜，分付客愁金縷杯。"]'),
('a24aea2d-ff8d-4c5e-aa00-781bd3db4073','至洪澤','楊萬里','宋','宋诗','song-poetry','','[]','今宵合過山陽驛，泊船問來是洪澤。',128,'全唐诗/poet.song.141000.json','["今宵合過山陽驛，泊船問來是洪澤。", "都梁到此只一程，却費一宵兼兩日。", "政緣夜來到瀆頭，打頭風起浪不休。", "舟人相賀已入港，不怕淮河更風浪。", "老夫摇手且低聲，驚心猶恐淮神聽。", "急呼津吏催開閘，津吏叉手不敢答。", "早潮已落水入淮，晚潮未來閘不開。", "細問晚潮何時來，更待玉蟲綴金釵。"]'),
('aae3a047-1817-41b2-afa8-fff03886fd61','過淮陰縣','楊萬里','宋','宋诗','song-poetry','','[]','索寞淮陰縣，人家草草中。',48,'全唐诗/poet.song.141000.json','["索寞淮陰縣，人家草草中。", "荻籬緯春勝，茅屋學船篷。", "今日非昨日，南風轉北風。", "霍然香霧散，放出一輪紅。"]'),
('5efa0bb2-9b1f-41d1-874e-bff453e052a7','過磨盤得風掛帆','楊萬里','宋','宋诗','song-poetry','','[]','兩岸黄旗小隊兵，新晴歸路馬蹄輕。',64,'全唐诗/poet.song.141000.json','["兩岸黄旗小隊兵，新晴歸路馬蹄輕。", "全番長笛橫腰鼓，一曲春風出塞聲。", "鵲噪鴉啼俱喜色，船輕風順更兼程。", "却思兩日淮河浪，心悸魂驚尚未平。"]'),
('55640c7e-4a2f-46f9-b865-87b6c1941493','望楚州新城','楊萬里','宋','宋诗','song-poetry','','[]','已近山陽望漸寬，湖光百里見千村。',64,'全唐诗/poet.song.141000.json','["已近山陽望漸寬，湖光百里見千村。", "人家四面皆臨水，柳樹雙垂便是門。", "全盛向來元孔道，雜耕今是一雄藩。", "金湯再葺真長策，此外猶須子細論。"]'),
('4b90c55c-6934-454a-9c39-1ab15fe28c81','阻風泊黄浦','楊萬里','宋','宋诗','song-poetry','','[]','回顧山陽北，前瞻寶應東。',48,'全唐诗/poet.song.141000.json','["回顧山陽北，前瞻寶應東。", "又逢翻手雨，更著打頭風。", "不了行程債，從來賦命窮。", "客愁無訴處，摇指畫船篷。"]'),
('1f050099-6d79-4de6-a0a1-781c77b7588b','過寶應縣新開湖十首  其一','楊萬里','宋','宋诗','song-poetry','','[]','寒裏船門不可開，試開一望興悠哉。',32,'全唐诗/poet.song.141000.json','["寒裏船門不可開，試開一望興悠哉。", "空濛煙雨微茫樹，都向湖光外面來。"]'),
('6878cf64-a20d-4be0-bc89-c5c288a13047','過寶應縣新開湖十首  其二','楊萬里','宋','宋诗','song-poetry','','[]','細雨初如弄隙塵，須臾化作舞空蚊。',32,'全唐诗/poet.song.141000.json','["細雨初如弄隙塵，須臾化作舞空蚊。", "作團面旋還分散，只見輕煙與薄雲。"]'),
('fbb6bf96-7bd8-411e-bb57-bb85113df791','過寶應縣新開湖十首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雨絲拂水不曾沉，一一如珠一一明。',32,'全唐诗/poet.song.141000.json','["雨絲拂水不曾沉，一一如珠一一明。", "亂走不停跳不住，忽然跳入水精瓶。"]'),
('10259d03-1c5d-4148-a412-eb3d5b6be3c4','過寶應縣新開湖十首  其四','楊萬里','宋','宋诗','song-poetry','','[]','漁家可是厭塵囂，結屋圓沙最盡梢。',32,'全唐诗/poet.song.141000.json','["漁家可是厭塵囂，結屋圓沙最盡梢。", "外面更栽楊柳樹，上頭無數鷺鷥巢。"]'),
('406a5396-27b9-49fe-9e58-ea3c98c7e2c4','過寶應縣新開湖十首  其五','楊萬里','宋','宋诗','song-poetry','','[]','湖堤插柳早青葱，猶带隋家舊土風。',32,'全唐诗/poet.song.141000.json','["湖堤插柳早青葱，猶带隋家舊土風。", "莫笑千株尺來許，看渠攬盡夕陽紅。"]'),
('4a4c2717-7683-4b7b-bbc1-69067afb4b3f','過寶應縣新開湖十首  其六','楊萬里','宋','宋诗','song-poetry','','[]','雨裏樓船即釣磯，碧雲便是綠蓑衣。',32,'全唐诗/poet.song.141000.json','["雨裏樓船即釣磯，碧雲便是綠蓑衣。", "滄波萬頃平如鏡，一隻鸕鷀貼水飛。"]'),
('fc11a492-b46a-4ee4-aa80-4272fe7bf88c','過寶應縣新開湖十首  其七','楊萬里','宋','宋诗','song-poetry','','[]','半濃黛汁點遥林，微淡鉛膏抹暮雲。',32,'全唐诗/poet.song.141000.json','["半濃黛汁點遥林，微淡鉛膏抹暮雲。", "似白如青都不是，淮南弄色五湖春。"]'),
('7ec1f42a-669d-4bfe-93fe-f58079ff33cd','過寶應縣新開湖十首  其八','楊萬里','宋','宋诗','song-poetry','','[]','天上雲煙壓水來，湖中波浪打雲回。',32,'全唐诗/poet.song.141000.json','["天上雲煙壓水來，湖中波浪打雲回。", "中間不是平林樹，水色天容拆不開。"]'),
('3c004990-03a2-4553-827d-5e6308073436','過寶應縣新開湖十首  其九','楊萬里','宋','宋诗','song-poetry','','[]','兩隻釣船相對行，釣車自轉不須縈。',32,'全唐诗/poet.song.141000.json','["兩隻釣船相對行，釣車自轉不須縈。", "車停不轉船停處，特地縈車手不停。"]'),
('6d2c44db-e69b-42ce-8c2c-66f5dd840c8f','過寶應縣新開湖十首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','五湖佳處是荒寒，却爲無山水更寬。',32,'全唐诗/poet.song.141000.json','["五湖佳處是荒寒，却爲無山水更寬。", "歸去江南無此景，未須喫飯且來看。"]'),
('46e6b303-7580-44af-9b58-021590f9948b','過九里亭','楊萬里','宋','宋诗','song-poetry','','[]','水渚纔容足，漁家便架椽。',48,'全唐诗/poet.song.141000.json','["水渚纔容足，漁家便架椽。", "屋根些子地，簷外不勝天。", "岸岸皆垂柳，門門一釣船。", "五湖好風月，乞與不論錢。"]'),
('23eead99-290c-42c8-9ab8-573e4439bce7','過楊子橋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','浪說春歸已四旬，淮南元自不知春。',32,'全唐诗/poet.song.141000.json','["浪說春歸已四旬，淮南元自不知春。", "明朝却是中和節，野次誰憐寂寞人。"]'),
('16524f6c-d1b9-4754-a313-9d0b4d49e506','過楊子橋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','客愁滿目政無聊，忽報船經楊子橋。',32,'全唐诗/poet.song.141000.json','["客愁滿目政無聊，忽報船經楊子橋。", "未到江南心已喜，隔江山色碧相招。"]'),
('1411ebfa-5825-417c-a3cb-02b42b408505','瓜州遇風','楊萬里','宋','宋诗','song-poetry','','[]','金鉦三聲船欲發，天地蒼茫忽開闔。',137,'全唐诗/poet.song.141000.json','["金鉦三聲船欲發，天地蒼茫忽開闔。", "惡風吹倒多景樓，怒濤打碎金山塔。", "濤頭拋船入半空，船從空中落水中。", "勢如崩山同日二十九，聲如推墮萬石之簴千石鐘。", "岸人驚呼船欲沒，舟人絕叫船復出。", "平生所聞楊子江，無風已自波相撞。", "莫教風動一波起，三日奔騰收不止。", "君不見逆酋投鞭欲斷流，藁街自送月氏頭。"]'),
('c31f52cc-f255-451c-b336-0619ef81501b','再賦石翁石婆','楊萬里','宋','宋诗','song-poetry','','[]','石翁誰怒猶睅目，石婆多愁鬢先秃。',64,'全唐诗/poet.song.141000.json','["石翁誰怒猶睅目，石婆多愁鬢先秃。", "荒山野水四無人，二老對立今幾春。", "珠襦玉匣化爲土，金雁銀鳬亦飛去。", "知是六朝何帝陵，摩娑碧蘚俱無語。"]'),
('019256db-cbae-404d-8b29-f08ea80798e5','觀張功父南湖海棠杖藜走筆三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','看盡都城種海棠，只將一徑引教長。',32,'全唐诗/poet.song.141000.json','["看盡都城種海棠，只將一徑引教長。", "約齋妙出春風手，人在中央花四傍。"]'),
('f3126fe1-a16e-489c-800b-e4f3641b437d','觀張功父南湖海棠杖藜走筆三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','百株都好却嫌渠，揀中東邊第一株。',32,'全唐诗/poet.song.141000.json','["百株都好却嫌渠，揀中東邊第一株。", "開與未開相間著，濃紅密密淡疎疎。"]'),
('c89be244-f557-4b46-88a4-54faf74d536d','觀張功父南湖海棠杖藜走筆三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','天工信手灑明霞，若遣停勻未必佳。',32,'全唐诗/poet.song.141000.json','["天工信手灑明霞，若遣停勻未必佳。", "却得數株多葉底，殷勤襯出密邊花。"]'),
('deb85ce9-c27d-4c3d-9ad4-47ce1336a173','送薛子約下第歸永嘉','楊萬里','宋','宋诗','song-poetry','','[]','河東鸑鷟志青天，冀北麒麟受玉鞭。',64,'全唐诗/poet.song.141000.json','["河東鸑鷟志青天，冀北麒麟受玉鞭。", "二十年前元脫穎，五千人裏又遺賢。", "請君更草凌雲賦，老我重看斫桂仙。", "趁取春風雙鬢綠，收科誰後復誰先。"]'),
('741d8d27-4ce9-4554-8b30-9ffadc822c76','和張功父榿木巴欖花韻','楊萬里','宋','宋诗','song-poetry','','[]','南湖窠木已交加，種欖栽榿更北涯。',64,'全唐诗/poet.song.141000.json','["南湖窠木已交加，種欖栽榿更北涯。", "生眼錯呼爲夜合，新鶑知不是桃花。", "綠陰四合藏雲屋，翠浪全機織素紗。", "桂隠主人臞見骨，不餐酥酪却餐茶。"]'),
('efe9693d-266f-4f06-a1dc-2fc336caec31','走筆謝張功父送似酴醾','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖野僧誇藏冰，半年化作真水精。',200,'全唐诗/poet.song.141000.json','["西湖野僧誇藏冰，半年化作真水精。", "南湖詩人笑渠拙，不如儂家解乾雪。", "藏冰窨子山之幽，鑱透九地山鬼愁。", "儂家藏雪有妙手，分明曬在翡翠樓。", "向來巽二拉滕六，玉妃夜投玉川屋。", "剪水作花吹朔風，揉雲爲粉散寒空。", "醉揮兩袖拂銀漢，梢頭萬斛冷不融。", "瓊田挈月拾翠羽，砌成重樓天半許。", "盤作青蛟吐綠霧，亂飄六出薰沉炷。", "人間雪脆那可藏，天上雪落何曾香。", "三月盡頭四月首，南湖香雪今誰有，分似誠齋老詩叟。", "碎挼玉花泛春酒，一飲一石更五斗。"]'),
('cdce144d-bbb9-48ae-9297-a054d741306d','和祝汝玉作舉子語之句','楊萬里','宋','宋诗','song-poetry','','[]','玉奴何必減花奴，省識春風作畫圖。',64,'全唐诗/poet.song.141000.json','["玉奴何必減花奴，省識春風作畫圖。", "臨水隔花看走馬，翻身射雁落彫弧。", "詞場君擅傾城色，詩社儂凋覓句鬚。", "摩壘致師仰餘勇，政慚連叔答肩吾。"]'),
('56a1f658-c547-4723-bbb0-23cecb4dbb2a','和徐盈贈詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','不謁長安衆富兒，不隨舉子脫麻衣。',32,'全唐诗/poet.song.141000.json','["不謁長安衆富兒，不隨舉子脫麻衣。", "片雲出岫元無事，催我詩成翻手歸。"]'),
('739d8f74-cbb6-4216-9c52-2293881d03b0','和徐盈贈詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','無鬼玄談彫苦空，端能問字過楊雄。',32,'全唐诗/poet.song.141000.json','["無鬼玄談彫苦空，端能問字過楊雄。", "韓琮不生王駕死，乞君明月與清風。"]'),
('9270d351-6930-4139-a0e0-9dea55ef162c','送劉德脩殿院直閣將漕潼川二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','烏府何緣著佞臣，紫皇親擢得斯人。',64,'全唐诗/poet.song.141000.json','["烏府何緣著佞臣，紫皇親擢得斯人。", "金丹半粒回元氣，玉宇崇朝作好春。", "不惜孤身輕一葉，坐令九鼎重千鈞。", "萬牛回首求梁棟，未要沱江理釣緡。"]'),
('cbf27644-6061-44d0-ad5f-8de967b2cec0','送劉德脩殿院直閣將漕潼川二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','半世西風吹盛名，晚同朝路慰平生。',64,'全唐诗/poet.song.141000.json','["半世西風吹盛名，晚同朝路慰平生。", "一言半語到金石，四海九州成弟兄。", "雪嶺錦城君理棹，青鞋黄帽我歸耕。", "長江萬里通吳蜀，逢著雙魚各寄聲。"]'),
('a7deab33-5b6d-4c08-9011-6366d78e0eff','送馬莊父游金陵','楊萬里','宋','宋诗','song-poetry','','[]','東華踏徧軟紅塵，却去秦淮釣月輪。',64,'全唐诗/poet.song.141000.json','["東華踏徧軟紅塵，却去秦淮釣月輪。", "朱雀烏衣王謝宅，黄旗紫蓋晉梁春。", "江山拾得風光好，杖屨歸來句子新。", "祗恐參卿署軍事，醲薰薦墨到槐宸。"]'),
('e5b22c61-a2e8-4e71-9b2d-bedef13720c7','跋吳箕秀才詩卷','楊萬里','宋','宋诗','song-poetry','','[]','君家子華翰林老，解吟芳草夕陽愁。',116,'全唐诗/poet.song.141000.json','["君家子華翰林老，解吟芳草夕陽愁。", "開紅落翠天爲泣，覆手作春翻手秋。", "晚唐異味今誰嗜，耳孫下筆參差是。", "一徑芙蓉十萬枝，喚作春風二月時。", "旁人笑渠眼花恐落井，渠方掉頭得句呼不醒。", "老夫向來守荆溪，郡有詩人元不知。", "贈我連城雜照乘，一夜空齋橫白蜺。"]'),
('9d31bbc4-641b-4bbf-94b9-538b1582291f','記丘宗卿語紹興府學前景','楊萬里','宋','宋诗','song-poetry','','[]','鏡湖泮宮轉街曲，纔隔清溪便無俗。',64,'全唐诗/poet.song.141000.json','["鏡湖泮宮轉街曲，纔隔清溪便無俗。", "竹橋斜度透竹門，牆根一竿半竿竹。", "恰思是間宜看梅，忽然一枝橫出來。", "霜餘皴裂臂來大，只著寒花三兩箇。"]'),
('444d9168-e582-4ca2-8d66-f794759e1513','和御製瓊林宴賜進士余復等詩','楊萬里','宋','宋诗','song-poetry','','[]','聖主臨軒士褎然，曲江花底宴群賢。',64,'全唐诗/poet.song.141000.json','["聖主臨軒士褎然，曲江花底宴群賢。", "九天日月開清照，四海豪英看廣延。", "祗合致君上堯舜，不應侔德止宗宣。", "草萊憂國從今始，記取雲章第一篇。"]'),
('af51c21b-d30d-4e53-9957-f561e8efc64f','送徐宋臣監丞補外','楊萬里','宋','宋诗','song-poetry','','[]','出處何心一似雲，世間萬事不關身。',64,'全唐诗/poet.song.141000.json','["出處何心一似雲，世間萬事不關身。", "補天鍊石無虛日，憂國如家有幾人。", "千載芬香只忠孝，百年富貴竟埃塵。", "看君兩鬢青青在，不晚歸來侍玉宸。"]'),
('e1b7091f-8547-47ef-862a-e68b059c1c16','題瀏陽縣柳仲明致政雲居山書院','楊萬里','宋','宋诗','song-poetry','','[]','雲居山高三萬尺，下插瀏江上撞日。',160,'全唐诗/poet.song.141000.json','["雲居山高三萬尺，下插瀏江上撞日。", "柳下和風百世師，有孫避地來築室。", "奕葉隠居三百年，栽桃種杏今滿川。", "當家相傳一破硯，此外文字九千卷。", "旄頭畢方書散亡，維仲明父再耿光。", "木葉衣裳野蕨腸，牙籤玉軸還堆床。", "更於山下起高閣，竹戶松窗照林壑。", "閣上諸郎夜誦聲，太一真人降雲鶴。", "向來有子中文科，泮宮彈琴詠菁莪。", "柳氏門閭人刮目，仲明依舊一漁蓑。"]'),
('ce79e2bb-d0df-4a5c-a97c-1ebc298259f9','小樓晚眺雲日','楊萬里','宋','宋诗','song-poetry','','[]','小樓掛上綠窗櫺，落日孤雲萬態生。',32,'全唐诗/poet.song.141000.json','["小樓掛上綠窗櫺，落日孤雲萬態生。", "碧玉峰巒白銀緣，峰巒暗處緣偏明。"]'),
('b620c23b-dac8-42a9-9564-5c1b28662712','記丘宗卿嚥冰語','楊萬里','宋','宋诗','song-poetry','','[]','醉嚥冰丸不作難，不須碎嚼不須餐。',32,'全唐诗/poet.song.141000.json','["醉嚥冰丸不作難，不須碎嚼不須餐。", "聽渠歷歷胸中過，一寸詩腸一寸寒。"]'),
('e69ffa02-fde7-485f-ad51-1892aab44701','送李制幹季允擢第歸蜀','楊萬里','宋','宋诗','song-poetry','','[]','玉立長身太史公，諸郎箇箇有家風。',64,'全唐诗/poet.song.141000.json','["玉立長身太史公，諸郎箇箇有家風。", "高文大冊傳書種，怨句愁吟惱化工。", "鴻雁雙銜月宮桂，鵷雛獨戀蜀山桐。", "何如天網籠雲表，三鳳都歸上苑中。"]'),
('e233b72d-54ab-4b52-a159-9dbac224e682','林宏才秉義挽辭','楊萬里','宋','宋诗','song-poetry','','[]','行盡江南北，於何隠去休。',48,'全唐诗/poet.song.141000.json','["行盡江南北，於何隠去休。", "福清好雲谷，老子得菟裘。", "風采今千古，英靈閟一丘。", "庭階俱玉樹，仲氏立鼇頭。"]'),
('46a5e890-153e-4383-97c9-70991ff5fa10','題沈子壽旁觀錄','楊萬里','宋','宋诗','song-poetry','','[]','逢著詩人沈竹齋，丁寧有口不須開。',32,'全唐诗/poet.song.141000.json','["逢著詩人沈竹齋，丁寧有口不須開。", "被渠譜入旁觀錄，四馬如何挽得回。"]'),
('bbaf4fb8-ecbb-4974-b304-7e0c2c746df7','送吳敏叔待制侍郎','楊萬里','宋','宋诗','song-poetry','','[]','脚踏雞翹豹尾間，心飛碧岫白雲端。',64,'全唐诗/poet.song.141000.json','["脚踏雞翹豹尾間，心飛碧岫白雲端。", "人看疎傅如圖畫，帝念嚴光返釣灘。", "玉殿松班唐次對，竹宮茅立漢祠官。", "自憐病鶴樊籠底，萬羨冥鴻片影寒。"]'),
('ad497a9d-d948-4c99-b953-89a72ec85dab','寄吳宜之','楊萬里','宋','宋诗','song-poetry','','[]','罨畫溪頭老詩伯，夜榜仙槎鬰林石。',96,'全唐诗/poet.song.141000.json','["罨畫溪頭老詩伯，夜榜仙槎鬰林石。", "要令南斗避文星，却歸北辰捧天極。", "頃逢桂江雙鯉魚，殷勤兩寄尺素書。", "山長水遠到不到，未必韋郎跡也疎。", "書中只有相思字，更及融州一寒士。", "泮水曾參冷似冰，等待春風放桃李。"]'),
('47173f7a-b3ad-4bdf-89da-6cd35d625fd7','和沈子壽還朝天集之韻','楊萬里','宋','宋诗','song-poetry','','[]','愁城不著狂詩客，徑超天外華胥國。',144,'全唐诗/poet.song.141000.json','["愁城不著狂詩客，徑超天外華胥國。", "苦海惟愁熱惱人，別有月中水精域。", "浣花一老已九京，何人再築五言城。", "竹齋衣鉢傳錦里，咄咄雲煙飛落紙。", "胸中磊磈有餘地，語下飄蕭無俗氣。", "詩壇筆陣制中權，勢如常山看率然。", "觀者堵牆顔色沮，驚聞柘彈金盤句。", "老夫性癖耽此趣，被渠夜半赤手取。", "重陽過了元不知，猶有黄花三兩枝。"]'),
('9259ac5f-0075-4125-a026-08c1bdd01663','雨中出湖上送客','楊萬里','宋','宋诗','song-poetry','','[]','細雨輕煙著地昏，湖波真箇解生塵。',32,'全唐诗/poet.song.141000.json','["細雨輕煙著地昏，湖波真箇解生塵。", "浄慈靈隠君休覓，失却諸峰不惱人。"]'),
('f7ccd316-a475-494e-a44c-4b297283ae3e','入北昭慶寺','楊萬里','宋','宋诗','song-poetry','','[]','兩岸芙蓉雨洗粧，愁將紅淚照銀塘。',32,'全唐诗/poet.song.141000.json','["兩岸芙蓉雨洗粧，愁將紅淚照銀塘。", "抬頭不起珠璣重，柳外西風特地狂。"]'),
('abd96bdc-52d3-49c8-8e7b-69fb959f8c00','張幾仲侍郎挽詞三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','半世金閨彥，中年碧落班。',48,'全唐诗/poet.song.141000.json','["半世金閨彥，中年碧落班。", "一般俱紫橐，千古忽青山。", "秋入篇章裏，春生岳牧間。", "汾陽舊部曲，白髮萬人潸。"]'),
('2ea209a6-bd47-414f-9c67-732df5f5676e','張幾仲侍郎挽詞三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','烈考同心德，中興異姓王。',48,'全唐诗/poet.song.141000.json','["烈考同心德，中興異姓王。", "勳勞貫三極，文獻在諸郎。", "公也山林味，天乎日月忙。", "一生非不達，晚達却堪傷。"]'),
('7533178d-48bb-41a2-bd46-17af660864da','張幾仲侍郎挽詞三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','京口連滄觀，洪都孺子亭。',48,'全唐诗/poet.song.141000.json','["京口連滄觀，洪都孺子亭。", "飛觴回落月，灑筆濕寒星。", "別去長離索，歸來遽杳冥。", "知公喜儂句，五字酹英靈。"]'),
('3a9e9872-82bc-42e5-86e5-8ae4a997d4cb','徐氏太淑人挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','三子官期至，同時各致勤。',48,'全唐诗/poet.song.141000.json','["三子官期至，同時各致勤。", "爭迎阿潘母，獨就大馮君。", "喜入烏巢舍，驚傳鶴弔墳。", "傷心是廷尉，目斷太行雲。"]'),
('1a63e933-5727-4fce-9742-fab78006cfd7','徐氏太淑人挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','赤矢生名族，烏衣媲德門。',48,'全唐诗/poet.song.141000.json','["赤矢生名族，烏衣媲德門。", "萱堂登九秩，蘭砌頷重孫。", "樂飲占蛇日，翻隨藥兔魂。", "一生參貝葉，夢幻了無痕。"]'),
('3bfbb6e0-8f3c-4c8c-9a42-cc713068f9de','跋眉山程仁萬言書草','楊萬里','宋','宋诗','song-poetry','','[]','峨眉山下三蘇鄉，至今草木文章香。',131,'全唐诗/poet.song.141000.json','["峨眉山下三蘇鄉，至今草木文章香。", "近時英妙有程郎，數寸管底翻錦江。", "向來曾草三千牘，流涕太息仍痛哭。", "九虎當關北斗深，十年買桂炊白玉。", "荆溪溪上相識初，君猶少年我壯夫。", "帝城再見各白鬚，袖中一紙梁溪書。", "剡藤方策一萬字，猶带權書衡論味。", "君不見古來富貴掃無痕，只有文章照天地。"]'),
('5d6871b9-e589-4850-a8cc-48ea733d454b','題鞏仲至脩辭齋','楊萬里','宋','宋诗','song-poetry','','[]','人道莊周夢蝴蝶，我言蝴蝶夢莊周。',96,'全唐诗/poet.song.141000.json','["人道莊周夢蝴蝶，我言蝴蝶夢莊周。", "莊周解飛蝶解語，說向蝴蝶應點頭。", "脩辭齋中子鞏子，年少詩狂狂到底。", "蹇馿破帽衝達官，白眼清談對餘子。", "東萊一翁印斯人，世人皆憎翁不嗔。", "爲渠落筆三大字，政自不妨詩入神。"]'),
('b29a613e-33fd-4872-ac7a-e38770ffad05','秋夕不寐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','每到炎天只願秋，如何秋到却成愁。',32,'全唐诗/poet.song.141000.json','["每到炎天只願秋，如何秋到却成愁。", "官居也有寒蛩語，不似山間聽得幽。"]'),
('f1609621-4565-473f-a7c5-30e037f86eef','秋夕不寐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夏熱通宵睡不成，秋涼老眼又偏醒。',32,'全唐诗/poet.song.141000.json','["夏熱通宵睡不成，秋涼老眼又偏醒。", "窗虛月白清無夢，却爲西風數漏聲。"]'),
('59c71ea9-efc8-4173-875a-6411b142292d','跋符發所錄上蔡語二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','洙泗淵源一線寒，再從伊洛起濤瀾。',32,'全唐诗/poet.song.141000.json','["洙泗淵源一線寒，再從伊洛起濤瀾。", "偶看上蔡先生語，滿目淙淙八節灘。"]'),
('f1e5664e-c559-4d22-b8f4-bbae3a3dc0dc','跋符發所錄上蔡語二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','符君天秀擢炎方，繭足擔簦學北方。',32,'全唐诗/poet.song.141000.json','["符君天秀擢炎方，繭足擔簦學北方。", "不是澹菴謫南海，姓名那得許芬香。"]'),
('7a05e67f-0a49-442c-8bd4-5a6b85295eb0','贈墨工張公明','楊萬里','宋','宋诗','song-poetry','','[]','廬陵舊墨說潘衡，廬陵新墨說張生。',80,'全唐诗/poet.song.141000.json','["廬陵舊墨說潘衡，廬陵新墨說張生。", "潘家衣鉢嗣蘇子，張家苗裔出易水。", "易水松花煙一螺，漲起倒流三峽波。", "人言天下無白墨，那知真有玄尚白。", "磨光漆几奪眼睛，試點一點傾人城。"]'),
('a1cf8044-d05d-4256-a098-2183dd1457ff','跋丘宗卿侍郎見贈使北詩一軸','楊萬里','宋','宋诗','song-poetry','','[]','太行界天二千里，清晨跳入寒窗底。',242,'全唐诗/poet.song.141000.json','["太行界天二千里，清晨跳入寒窗底。", "黄河動地萬壑雷，却與太行相趁來。", "青崖顛狂白波怒，老夫驚倒立不住。", "乃是丘遲出塞歸，贈我大軸出塞詩。", "手持漢節娖秋月，弓挂天山鳴積雪。", "過故東京到北京，淚滴禾黍枯不生。", "誓取胡頭爲飲器，盡與遺民解魋髻。", "詩中哀怨訴阿誰，河水嗚咽山風悲。", "中原萬象聽驅使，總隨詩句歸行李。", "君不見晉人王右軍，龍跳虎卧筆有神。", "何曾哦得一句子，自哦自寫傳世人。", "君不見唐人杜子美，萬草千花句何綺。", "祗以詩傳字不傳，却羨別人雲落紙。", "莫道丘遲一軸詩，此詩此字絕世奇。", "再三莫遣鬼神知，鬼神知了偷却伊。"]'),
('5dc3ca3e-186c-432e-b318-fc1a946b3312','謝湖州太守王成之給事送百花春糟蟹','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','烏衣巷裏批敕手，整頓乾坤渠儘有。',160,'全唐诗/poet.song.141000.json','["烏衣巷裏批敕手，整頓乾坤渠儘有。", "天風吹入水精宮，一夜陽和徧花柳。", "愛殺苕溪波底雲，揉雲釀出蒲萄春。", "更挼百花作香塵，小槽濺破真珠痕。", "一杯吸盡太湖月，郡齋忽念山中客。", "遠澆白首草玄人，伯雅仲雅俱清絕。", "一介不肯遣長鬚，却遣郭索持尺書。", "二執戈者爭走趨，登彼糟丘勸腹腴，可憐郭索與陸諝。", "不傍貴人熱門戶，却訪誠齋老病翁，多謝苕溪賢地主。"]'),
('35defd8c-0445-425a-858d-404080c571bb','贈寫真水鑑處士王溫叔','楊萬里','宋','宋诗','song-poetry','','[]','我不如森森千丈松，我不如濯濯春月柳。',136,'全唐诗/poet.song.141000.json','["我不如森森千丈松，我不如濯濯春月柳。", "髯疎鬢秃已雪霜，皮皺肉皴真老醜。", "葉生畫時顔尚朱，王生畫時骨更臞。", "一生愛山吟不就，兩肩化作秋山瘦。", "君不見褒公鄂公圖凌煙，腰間羽箭大如椽。", "君不見浣花醉圖粉墨落，日斜泥滑馿失脚。", "貴人寒士兩相嗤，畫圖猶在人已非。", "王生王生且停手，不如生前一杯酒。"]'),
('9558b233-ac9f-4884-94f9-2482a4939800','題汪季路太丞魏野草堂圖二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','汾陰西祀告昇平，四海無波鏡樣清。',32,'全唐诗/poet.song.141000.json','["汾陰西祀告昇平，四海無波鏡樣清。", "乞與幽人好風月，萬山裏許聽泉聲。"]'),
('a795ea28-0421-4ad1-82b4-00e8ead34172','題汪季路太丞魏野草堂圖二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','奉常夫子半錢無，不問田園況室廬。',32,'全唐诗/poet.song.141000.json','["奉常夫子半錢無，不問田園況室廬。", "聞道買來新宅子，借看却是草堂圖。"]'),
('cf84c8c1-fa35-45df-b2f9-bf43756a9a46','題汪季路所藏李伯時飛騎斫鬃射楊枝及繡毬圖二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','虎夫馳射殿西偏，一箭穿毬不再彎。',32,'全唐诗/poet.song.141000.json','["虎夫馳射殿西偏，一箭穿毬不再彎。", "飛騎新圖天上本，龍眠偷得到人間。"]'),
('d6efe6bf-3b7e-4739-8ffb-b201adbc1e34','題汪季路所藏李伯時飛騎斫鬃射楊枝及繡毬圖二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','君王將幸寶津園，刷洗天駒尚未乾。',32,'全唐诗/poet.song.141000.json','["君王將幸寶津園，刷洗天駒尚未乾。", "禁地何緣有闌入，考官應奉得來看。"]'),
('185a7522-f165-44b9-ab9a-caad8856975e','曉登小樓霧失南高峰塔','楊萬里','宋','宋诗','song-poetry','','[]','日日南高峰，知我登小樓。',84,'全唐诗/poet.song.141000.json','["日日南高峰，知我登小樓。", "笑回紫翠面，擎獻新鮮秋。", "獨將詩魂去，恣繞月脇游。", "得句寄與渠，月姊不敢搜。", "絕頂珥瓊筆，仰空書銀鈎。", "今晨招不來，開窗得孤愁。", "折簡呼屏翳，能爲追亡不。"]'),
('3f3d3af8-6b7a-4c71-bc24-7889c3fdb38e','跋羅春伯所藏高氏樂毅論','楊萬里','宋','宋诗','song-poetry','','[]','右軍樂毅論，大令洛神賦。',124,'全唐诗/poet.song.141000.json','["右軍樂毅論，大令洛神賦。", "王家小楷天取將，祗餘驚鸞尚雙翥。", "昭陵銀海閟銀鈎，秦王卧看偷兒偷。", "秣陵井苔剝山骨，祝融復遣山鬼搜。", "裂瓊劃玉各分散，遺下寶圭三五段。", "墨卿收拾驪頷珠，僅僅一百八十餘。", "江西今代韓吏部，古心古道生好古。", "雷電勃興急捉取，阿那精靈會飛去。"]'),
('88a34c77-3a3c-4f82-b8a7-c49f8196ea49','贈周敬伯','楊萬里','宋','宋诗','song-poetry','','[]','萬方英傑集橋門，作麽吾州不數人。',64,'全唐诗/poet.song.141000.json','["萬方英傑集橋門，作麽吾州不數人。", "之子獨携一方策，短檠以外四無鄰。", "歲云暮矣猶爲客，歸去來兮未立身。", "待上六鼇頭上立，還家藉手拜雙親。"]'),
('097bea38-db8c-4b08-960f-518c676f0d11','贈翦字吳道人','楊萬里','宋','宋诗','song-poetry','','[]','寶晉雲煙雜海濤，玉谿花月寫風騷。',32,'全唐诗/poet.song.141000.json','["寶晉雲煙雜海濤，玉谿花月寫風騷。", "一生不倩毛錐子，只倩并州快翦刀。"]'),
('95335648-3a9b-4804-97bc-67918cfb1146','題汪聖錫墳庵真如軒在玉山常山之間','楊萬里','宋','宋诗','song-poetry','','[]','東吳南垂楚北際，中央不合大如礪。',128,'全唐诗/poet.song.141000.json','["東吳南垂楚北際，中央不合大如礪。", "百灘千嶂自一川，清空不是人間世。", "玉山先生携老禪，把茅結庵開小軒。", "身前身後來醉眠，一醉不醒三千年。", "先生杖屨半宇宙，每到此軒去還又。", "爲憐雪立孤竹君，月骨風筋如許瘦。", "向來種笋今排天，先生手痕故依然。", "騎龍帝旁爲飛仙，玉棺寂寞空寒煙。"]'),
('68f2ac9c-53a5-4711-b253-955536535a2e','和陸務觀用張季長吏部韻寄季長兼簡老夫補外之行二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','今代老龜蒙，無書遺子公。',48,'全唐诗/poet.song.141000.json','["今代老龜蒙，無書遺子公。", "也能將好句，特地寄西風。", "遲暮甘三已，飄零笑兩窮。", "絕憐張與陸，百戰角新功。"]'),
('d96857f2-7408-42e3-8a25-81b640f4ec93','和陸務觀用張季長吏部韻寄季長兼簡老夫補外之行二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','別去公懷我，詩來我夢公。',48,'全唐诗/poet.song.141000.json','["別去公懷我，詩來我夢公。", "半輪笠澤月，一信鏡湖風。", "豈有詩名世，而無鬼作窮。", "管城言曉事，猶欲策元功。"]'),
('b491d107-724e-4bd6-b22b-6c0944523bb7','之官江左舟中梳頭','楊萬里','宋','宋诗','song-poetry','','[]','耐癢呼僮理亂絲，一梳一快勝千篦。',32,'全唐诗/poet.song.141000.json','["耐癢呼僮理亂絲，一梳一快勝千篦。", "是中妙處無人會，合眼垂頭到睡時。"]'),
('7af937fe-7b68-4eee-afce-656757e455ae','題張以道上舍寒綠軒','楊萬里','宋','宋诗','song-poetry','','[]','菊芽伏土糝青粟，杞笋傍根埋紫玉。',211,'全唐诗/poet.song.141000.json','["菊芽伏土糝青粟，杞笋傍根埋紫玉。", "雷聲一夜雨一朝，森然迸出如蕨苗。", "先生饑腸詩作梗，小摘珍芳汲冰井。", "風爐蟹眼候松聲，笊籬親撈微带生。", "爛炊凋胡淅青精，芼以天隨寒綠萌。", "饑時作齏仍作羹，飽後龍鳳同庖烹。", "太官蒸羔壓花片，宰夫胹蹯削瓊軟。", "豹胎熬出禍胎來，貴人有眼何曾見。", "天隨尚有愁作魔，愁杞作棘菊作莎。", "君不見黄金錢照紅玉豆，秋高更覺風味多。", "先生釀金鍊紅玉，自莎自棘如予何。", "金空玉盡苗復出，喫苗喫花并喫實。", "天隨白眼屠沽兒，不道有人頭上立。"]');
